import { useState, useEffect } from 'react';
import { StateProvider, useStateContext } from './context/StateContext';
import AuthGate from './views/AuthGate';
import Dashboard from './views/Dashboard';
import ArchitectureReviews from './views/ArchitectureReviews';
import ThreatModeling from './views/ThreatModeling';
import AdminPanel from './views/AdminPanel';
import Navbar from './components/layout/Navbar';
import Header from './components/layout/Header';
import { ErrorBoundary } from './components/layout/ErrorBoundary';
import AgentChat from './components/ui/AgentChat';
import ModelConsentModal from './components/ui/ModelConsentModal';
import BackupConsentModal from './components/ui/BackupConsentModal';
import NetworkGatekeeperModal from './components/ui/NetworkGatekeeperModal';
import { seedDatabase } from './lib/seedData';

function AppContent() {
  const { identity, setIdentity } = useStateContext();
  const [currentView, setCurrentView] = useState('dashboard');
  const [adminSubView, setAdminSubView] = useState('layers');

  const [_currentSessionId, setCurrentSessionId] = useState<number | null>(null);

  // Index Redirect Mechanism (Router-like behavior)
  useEffect(() => {
    if (currentView === 'expert-config' && !['layers', 'principles', 'service-domains', 'metamodel', 'categories', 'tags'].includes(adminSubView)) {
      setAdminSubView('layers');
    } else if (currentView === 'agent-config' && !['prompts', 'configs', 'workflows', 'templates'].includes(adminSubView)) {
      setAdminSubView('prompts');
    } else if (currentView === 'system-pref' && !['network', 'users', 'audit', 'dpdp', 'models', 'system'].includes(adminSubView)) {
      setAdminSubView('network');
    } else if (currentView === 'knowledge-mgmt' && !['knowledge'].includes(adminSubView)) {
      setAdminSubView('knowledge');
    }
  }, [currentView, adminSubView]);

  useEffect(() => {
    seedDatabase();

    const worker = new Worker(new URL('./workers/distillation.worker.ts', import.meta.url), { type: 'module' });
    (window as any).distillationWorker = worker;

    worker.onmessage = (event) => {
      window.dispatchEvent(new CustomEvent('DISTILLATION_EVENT', { detail: event.data }));
    };

    const handleNavigate = (e: Event) => {
      const customEvent = e as CustomEvent;
      if (customEvent.detail.view) setCurrentView(customEvent.detail.view);
      if (customEvent.detail.subView) setAdminSubView(customEvent.detail.subView);
    };
    
    window.addEventListener('EA_NAVIGATE', handleNavigate);
    return () => {
      window.removeEventListener('EA_NAVIGATE', handleNavigate);
      worker.terminate();
    };
  }, []);

  if (!identity) {
    return <AuthGate onAuthenticated={setIdentity} />;
  }

  const renderView = () => {
    switch (currentView) {
      case 'dashboard':
        return <Dashboard setCurrentView={setCurrentView} setCurrentSessionId={setCurrentSessionId} />;
      case 'reviews':
        return <ArchitectureReviews setCurrentView={setCurrentView} setCurrentSessionId={setCurrentSessionId} />;
      case 'threat':
        return <ThreatModeling />;
      case 'expert-config':
      case 'agent-config':
      case 'system-pref':
      case 'knowledge-mgmt':
      case 'admin':
        return <AdminPanel adminSubView={adminSubView} setAdminSubView={setAdminSubView} />;
      default:
        return <Dashboard setCurrentView={setCurrentView} setCurrentSessionId={setCurrentSessionId} />;
    }
  };

  return (
    <>
      <div className="h-screen overflow-hidden flex flex-col md:flex-row bg-gray-50 dark:bg-gray-900 transition-colors duration-300">
        <Navbar 
          currentView={currentView} 
          setCurrentView={setCurrentView} 
          adminSubView={adminSubView}
          setAdminSubView={setAdminSubView}
        />
        <div className="flex-1 flex flex-col overflow-hidden mt-16 md:mt-0">
          <Header 
            currentView={currentView} 
            setCurrentView={setCurrentView} 
            adminSubView={adminSubView}
            setAdminSubView={setAdminSubView}
          />
          <main className="flex-1 overflow-y-auto p-4 sm:p-6 lg:p-8">
            <div className="max-w-7xl mx-auto pb-12">
              {renderView()}
            </div>
          </main>
        </div>
      </div>
      <AgentChat />
      <ModelConsentModal />
      <BackupConsentModal />
      <NetworkGatekeeperModal />
    </>
  );
}

function App() {
  return (
    <ErrorBoundary>
      <StateProvider>
        <AppContent />
      </StateProvider>
    </ErrorBoundary>
  );
}

export default App;

import { describe, it, expect, beforeEach, afterEach, vi } from 'vitest';
import {
  initializeVault,
  getVaultKey,
  clearVault,
  encryptString,
  decryptString,
  encryptBlob,
  decryptBlob,
} from '../lib/cryptoVault';
import { hashSecret } from '../lib/authEngine';

describe('CryptoVault Security Tests', () => {
  const testPin = 'test-pin-12345';
  const testSalt = 'test-salt-67890';
  const testMessage = 'This is a test message for encryption';

  beforeEach(async () => {
    // Clear any existing vault state
    clearVault();
    // Initialize with test credentials
    await initializeVault(testPin, testSalt);
  });

  afterEach(() => {
    clearVault();
  });

  describe('Vault Initialization & Key Management', () => {
    it('should initialize vault and store DEK', async () => {
      const dek = getVaultKey();
      expect(dek).toBeTruthy();
      expect(typeof dek).toBe('string');
    });

    it('should return null after clearing vault', () => {
      clearVault();
      const dek = getVaultKey();
      expect(dek).toBeNull();
    });

    it('should derive consistent DEK from same PIN and salt', async () => {
      const dek1 = getVaultKey();
      clearVault();
      await initializeVault(testPin, testSalt);
      const dek2 = getVaultKey();
      expect(dek1).toBe(dek2);
    });

    it('should derive different DEK from different PIN', async () => {
      const dek1 = getVaultKey();
      clearVault();
      await initializeVault('different-pin', testSalt);
      const dek2 = getVaultKey();
      expect(dek1).not.toBe(dek2);
    });
  });

  describe('String Encryption & Decryption (AES-GCM)', () => {
    it('should encrypt and decrypt a string successfully (roundtrip)', async () => {
      const encrypted = await encryptString(testMessage);
      expect(encrypted).toBeTruthy();
      expect(typeof encrypted).toBe('string');
      // Format should be: ivHex:encryptedHex
      expect(encrypted).toMatch(/^[0-9a-f]+:[0-9a-f]+$/);

      const decrypted = await decryptString(encrypted);
      expect(decrypted).toBe(testMessage);
    });

    it('should encrypt different messages to different ciphertexts (IV randomization)', async () => {
      const encrypted1 = await encryptString(testMessage);
      const encrypted2 = await encryptString(testMessage);
      // Due to random IV, ciphertexts should differ
      expect(encrypted1).not.toBe(encrypted2);

      // But both should decrypt to the same plaintext
      const decrypted1 = await decryptString(encrypted1);
      const decrypted2 = await decryptString(encrypted2);
      expect(decrypted1).toBe(testMessage);
      expect(decrypted2).toBe(testMessage);
    });

    it('should handle empty strings', async () => {
      const encrypted = await encryptString('');
      expect(encrypted).toBeTruthy();
      const decrypted = await decryptString(encrypted);
      expect(decrypted).toBe('');
    });

    it('should handle special characters and unicode', async () => {
      const specialMessage = '🔐 Secure: !@#$%^&*()_+-=[]{}|;:,.<>?';
      const encrypted = await encryptString(specialMessage);
      const decrypted = await decryptString(encrypted);
      expect(decrypted).toBe(specialMessage);
    });

    it('should handle large messages', async () => {
      const largeMessage = 'x'.repeat(10000);
      const encrypted = await encryptString(largeMessage);
      const decrypted = await decryptString(encrypted);
      expect(decrypted).toBe(largeMessage);
    });
  });

  describe('Decryption Error Handling (Fix 1.2)', () => {
    it('should throw error when decrypting with missing DEK', async () => {
      const encrypted = await encryptString(testMessage);
      clearVault();

      await expect(decryptString(encrypted)).rejects.toThrow('Vault decryption key not available');
    });

    it('should throw error on corrupted ciphertext (missing colon)', async () => {
      const corruptedCiphertext = 'not_a_valid_ciphertext';

      await expect(decryptString(corruptedCiphertext)).rejects.toThrow('Invalid ciphertext format');
    });

    it('should throw error on tampered ciphertext (modified encrypted portion)', async () => {
      const encrypted = await encryptString(testMessage);
      const [iv, cipher] = encrypted.split(':');
      // Flip a bit in the ciphertext to simulate tampering
      const tamperedCiphertext = `${iv}:${(parseInt(cipher[0], 16) ^ 1).toString(16)}${cipher.slice(1)}`;

      await expect(decryptString(tamperedCiphertext)).rejects.toThrow('Failed to decrypt string');
    });

    it('should throw error on invalid IV (corrupted hex)', async () => {
      const encrypted = await encryptString(testMessage);
      const [, cipher] = encrypted.split(':');
      const corruptedIV = 'zz'; // Invalid hex

      await expect(decryptString(`${corruptedIV}:${cipher}`)).rejects.toThrow();
    });

    it('should throw error on truncated ciphertext', async () => {
      const encrypted = await encryptString(testMessage);
      const truncated = encrypted.slice(0, -10);

      await expect(decryptString(truncated)).rejects.toThrow('Failed to decrypt string');
    });

    it('should not return plaintext on decryption failure', async () => {
      const encrypted = await encryptString(testMessage);
      const [iv] = encrypted.split(':');
      const corruptedCiphertext = `${iv}:invalid`;

      try {
        await decryptString(corruptedCiphertext);
        // Should not reach here
        expect.fail('Should have thrown an error');
      } catch (e) {
        const error = e as Error;
        expect(error.message).not.toContain(testMessage);
      }
    });
  });

  describe('Blob Encryption & Decryption', () => {
    it('should encrypt and decrypt a blob successfully', async () => {
      const testData = new Uint8Array([1, 2, 3, 4, 5]);
      const blob = new Blob([testData], { type: 'application/octet-stream' });

      const encrypted = await encryptBlob(blob);
      expect(encrypted).toBeTruthy();
      expect(encrypted.type).toBe('application/octet-stream');

      const decrypted = await decryptBlob(encrypted);
      const decryptedData = await decrypted.arrayBuffer();
      const decryptedArray = new Uint8Array(decryptedData);

      expect(decryptedArray).toEqual(testData);
    });

    it('should throw error when decrypting blob with missing DEK', async () => {
      const blob = new Blob([new Uint8Array([1, 2, 3, 4, 5])]);
      clearVault();

      await expect(decryptBlob(blob)).rejects.toThrow('Vault decryption key not available');
    });

    it('should throw error on invalid encrypted blob (too small)', async () => {
      const invalidBlob = new Blob([new Uint8Array([1, 2])], { type: 'application/octet-stream' });

      await expect(decryptBlob(invalidBlob)).rejects.toThrow('Invalid encrypted payload');
    });

    it('should throw error on tampered blob', async () => {
      const testData = new Uint8Array([1, 2, 3, 4, 5]);
      const blob = new Blob([testData]);
      const encrypted = await encryptBlob(blob);

      const encryptedData = await encrypted.arrayBuffer();
      const corruptedArray = new Uint8Array(encryptedData);
      // Flip a bit in encrypted portion (after IV)
      corruptedArray[15] ^= 1;
      const corruptedBlob = new Blob([corruptedArray]);

      await expect(decryptBlob(corruptedBlob)).rejects.toThrow('Failed to decrypt blob');
    });
  });

  describe('Key Isolation & Uniqueness', () => {
    it('should not expose DEK in plaintext', () => {
      const dek = getVaultKey();
      // DEK should be a hex string (not raw binary)
      expect(dek).toMatch(/^[0-9a-f]+$/);
    });

    it('should not share DEK between sessions', async () => {
      const dek1 = getVaultKey();

      // Simulate new session
      clearVault();
      await initializeVault(testPin, testSalt);
      const dek2 = getVaultKey();

      // Same credentials should produce same key (deterministic)
      expect(dek1).toBe(dek2);

      // But after clearing, retrieving should give null
      clearVault();
      const dek3 = getVaultKey();
      expect(dek3).toBeNull();
    });
  });

  describe('Encryption Performance', () => {
    it('should encrypt string in reasonable time (<100ms)', async () => {
      const start = performance.now();
      await encryptString(testMessage);
      const elapsed = performance.now() - start;

      expect(elapsed).toBeLessThan(100);
    });

    it('should decrypt string in reasonable time (<100ms)', async () => {
      const encrypted = await encryptString(testMessage);
      const start = performance.now();
      await decryptString(encrypted);
      const elapsed = performance.now() - start;

      expect(elapsed).toBeLessThan(100);
    });

    it('should handle bulk encryption of multiple strings', async () => {
      const messages = Array(50).fill(testMessage);
      const encrypted = await Promise.all(messages.map(m => encryptString(m)));

      expect(encrypted).toHaveLength(50);
      expect(encrypted.every(e => typeof e === 'string')).toBe(true);

      const decrypted = await Promise.all(encrypted.map(e => decryptString(e)));
      expect(decrypted).toEqual(messages);
    });
  });
});

import React, { useState, useEffect } from 'react';
import { useLiveQuery } from 'dexie-react-hooks';
import { db, CustomAgent } from '../../lib/db';
import { CheckCircle2, AlertTriangle, Activity, Plus, Edit, Archive as ArchiveIcon, ToggleLeft, ToggleRight, Loader2, X, Zap, Bot } from 'lucide-react';
import CreatableDropdown from '../ui/CreatableDropdown';
import CacheButton from '../ui/CacheButton';
import { useMasterData } from '../../hooks/useMasterData';
import { useArchive } from '../../hooks/useArchive';
import { useDataPortability } from '../../hooks/useDataPortability';
import DataPortabilityButtons from '../ui/DataPortabilityButtons';
import { useStateContext } from '../../context/StateContext';
import { SUPPORTED_MLC_MODELS } from '../../lib/constants';
import PageHeader from '../ui/PageHeader';

interface BaseConfig {
  id: string;
  url: string;
  modelLibUrl?: string;
  context: number;
  isActive: boolean;
  agentCategory: string;
  engineType: string;
  personaInstruction: string;
  modelSourceMode: 'Remote URL' | 'Offline Sideloaded';
  baseApiEndpoint: string;
  modelSize?: string;
  isValidated?: boolean;
}

const getDynamicEndpoint = () => typeof window !== 'undefined' ? `${window.location.protocol}//${window.location.hostname}:11434` : 'http://localhost:11434';

export default function AgentConfigTab() {
  const [hardwareWarning, setHardwareWarning] = useState<string | null>(null);


  const defaultPrimary: BaseConfig = { 
    id: 'Phi-3-mini-4k-instruct-q4f16_1-MLC', 
    url: 'https://huggingface.co/mlc-ai/Phi-3-mini-4k-instruct-q4f16_1-MLC', 
    modelLibUrl: 'https://raw.githubusercontent.com/mlc-ai/binary-mlc-llm-libs/main/Phi-3-mini-4k-instruct-q4f16_1-ctx4k_cs1k-webgpu.wasm',
    context: 8192,
    isActive: true,
    agentCategory: 'Coding Agent',
    engineType: 'WebLLM (Browser Cache)',
    personaInstruction: 'You are EA-NITI. Elite, air-gapped Enterprise Architecture AI.',
    modelSourceMode: 'Remote URL',
    baseApiEndpoint: getDynamicEndpoint()
  };

  const defaultTriage: BaseConfig = { 
    id: 'gemma-2b-it-q4f16_1-MLC', 
    url: 'https://huggingface.co/mlc-ai/gemma-2b-it-q4f16_1-MLC', 
    modelLibUrl: 'https://raw.githubusercontent.com/mlc-ai/binary-mlc-llm-libs/main/gemma-2b-it-q4f16_1-ctx4k_cs1k-webgpu.wasm',
    context: 4096,
    isActive: true,
    agentCategory: 'Tiny Triage',
    engineType: 'WebLLM (Browser Cache)',
    personaInstruction: 'You are a Triage Agent. Analyze and categorize input.',
    modelSourceMode: 'Remote URL',
    baseApiEndpoint: getDynamicEndpoint()
  };

  const [primaryConfig, setPrimaryConfig] = useState<BaseConfig>(defaultPrimary);
  const [triageConfig, setTriageConfig] = useState<BaseConfig>(defaultTriage);

  const [savedPrimary, setSavedPrimary] = useState<BaseConfig>(defaultPrimary);
  const [savedTriage, setSavedTriage] = useState<BaseConfig>(defaultTriage);

  const [primarySaveError, setPrimarySaveError] = useState<string | null>(null);
  const [triageSaveError, setTriageSaveError] = useState<string | null>(null);
  const [isSavingPrimary, setIsSavingPrimary] = useState(false);
  const [isSavingTriage, setIsSavingTriage] = useState(false);

  const defaultCategories = useMasterData('AGENT_CATEGORIES');
  const defaultEngineTypes = useMasterData('AGENT_ENGINE_TYPES');

  const logs = useLiveQuery(() => 
    db.audit_logs
      .where('tableName')
      .equals('agent_configs')
      .reverse()
      .toArray()
  ) || [];

  useEffect(() => {
    const loadCoreConfigs = async () => {
      const p = await db.app_settings.get('core-primary');
      if (p?.value) {
        setPrimaryConfig(p.value);
        setSavedPrimary(p.value);
      }
      const t = await db.app_settings.get('core-triage');
      if (t?.value) {
        setTriageConfig(t.value);
        setSavedTriage(t.value);
      }
    };
    loadCoreConfigs();
  }, []);

  const offlineModels = useLiveQuery(() => db.model_registry.filter(m => m.isLocalhost).toArray()) || [];
  const allCustomAgents = useLiveQuery(() => db.custom_agents.toArray()) || [];

  const { showArchived, setShowArchived, archiveItem } = useArchive({
    tableName: 'custom_agents',
    statusField: 'status',
    archivedValue: 'PURGED',
    activeValue: 'Active'
  });

  const { handleExport, handleImport } = useDataPortability({
    tableName: 'custom_agents',
    filename: 'agent_personas_export'
  });

  const filteredCustomAgents = allCustomAgents.filter(agent => {
    if (showArchived) return agent.status === 'PURGED';
    return agent.status !== 'PURGED';
  });

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingAgentId, setEditingAgentId] = useState<number | null>(null);
  const [modalConfig, setModalConfig] = useState<BaseConfig & { name: string }>({
    name: '',
    id: '',
    url: '',
    context: 4096,
    isActive: true,
    agentCategory: '',
    engineType: '',
    personaInstruction: '',
    modelSourceMode: 'Remote URL',
    baseApiEndpoint: getDynamicEndpoint()
  });

  const isPrimaryDirty = JSON.stringify(primaryConfig) !== JSON.stringify(savedPrimary);
  const isTriageDirty = JSON.stringify(triageConfig) !== JSON.stringify(savedTriage);

  useEffect(() => {
    const checkGPU = async () => {
      if (!(navigator as any).gpu) {
        setHardwareWarning("System Requirement Alert: WebGPU unavailable. Browser instability may occur.");
        return;
      }
      try {
        const adapter = await (navigator as any).gpu.requestAdapter();
        if (!adapter) {
          setHardwareWarning("System Requirement Alert: WebGPU adapter not found. Browser instability may occur.");
        }
      } catch (e) {
        setHardwareWarning("System Requirement Alert: Error requesting WebGPU. " + e);
      }
    };
    checkGPU();
  }, []);

  const handlePullWebCache = (modelId: string, modelUrl: string) => {
    if (!navigator.onLine) {
       alert("Air-gap mode active. Please use sideloaded models.");
       return;
    }
    window.dispatchEvent(new CustomEvent('EA_AI_CONSENT_REQUIRED', {
        detail: { networkEnabled: true, targetModelId: modelId, targetModelUrl: modelUrl, modelSize: (modelId === primaryConfig.id ? primaryConfig.modelSize : triageConfig.modelSize) || 'Size: Varies (Check documentation)' } 
    }));
  };

  const validateAndSave = async (
    config: BaseConfig,
    dbKey: 'core-primary' | 'core-triage',
    label: string,
    setSaved: (c: BaseConfig) => void,
    setError: React.Dispatch<React.SetStateAction<string | null>>,
    setLoading: React.Dispatch<React.SetStateAction<boolean>>
  ) => {
    setError(null);
    setLoading(true);

    let validationWarning: string | null = null;

    try {
      // TASK 1: TRUST THE INTERNAL REGISTRY
      // Check if the selected model is in our trusted registry (excluding the 'custom' placeholder)
      const isRegistryModel = SUPPORTED_MLC_MODELS.some(
        m => m.modelId === config.id && m.modelId !== 'custom'
      );

      // If it's a known-good registry model, skip all network validation entirely
      if (isRegistryModel) {
        // Instantly pass validation for registered models — no network probes
        validationWarning = null;
      } else if (config.modelSourceMode === 'Remote URL' && config.url) {
        // TASK 2: SOFT-FAIL CUSTOM VALIDATION
        // For custom URLs, attempt validation but never block the save on network failure
        try {
          const probe = await fetch(config.url, {
            method: 'HEAD',
            signal: AbortSignal.timeout(8000)
          });

          // Check response validity (treating 405 as OK — some servers don't allow HEAD)
          if (!probe.ok && probe.status !== 405) {
            validationWarning = `Network validation returned HTTP ${probe.status}. Configuration saved anyway.`;
          }
        } catch (fetchError: any) {
          // CRUCIAL: Network/CORS failures are NOT fatal — user may be offline or CORS-blocked
          // Log a soft warning but ALWAYS proceed with the save
          validationWarning = 'Network validation failed or offline. Saving custom configuration anyway.';
        }
      }

      // SAVE ALWAYS SUCCEEDS (unless DB write fails)
      // Validation warnings are informational only and never block persistence
      const validated: BaseConfig = { ...config, isValidated: !validationWarning };
      await db.app_settings.put({ key: dbKey, value: validated });

      // Audit trail
      await db.audit_logs.add({
        timestamp: new Date(),
        pseudokey: sessionStorage.getItem('ea_niti_session') || 'Unknown',
        action: 'UPDATE',
        tableName: 'agent_configs',
        recordId: label,
        details: `Updated Model ID to "${config.id}" (${config.agentCategory}) — Registry: ${isRegistryModel}, Validation: ${!validationWarning ? 'Passed' : 'Warning'}`
      });

      setSaved(validated);

      // TASK 2 (continued): Surface soft warning AFTER successful save (non-blocking)
      // User sees a yellow/amber toast, not a blocking red error
      if (validationWarning) {
        setError(validationWarning);
      }
    } catch (err: any) {
      // Only real errors (DB write failures, etc.) stop the flow
      setError(`Save failed: ${err?.message || 'Unknown error'}`);
    } finally {
      setLoading(false);
    }
  };

  const handleSavePrimary = () =>
    validateAndSave(primaryConfig, 'core-primary', 'Primary EA Agent', (v) => {
      setPrimaryConfig(v);
      setSavedPrimary(v);
    }, setPrimarySaveError, setIsSavingPrimary);

  const handleSaveTriage = () =>
    validateAndSave(triageConfig, 'core-triage', 'Tiny Triage Agent', (v) => {
      setTriageConfig(v);
      setSavedTriage(v);
    }, setTriageSaveError, setIsSavingTriage);

  const openAddAgentModal = () => {
    setEditingAgentId(null);
    setModalConfig({
      name: '',
      id: '',
      url: '',
      context: 4096,
      isActive: true,
      agentCategory: '',
      engineType: '',
      personaInstruction: '',
      modelSourceMode: 'Remote URL',
      baseApiEndpoint: getDynamicEndpoint()
    });
    setIsModalOpen(true);
  };

  const openEditAgentModal = (agent: CustomAgent) => {
    setEditingAgentId(agent.id!);
    setModalConfig({
      name: agent.name,
      id: agent.modelId,
      url: agent.modelUrl,
      context: agent.context,
      isActive: agent.isActive,
      agentCategory: agent.agentCategory,
      engineType: agent.engineType,
      personaInstruction: agent.personaInstruction,
      modelSourceMode: agent.modelSourceMode,
      baseApiEndpoint: agent.baseApiEndpoint
    });
    setIsModalOpen(true);
  };

  const saveCustomAgent = async () => {
    const payload: Partial<CustomAgent> = {
      name: modalConfig.name,
      isActive: modalConfig.isActive,
      agentCategory: modalConfig.agentCategory,
      engineType: modalConfig.engineType,
      personaInstruction: modalConfig.personaInstruction,
      modelSourceMode: modalConfig.modelSourceMode,
      modelId: modalConfig.id,
      modelUrl: modalConfig.url,
      baseApiEndpoint: modalConfig.baseApiEndpoint,
      context: modalConfig.context,
      status: 'Active',
      updatedAt: new Date()
    };

    if (editingAgentId) {
      await db.custom_agents.update(editingAgentId, payload);
    } else {
      payload.createdAt = new Date();
      await db.custom_agents.add(payload as CustomAgent);
    }
    setIsModalOpen(false);
  };

  const renderConfigForm = (
    config: BaseConfig, 
    setConfig: React.Dispatch<React.SetStateAction<BaseConfig>>,
    isDirty: boolean,
    onSave: () => void,
    saveLabel: string,
    cardSaving: boolean,
    cardError: string | null,
    clearError: () => void
  ) => (
    <div className="space-y-4">
      <div className="flex justify-between items-center bg-gray-50 dark:bg-gray-800/50 p-3 rounded-lg border border-gray-200 dark:border-gray-700">
        <label className="text-sm font-semibold text-gray-700 dark:text-gray-300">Active Status</label>
        <button
          onClick={() => setConfig({ ...config, isActive: !config.isActive })}
          className={`relative inline-flex h-6 w-11 items-center rounded-full transition-colors focus:outline-none ${config.isActive ? 'bg-blue-600' : 'bg-gray-400'}`}
          aria-label="Toggle Active Status"
          title="Toggle Active Status"
        >
          <span className={`inline-block h-4 w-4 transform rounded-full bg-white transition-transform ${config.isActive ? 'translate-x-6' : 'translate-x-1'}`} />
        </button>
      </div>

      <div>
        <label className="block text-xs font-semibold text-gray-600 dark:text-gray-400 mb-1">Agent Category</label>
        <CreatableDropdown
           value={config.agentCategory}
           onChange={(val) => setConfig({ ...config, agentCategory: val })}
           options={defaultCategories.map(o => ({ label: o.name, value: o.name }))}
           categoryType="AGENT_CATEGORIES"
           placeholder="Select Category..."
        />
      </div>

      <div>
        <label className="block text-xs font-semibold text-gray-600 dark:text-gray-400 mb-1">Engine Type</label>
        <CreatableDropdown
           value={config.engineType}
           onChange={(val) => setConfig({ ...config, engineType: val })}
           options={defaultEngineTypes.map(o => ({ label: o.name, value: o.name }))}
           categoryType="AGENT_ENGINE_TYPES"
           placeholder="Select Engine..."
        />
      </div>

      <div>
         <label className="block text-xs font-semibold text-gray-600 dark:text-gray-400 mb-1">Persona Instruction</label>
         <textarea 
            value={config.personaInstruction} 
            onChange={e => setConfig({...config, personaInstruction: e.target.value})} 
            className="w-full bg-white dark:bg-gray-800 border border-gray-300 dark:border-gray-700 rounded-lg px-3 py-2 text-gray-900 dark:text-white text-sm focus:border-blue-500 focus:ring-1 focus:ring-blue-500 min-h-[80px]"
            aria-label="Persona Instruction"
            title="Persona Instruction"
            placeholder="Enter persona instructions..."
         />
      </div>

      {config.engineType === 'WebLLM (Browser Cache)' && (
         <>
             <div className="flex gap-4 mb-2">
                <label className="flex items-center gap-2 text-sm text-gray-600 dark:text-gray-400">
                   <input type="radio" checked={config.modelSourceMode === 'Remote URL'} onChange={() => setConfig({...config, modelSourceMode: 'Remote URL'})} />
                   Remote URL
                </label>
                <label className="flex items-center gap-2 text-sm text-gray-600 dark:text-gray-400">
                   <input type="radio" checked={config.modelSourceMode === 'Offline Sideloaded'} onChange={() => setConfig({...config, modelSourceMode: 'Offline Sideloaded'})} />
                   Offline Sideloaded
                </label>
             </div>
             {config.modelSourceMode === 'Remote URL' ? (
                <>
                  <div>
                    <label htmlFor="model-registry-select" className="block text-xs font-semibold text-gray-600 dark:text-gray-400 mb-1">Model Registry</label>
                    <select
                      id="model-registry-select"
                      value={SUPPORTED_MLC_MODELS.find(m => m.modelId === config.id) ? config.id : 'custom'}
                      onChange={(e) => {
                        const val = e.target.value;
                        // Clear any validation errors when user changes the model selection
                        clearError();
                        if (val === 'custom') {
                          setConfig({ ...config, id: '', url: '', modelLibUrl: '' });
                        } else {
                          const registryMatch = SUPPORTED_MLC_MODELS.find(m => m.modelId === val);
                          if (registryMatch) {
                            setConfig({
                              ...config,
                              id: registryMatch.modelId,
                              url: registryMatch.modelUrl,
                              modelLibUrl: '',
                              context: registryMatch.contextLimit
                            });
                          }
                        }
                      }}
                      className="w-full bg-white dark:bg-gray-800 border border-gray-300 dark:border-gray-700 rounded-lg px-3 py-2 text-gray-900 dark:text-white text-sm mb-3"
                    >
                      {SUPPORTED_MLC_MODELS.map(m => (
                        <option key={m.modelId} value={m.modelId}>{m.label}</option>
                      ))}
                    </select>

                    {(!SUPPORTED_MLC_MODELS.find(m => m.modelId === config.id && m.modelId !== 'custom')) && (
                      <div className="mb-3">
                        <label className="block text-xs font-semibold text-gray-600 dark:text-gray-400 mb-1">Custom Model ID</label>
                        <input
                          type="text"
                          value={config.id}
                          onChange={(e) => {
                            setConfig({
                              ...config,
                              id: e.target.value
                            });
                          }}
                          className="w-full bg-white dark:bg-gray-800 border border-gray-300 dark:border-gray-700 rounded-lg px-3 py-2 text-gray-900 dark:text-white text-sm"
                          aria-label="Model ID"
                          title="Model ID"
                          placeholder="Enter explicit Model ID"
                        />
                      </div>
                    )}
                    
                    <label className="block text-xs font-semibold text-gray-600 dark:text-gray-400 mb-1">Model URL</label>
                    <div className="flex gap-2">
                      <input type="text" value={config.url} onChange={(e) => setConfig({...config, url: e.target.value})} className="flex-1 bg-white dark:bg-gray-800 border border-gray-300 dark:border-gray-700 rounded-lg px-3 py-2 text-gray-900 dark:text-white text-sm" aria-label="Model URL" title="Model URL" placeholder="Enter model URL" />
                      <CacheButton 
                        modelId={config.id}
                        modelUrl={config.url}
                        onPull={handlePullWebCache}
                        disabled={isDirty}
                      />
                    </div>

                    <div className="mt-3">
                      <div className="flex justify-between mb-1">
                        <label className="block text-xs font-semibold text-gray-600 dark:text-gray-400">WASM Library URL (model_lib_url)</label>
                        <span className="text-[10px] text-gray-400 uppercase tracking-wider flex items-center gap-1">
                           <Zap size={10} className="text-amber-500" />
                           {(() => {
                             const isPredefined = config.id !== 'custom' && SUPPORTED_MLC_MODELS.some(m => m.modelId === config.id && m.modelId !== 'custom');
                             return isPredefined ? 'Auto-Managed' : 'Manual Entry';
                           })()}
                        </span>
                      </div>

                      {(() => {
                        const isPredefined = config.id !== 'custom' && SUPPORTED_MLC_MODELS.some(m => m.modelId === config.id && m.modelId !== 'custom');

                        if (isPredefined) {
                          return (
                            <>
                              <input
                                type="text"
                                value="Auto-managed by WebLLM version match"
                                disabled={true}
                                readOnly={true}
                                className="w-full bg-gray-100 dark:bg-gray-900 border border-gray-200 dark:border-gray-800 rounded-lg px-3 py-2 text-gray-600 dark:text-gray-500 text-sm opacity-50 cursor-not-allowed"
                                aria-label="WASM Library URL"
                                title="WASM auto-managed for predefined registry models"
                              />
                              <p className="text-xs text-blue-600 dark:text-blue-400 mt-1.5 flex items-center gap-1.5">
                                <CheckCircle2 size={12} /> Registry model WASM managed by @mlc-ai/web-llm native matcherNo manual entry needed.
                              </p>
                            </>
                          );
                        }

                        return (
                          <>
                            <input
                              type="text"
                              value={config.modelLibUrl || ''}
                              onChange={(e) => setConfig({...config, modelLibUrl: e.target.value})}
                              className={`w-full bg-white dark:bg-gray-800 border rounded-lg px-3 py-2 text-gray-900 dark:text-white text-sm ${!config.modelLibUrl ? 'border-amber-400 dark:border-amber-500' : 'border-gray-300 dark:border-gray-700'}`}
                              aria-label="WASM Library URL"
                              title="Enter WASM Library URL for custom models"
                              placeholder="Enter WASM Library URL"
                            />
                            {!config.modelLibUrl && (
                              <p className="text-xs text-amber-600 dark:text-amber-400 mt-1.5 flex items-center gap-1.5">
                                <AlertTriangle size={12} /> WASM Library URL is required for custom models.
                              </p>
                            )}
                          </>
                        );
                      })()}
                    </div>
                  </div>
                </>
             ) : (
                <div>
                   <label className="block text-xs font-semibold text-gray-600 dark:text-gray-400 mb-1">Select Sideloaded Model</label>
                   <select 
                      value={config.id} 
                      onChange={e => setConfig({...config, id: e.target.value, url: offlineModels.find(m => m.name === e.target.value)?.modelUrl || ''})} 
                      className="w-full bg-white dark:bg-gray-800 border border-gray-300 dark:border-gray-700 rounded-lg px-3 py-2 text-gray-900 dark:text-white text-sm"
                      aria-label="Select Sideloaded Model"
                      title="Select Sideloaded Model"
                   >
                     {offlineModels.length === 0 ? <option value="">No sideloaded models found...</option> : offlineModels.map(m => (
                        <option key={m.id} value={m.name}>{m.name}</option>
                     ))}
                   </select>
                </div>
             )}
         </>
      )}

      {config.engineType === 'Local API (Ollama/Custom)' && (
         <div>
             <label className="block text-xs font-semibold text-gray-600 dark:text-gray-400 mb-1">Base API Endpoint</label>
             <input type="text" value={config.baseApiEndpoint} onChange={(e) => setConfig({...config, baseApiEndpoint: e.target.value})} className="w-full bg-white dark:bg-gray-800 border border-gray-300 dark:border-gray-700 rounded-lg px-3 py-2 text-gray-900 dark:text-white text-sm" aria-label="Base API Endpoint" title="Base API Endpoint" placeholder="Enter base API endpoint" />
         </div>
      )}

      <div>
        <label className="block text-xs font-semibold text-gray-600 dark:text-gray-400 mb-1 mt-2">Context Limit (Tokens)</label>
        <input type="number" value={config.context} onChange={(e) => setConfig({...config, context: parseInt(e.target.value) || 0})} className="w-full bg-white dark:bg-gray-800 border border-gray-300 dark:border-gray-700 rounded-lg px-3 py-2 text-gray-900 dark:text-white text-sm" aria-label="Context Limit" title="Context Limit" placeholder="Enter context limit" />
      </div>

      {cardError && (
        <div className="bg-red-50 dark:bg-red-900/20 border border-red-300 dark:border-red-700 rounded-lg p-3 flex items-start gap-3 mt-2">
          <AlertTriangle className="text-red-500 shrink-0 mt-0.5" size={14} />
          <p className="flex-1 text-xs text-red-700 dark:text-red-300 font-medium">{cardError}</p>
          <button onClick={clearError} className="text-red-400 hover:text-red-600 transition-colors" aria-label="Dismiss error" title="Dismiss error">
            <X size={14} />
          </button>
        </div>
      )}

      <button 
        onClick={onSave}
        disabled={!isDirty || cardSaving}
        className={`w-full px-4 py-2 mt-2 text-white rounded-lg text-sm font-medium transition-colors flex items-center justify-center gap-2 ${
          cardSaving ? 'bg-blue-500 cursor-wait' :
          isDirty ? 'bg-blue-600 hover:bg-blue-700' : 'bg-green-600 dark:bg-green-700 cursor-not-allowed'
        }`}
      >
        {cardSaving && <Loader2 size={14} className="animate-spin" />}
        {cardSaving ? 'Validating…' : isDirty ? saveLabel : '✓ Config Saved'}
      </button>
    </div>
  );

  return (
    <div className="flex flex-col h-full space-y-6 overflow-y-auto">
      <PageHeader 
        icon={<Bot className="text-blue-500" />}
        title="Agent Configurations & Personas"
        description="Configure local LLM routing parameters and strict persona governance boundaries."
      />

      {hardwareWarning && (
        <div className="bg-amber-50 dark:bg-amber-900/20 border border-amber-200 dark:border-amber-800 rounded-lg p-4 flex items-center gap-3 shrink-0">
          <AlertTriangle className="text-amber-500 shrink-0" size={20} />
          <p className="text-sm text-amber-800 dark:text-amber-300 font-medium">
            {hardwareWarning}
          </p>
        </div>
      )}

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6 shrink-0">
        <div className="bg-white dark:bg-gray-900 rounded-xl border border-gray-200 dark:border-gray-800 p-6 shadow-sm">
          <div className="flex justify-between items-center mb-4">
            <h3 className="text-lg font-bold text-gray-900 dark:text-white flex items-center gap-2">
              Primary EA Agent
              <CheckCircle2 size={16} className={primaryConfig.isActive ? "text-green-500" : "text-gray-400"} />
            </h3>
          </div>
          {renderConfigForm(
            primaryConfig, 
            setPrimaryConfig, 
            isPrimaryDirty, 
            handleSavePrimary, 
            'Save Primary Configuration',
            isSavingPrimary,
            primarySaveError,
            () => setPrimarySaveError(null)
          )}
        </div>

        <div className="bg-white dark:bg-gray-900 rounded-xl border border-gray-200 dark:border-gray-800 p-6 shadow-sm">
          <div className="flex justify-between items-center mb-4">
            <h3 className="text-lg font-bold text-gray-900 dark:text-white flex items-center gap-2">
              Tiny Triage Agent
              <CheckCircle2 size={16} className={triageConfig.isActive ? "text-green-500" : "text-gray-400"} />
            </h3>
          </div>
          {renderConfigForm(
            triageConfig, 
            setTriageConfig, 
            isTriageDirty, 
            handleSaveTriage, 
            'Save Triage Configuration',
            isSavingTriage,
            triageSaveError,
            () => setTriageSaveError(null)
          )}
        </div>
      </div>

      <div className="border-t border-gray-200 dark:border-gray-800 pt-6"></div>

      {/* Custom Mitra Registry */}
      <div className="bg-white dark:bg-gray-900 rounded-xl border border-gray-200 dark:border-gray-800 p-6 shadow-sm shrink-0">
        <div className="flex justify-between items-center mb-6">
          <div className="flex items-center gap-3">
             <h3 className="text-lg font-bold text-gray-900 dark:text-white">Custom Mitra Registry (Specialist Nodes)</h3>
          </div>
          <div className="flex items-center gap-4">
             <button
               onClick={() => setShowArchived(!showArchived)}
               className="flex items-center gap-2 text-sm text-gray-600 dark:text-gray-400 hover:text-gray-900 dark:hover:text-white transition-colors"
             >
               {showArchived ? <ToggleRight size={20} className="text-blue-500" /> : <ToggleLeft size={20} />}
               Show Archived
             </button>
             <DataPortabilityButtons onExport={handleExport} onImport={handleImport} />
             <button
               onClick={openAddAgentModal}
               className="flex items-center gap-2 bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-lg text-sm font-semibold transition-colors shadow-sm"
             >
               <Plus size={16} /> Add Custom Mitra
             </button>
          </div>
        </div>

        <div className="overflow-x-auto border border-gray-200 dark:border-gray-800 rounded-lg">
          <table className="w-full text-sm text-left">
            <thead className="bg-gray-50 dark:bg-gray-800/80 text-gray-600 dark:text-gray-400 uppercase text-xs">
              <tr>
                <th className="px-6 py-3 font-semibold">Mitra Name</th>
                <th className="px-6 py-3 font-semibold">Category</th>
                <th className="px-6 py-3 font-semibold">Engine</th>
                <th className="px-6 py-3 font-semibold">Status</th>
                <th className="px-6 py-3 font-semibold text-right">Actions</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-200 dark:divide-gray-800">
              {filteredCustomAgents.length === 0 ? (
                <tr>
                   <td colSpan={5} className="px-6 py-8 text-center text-gray-500 dark:text-gray-400">
                      No custom mitras found.
                   </td>
                </tr>
              ) : (
                filteredCustomAgents.map(agent => (
                   <tr key={agent.id} className="hover:bg-gray-50 dark:hover:bg-gray-800/50 transition-colors">
                      <td className="px-6 py-4 font-semibold text-gray-900 dark:text-white">
                         {agent.name}
                      </td>
                      <td className="px-6 py-4 text-gray-600 dark:text-gray-400">{agent.agentCategory}</td>
                      <td className="px-6 py-4 text-gray-600 dark:text-gray-400">{agent.engineType}</td>
                      <td className="px-6 py-4">
                         <span className={`inline-flex px-2 py-1 rounded-full text-xs font-bold uppercase tracking-wider ${agent.isActive ? 'bg-green-100 text-green-700 dark:bg-green-500/10 dark:text-green-400' : 'bg-gray-100 text-gray-600 dark:bg-gray-800 dark:text-gray-400'}`}>
                           {agent.isActive ? 'Active' : 'Inactive'}
                         </span>
                         {agent.status === 'PURGED' && <span className="ml-2 inline-flex px-2 py-1 rounded-full text-xs font-bold uppercase tracking-wider bg-red-100 text-red-700 dark:bg-red-500/10 dark:text-red-400">Purged</span>}
                      </td>
                      <td className="px-6 py-4 text-right flex justify-end gap-2">
                         <button onClick={() => openEditAgentModal(agent)} className="p-2 text-gray-500 hover:text-blue-600 dark:text-gray-400 dark:hover:text-blue-400 bg-white hover:bg-blue-50 dark:bg-gray-900 dark:hover:bg-blue-900/30 rounded-lg shadow-sm border border-gray-200 dark:border-gray-700 transition-colors" title="Edit Mitra">
                           <Edit size={16} />
                         </button>
                         <button onClick={() => archiveItem(agent.id!)} className="p-2 text-gray-500 hover:text-red-600 dark:text-gray-400 dark:hover:text-red-400 bg-white hover:bg-red-50 dark:bg-gray-900 dark:hover:bg-red-900/30 rounded-lg shadow-sm border border-gray-200 dark:border-gray-700 transition-colors" title="Archive / Soft Delete">
                           <ArchiveIcon size={16} />
                         </button>
                      </td>
                   </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      </div>

      <div className="bg-white dark:bg-gray-900 rounded-xl border border-gray-200 dark:border-gray-800 overflow-hidden shadow-sm shrink-0">
        <div className="p-5 border-b border-gray-200 dark:border-gray-800 flex justify-between items-center bg-gray-50 dark:bg-gray-800/50">
          <div className="flex items-center gap-2">
            <Activity className="text-gray-500 dark:text-gray-400" size={18} />
            <h3 className="text-sm font-bold text-gray-900 dark:text-white">Configuration Event Logs</h3>
          </div>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-sm text-left">
            <thead className="bg-gray-50 dark:bg-gray-800 text-gray-500 dark:text-gray-400 uppercase text-xs">
              <tr>
                <th className="px-6 py-3 font-semibold tracking-wider">Timestamp</th>
                <th className="px-6 py-3 font-semibold tracking-wider">Updated By</th>
                <th className="px-6 py-3 font-semibold tracking-wider">Agent</th>
                <th className="px-6 py-3 font-semibold tracking-wider">Action</th>
                <th className="px-6 py-3 font-semibold tracking-wider">Details</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-200 dark:divide-gray-800">
              {logs.length === 0 ? (
                <tr>
                  <td colSpan={5} className="px-6 py-8 text-center text-gray-500 dark:text-gray-400">
                    No configuration changes recorded.
                  </td>
                </tr>
              ) : (
                logs.map((log) => (
                  <tr key={log.id} className="hover:bg-gray-50 dark:hover:bg-gray-800/50 transition-colors">
                    <td className="px-6 py-4 whitespace-nowrap text-gray-600 dark:text-gray-400 font-mono text-xs">
                      {new Date(log.timestamp).toLocaleString()}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap text-gray-900 dark:text-white flex items-center gap-2 font-medium">
                       <div className="w-6 h-6 rounded-full bg-blue-100 flex items-center justify-center text-blue-700 text-xs font-bold shrink-0">
                         {log.pseudokey.charAt(0).toUpperCase()}
                       </div>
                       {log.pseudokey}
                    </td>
                    <td className="px-6 py-4 whitespace-nowrap font-medium">{log.recordId}</td>
                    <td className="px-6 py-4 whitespace-nowrap"><span className="inline-flex px-2 py-0.5 rounded text-[10px] font-bold uppercase tracking-wider bg-blue-100 text-blue-700">{log.action}</span></td>
                    <td className="px-6 py-4 text-gray-600 truncate max-w-sm">{log.details}</td>
                  </tr>
                ))
              )}
            </tbody>
          </table>
        </div>
      </div>
      <div className="pb-4" />

      {/* Add / Edit Agent Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-sm flex items-center justify-center z-50 p-4">
          <div className="bg-white dark:bg-gray-900 rounded-xl shadow-xl w-full max-w-xl max-h-[90vh] flex flex-col border border-gray-200 dark:border-gray-800">
             <div className="flex justify-between items-center p-5 border-b border-gray-200 dark:border-gray-800">
                <h3 className="text-xl font-bold text-gray-900 dark:text-white">
                   {editingAgentId ? 'Edit Custom Mitra' : 'Add Custom Mitra'}
                </h3>
             </div>
             
             <div className="p-6 overflow-y-auto flex-1 space-y-4">
                <div>
                   <label className="block text-xs font-semibold text-gray-600 dark:text-gray-400 mb-1">Mitra Name</label>
                   <input 
                     type="text" 
                     value={modalConfig.name} 
                     onChange={e => setModalConfig({ ...modalConfig, name: e.target.value })} 
                     placeholder="e.g. Code Reviewer"
                     className="w-full bg-white dark:bg-gray-800 border border-gray-300 dark:border-gray-700 rounded-lg px-3 py-2 text-gray-900 dark:text-white text-sm" 
                   />
                </div>
                {renderConfigForm(
                  modalConfig as BaseConfig,
                  setModalConfig as any,
                  true,
                  () => {}, // Empty, handle save below in modal buttons
                  "",
                  false,
                  null,
                  () => {}
                )}
             </div>

             <div className="p-5 border-t border-gray-200 dark:border-gray-800 flex justify-end gap-3 bg-gray-50 dark:bg-gray-800/50">
               <button 
                 onClick={() => setIsModalOpen(false)}
                 className="px-4 py-2 text-gray-700 dark:text-gray-300 hover:bg-gray-200 dark:hover:bg-gray-700 rounded-lg font-semibold text-sm transition-colors"
               >
                 Cancel
               </button>
               <button 
                 onClick={saveCustomAgent}
                 disabled={!modalConfig.name || !modalConfig.agentCategory || !modalConfig.engineType}
                 className="px-4 py-2 bg-blue-600 hover:bg-blue-700 text-white rounded-lg font-semibold text-sm transition-colors shadow-sm disabled:opacity-50"
               >
                 Save Mitra
               </button>
             </div>
          </div>
        </div>
      )}
    </div>
  );
}

import { useState, useCallback, useEffect, useMemo } from 'react';
import { Trash2, AlertTriangle, Plus, ToggleLeft, ToggleRight, Shield, X, Archive, RefreshCw, Lock, Download, Upload, Edit2, Check } from 'lucide-react';
import { db, PrivacyGuardrail, logForensicAudit } from '../../lib/db';
import { useArchive } from '../../hooks/useArchive';
import { generateReview, isModelCached, getActiveModelId } from '../../lib/aiEngine';
import PageHeader from '../ui/PageHeader';
import CreatableDropdown from '../ui/CreatableDropdown';
import { useLiveQuery } from 'dexie-react-hooks';
import { Logger } from '../../lib/logger';

export default function GlobalGuardrailsTab() {
  // ── Guardrails CRUD State ──────────────────────────────────────────
  const [guardrails, setGuardrails] = useState<PrivacyGuardrail[]>([]);
  const [showAddModal, setShowAddModal] = useState(false);
  const [newTitle, setNewTitle] = useState('');
  const [newRuleText, setNewRuleText] = useState('');
  const [newFrameworkTags, setNewFrameworkTags] = useState<string[]>([]);
  const [newEnforcementScope, setNewEnforcementScope] = useState<string[]>([]);
  const [editingPolicyId, setEditingPolicyId] = useState<number | null>(null);
  const [isAutoTagging, setIsAutoTagging] = useState(false);
  const [reviewTags, setReviewTags] = useState<string[] | null>(null);
  const [skipAutoTagging, setSkipAutoTagging] = useState(false);
  const [toastMessage, setToastMessage] = useState<string | null>(null);

  // ── Dirty State Tracking ───────────────────────────────────────────
  const isDirty = useMemo(() => {
    if (!editingPolicyId) return true; // Always dirty if creating new
    const original = guardrails.find(g => g.id === editingPolicyId);
    if (!original) return true;

    const arraysEqual = (a: string[], b: string[]) => {
      if (a.length !== b.length) return false;
      const sortedA = [...a].sort();
      const sortedB = [...b].sort();
      return sortedA.every((val, index) => val === sortedB[index]);
    };

    const originalTags = original.frameworkTags || [];
    const originalScope = original.enforcementScope || [];

    return (
      newTitle.trim() !== original.title ||
      newRuleText.trim() !== original.ruleText ||
      !arraysEqual(newFrameworkTags, originalTags) ||
      !arraysEqual(newEnforcementScope, originalScope)
    );
  }, [editingPolicyId, guardrails, newTitle, newRuleText, newFrameworkTags, newEnforcementScope]);

  // ── Pagination State ───────────────────────────────────────────────
  const [currentPage, setCurrentPage] = useState(1);
  const itemsPerPage = 5;

  // ── Data Fetching ──────────────────────────────────────────────────
  const masterCategories = useLiveQuery(() => db.master_categories.where('type').equals('FrameworkTag').toArray()) || [];
  const workflows = useLiveQuery(() => db.review_workflows.toArray()) || [];

  const frameworkOptions = masterCategories.map(c => ({ label: c.name, value: c.name }));
  const scopeOptions = [
    { label: 'Global Context', value: 'GLOBAL' },
    { label: 'Chat Interface', value: 'CHAT' },
    ...workflows.map(w => ({ label: `Workflow: ${w.name}`, value: `workflow-${w.id}` }))
  ];

  // ── Archive Hook ───────────────────────────────────────────────────
  const { showArchived, setShowArchived, archiveItem, restoreItem, permanentDeleteItem, filterByArchiveStatus } = useArchive({
    tableName: 'privacy_guardrails',
    statusField: 'isArchived',
    archivedValue: true,
    activeValue: false
  });

  // ── Filter State ───────────────────────────────────────────────────
  const [selectedTagFilter, setSelectedTagFilter] = useState<string>('ALL');

  // ── Load guardrails from Dexie ─────────────────────────────────────
  const loadGuardrails = useCallback(async () => {
    try {
      const data = await db.privacy_guardrails.toArray();
      setGuardrails(data);
    } catch (e) {
      Logger.('[DpdpTab] Failed to load guardrails:', e);
    }
  }, []);

  useEffect(() => { loadGuardrails(); }, [loadGuardrails]);

  // ── CRUD Handlers ──────────────────────────────────────────────────
  const executeSave = async (tagsToSave: string[]) => {
    const trimTitle = newTitle.trim();
    const trimRule = newRuleText.trim();
    if (!trimTitle || !trimRule) return;

    for (const tag of tagsToSave) {
      const existingTag = await db.master_categories.where('name').equals(tag).first();
      if (!existingTag) {
        await db.master_categories.add({
          name: tag,
          type: 'FrameworkTag',
          status: 'Active'
        });
      }
    }

    if (editingPolicyId) {
      const existing = await db.privacy_guardrails.get(editingPolicyId);
      if (existing) {
        const updated = {
          ...existing,
          title: trimTitle,
          ruleText: trimRule,
          frameworkTags: tagsToSave,
          enforcementScope: newEnforcementScope.length > 0 ? newEnforcementScope : ['GLOBAL']
        };
        await db.privacy_guardrails.put(updated);
        await logForensicAudit('UPDATE', 'privacy_guardrails', editingPolicyId, existing, updated);
      }
    } else {
      const newObj = {
        title: trimTitle,
        ruleText: trimRule,
        isDefault: false,
        isActive: true,
        isArchived: false,
        frameworkTags: tagsToSave,
        enforcementScope: newEnforcementScope.length > 0 ? newEnforcementScope : ['GLOBAL']
      };
      const newId = await db.privacy_guardrails.add(newObj);
      await logForensicAudit('CREATE', 'privacy_guardrails', newId, null, { ...newObj, id: newId });
    }

    setNewTitle('');
    setNewRuleText('');
    setNewFrameworkTags([]);
    setNewEnforcementScope([]);
    setEditingPolicyId(null);
    setShowAddModal(false);
    setReviewTags(null);
    setSkipAutoTagging(false);
    loadGuardrails();
  };

  const handleInitiateSave = async () => {
    const trimTitle = newTitle.trim();
    const trimRule = newRuleText.trim();
    if (!trimTitle || !trimRule) return;

    let finalTags = [...newFrameworkTags];

    if (finalTags.length === 0 && !skipAutoTagging) {
      setIsAutoTagging(true);
      let generatedTags: string[] = [];
      let aiFailed = false;

      try {
        // TASK 1: PRE-CHECK LLM CACHE
        const tinyModelId = await getActiveModelId('Tiny');
        const isCached = await isModelCached(tinyModelId);

        if (!isCached || !navigator.onLine) {
          Logger.('AI Model not cached or offline. Bypassing AI auto-tagging.');
          aiFailed = true;
        } else {
          const promptTemplate = await db.prompt_templates.where('name').equals('System Auto-Tagging Classifier').first();
          if (promptTemplate) {
            const prompt = promptTemplate.promptText.replace('{{ruleText}}', trimRule);
            const response = await generateReview(prompt, () => {}, 'Tiny Triage Agent');

            if (response) {
              generatedTags = response.split(',').map(t => t.trim()).filter(t => t);
            }
          }
        }
      } catch (e) {
        Logger.('Auto-tagging failed, falling back to heuristic:', e);
        aiFailed = true;
      } finally {
        setIsAutoTagging(false);
      }

      if (generatedTags.length === 0) {
        Logger.("[EA-NITI Fallback] AI Offline or yielded no tags. Initiating local Regex scan...");
        const existingFrameworkTags = await db.master_categories.where('type').equals('FrameworkTag').toArray();
        Logger.("[EA-NITI Fallback] Scanning against " + existingFrameworkTags.length + " master categories...");

        const combinedTextLower = `${trimTitle} ${trimRule}`.toLowerCase();

        generatedTags = existingFrameworkTags
          .filter(cat => combinedTextLower.includes(cat.name.toLowerCase()))
          .map(cat => cat.name);

        Logger.("[EA-NITI Fallback] Regex matches found:", generatedTags);
      }

      if (generatedTags.length > 0) {
        setReviewTags(generatedTags);
        return;
      } else {
        await executeSave([]);
        if (aiFailed) {
          setToastMessage("Policy saved. Auto-tagging unavailable (AI offline and no keyword matches).");
          setTimeout(() => setToastMessage(null), 5000);
        }
        return;
      }
    }

    await executeSave(finalTags);
  };

  const handleEditGuardrail = (guardrail: PrivacyGuardrail) => {
    setEditingPolicyId(guardrail.id!);
    setNewTitle(guardrail.title);
    setNewRuleText(guardrail.ruleText);
    setNewFrameworkTags(guardrail.frameworkTags || []);
    setNewEnforcementScope(guardrail.enforcementScope || []);
    setReviewTags(null);
    setSkipAutoTagging(false);
    setShowAddModal(true);
  };

  const handleToggle = async (id: number, currentState: boolean) => {
    const existing = await db.privacy_guardrails.get(id);
    if (existing) {
      const updated = { ...existing, isActive: !currentState };
      await db.privacy_guardrails.update(id, { isActive: !currentState });
      await logForensicAudit('UPDATE', 'privacy_guardrails', id, existing, updated);
    }
    loadGuardrails();
  };

  const handleArchive = async (id: number) => {
    await archiveItem(id);
    loadGuardrails();
  };

  const handleDelete = async (id: number) => {
    await permanentDeleteItem(id);
    loadGuardrails();
  };

  const activeCount = guardrails.filter(g => g.isActive).length;

  // Extract unique tags for the filter dropdown
  const uniqueTags = Array.from(new Set(guardrails.flatMap(g => g.frameworkTags || []))).sort();

  const filteredGuardrails = guardrails
    .filter(filterByArchiveStatus)
    .filter(g => selectedTagFilter === 'ALL' || (g.frameworkTags && g.frameworkTags.includes(selectedTagFilter)));

  const totalPages = Math.ceil(filteredGuardrails.length / itemsPerPage) || 1;
  const paginatedGuardrails = filteredGuardrails.slice((currentPage - 1) * itemsPerPage, currentPage * itemsPerPage);

  const handleExport = () => {
    const csvContent = "data:text/csv;charset=utf-8," 
      + "Title,Rule Text,Framework Tags,Enforcement Scope,Is Active\n"
      + filteredGuardrails.map(g => 
          `"${g.title.replace(/"/g, '""')}","${g.ruleText.replace(/"/g, '""')}","${(g.frameworkTags || []).join(', ')}","${(g.enforcementScope || []).join(', ')}",${g.isActive}`
        ).join("\n");
    const encodedUri = encodeURI(csvContent);
    const link = document.createElement("a");
    link.setAttribute("href", encodedUri);
    link.setAttribute("download", "privacy_guardrails_export.csv");
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
  };

  return (
    <div className="w-full max-w-4xl">
      <PageHeader 
        icon={<Lock className="text-emerald-500" />}
        title="Global Guardrails"
        description="Configure universal policies, privacy mappings, and architectural guardrails."
      />

      {/* Zero-PII Status Banner */}
      <div className="bg-emerald-50 dark:bg-emerald-900/20 border border-emerald-200 dark:border-emerald-800 rounded-xl p-5 mb-6">
        <h3 className="text-sm font-bold text-emerald-800 dark:text-emerald-400 mb-1">Zero-PII Mode Active</h3>
        <p className="text-sm text-emerald-700 dark:text-emerald-500/80">
          All architectural artifacts and review sessions are sanitized locally. External API calls (if any) strip all identifiable metadata automatically via the Zero-PII proxy engine.
        </p>
      </div>

      {/* ── Active Guardrails Section ───────────────────────── */}
      <div className="bg-white dark:bg-gray-800/50 border border-gray-200 dark:border-gray-700 rounded-xl p-6 mb-6">
        <div className="flex items-center justify-between mb-4">
          <div>
            <h3 className="text-sm font-bold text-gray-900 dark:text-white flex items-center gap-2">
              <Shield size={16} className="text-blue-500" />
              Active Guardrails
              <span className="ml-1 px-2 py-0.5 bg-blue-100 dark:bg-blue-900/30 text-blue-700 dark:text-blue-400 rounded-full text-[10px] font-bold">
                {activeCount} active
              </span>
            </h3>
            <p className="text-xs text-gray-500 dark:text-gray-400 mt-0.5">
              Rules injected into the AI system prompt before every inference call.
            </p>
          </div>
          <div className="flex items-center gap-2">
            <select
              value={selectedTagFilter}
              onChange={(e) => setSelectedTagFilter(e.target.value)}
              className="px-3 py-1.5 bg-gray-100 dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-lg text-xs font-medium text-gray-700 dark:text-gray-300 outline-none focus:ring-2 focus:ring-blue-500"
            >
              <option value="ALL">All Tags</option>
              {uniqueTags.map(tag => (
                <option key={tag} value={tag}>{tag}</option>
              ))}
            </select>
            <button
              onClick={() => setShowArchived(!showArchived)}
              className={`flex items-center gap-1.5 px-3 py-1.5 rounded-lg text-xs font-medium transition-colors ${
                showArchived 
                  ? 'bg-amber-100 text-amber-700 dark:bg-amber-900/30 dark:text-amber-400' 
                  : 'bg-gray-100 text-gray-700 hover:bg-gray-200 dark:bg-gray-800 dark:text-gray-300 dark:hover:bg-gray-700'
              }`}
            >
              <Archive size={14} />
              {showArchived ? 'View Active' : 'View Archived'}
            </button>
            <button 
              onClick={handleExport}
              className="flex items-center gap-1.5 px-3 py-1.5 bg-gray-100 hover:bg-gray-200 dark:bg-gray-800 dark:hover:bg-gray-700 text-gray-700 dark:text-gray-300 rounded-lg text-xs font-medium transition-colors"
            >
              <Download size={14} />
              Export CSV
            </button>
            <button 
              className="flex items-center gap-1.5 px-3 py-1.5 bg-gray-100 hover:bg-gray-200 dark:bg-gray-800 dark:hover:bg-gray-700 text-gray-700 dark:text-gray-300 rounded-lg text-xs font-medium transition-colors opacity-50 cursor-not-allowed"
              title="Import coming soon"
            >
              <Upload size={14} />
              Import
            </button>
            {!showArchived && (
              <button
                id="add-guardrail-btn"
                onClick={() => {
                  setEditingPolicyId(null);
                  setNewTitle('');
                  setNewRuleText('');
                  setNewFrameworkTags([]);
                  setNewEnforcementScope([]);
                  setReviewTags(null);
                  setSkipAutoTagging(false);
                  setShowAddModal(true);
                }}
                className="flex items-center gap-1.5 px-3 py-1.5 bg-blue-600 hover:bg-blue-700 text-white rounded-lg text-xs font-medium transition-colors"
              >
                <Plus size={14} />
                Add Policy
              </button>
            )}
          </div>
        </div>

        {filteredGuardrails.length === 0 ? (
          <p className="text-sm text-gray-400 dark:text-gray-500 py-6 text-center">
            {showArchived ? 'No archived guardrails.' : 'No guardrails configured. Add one to enforce compliance boundaries on AI output.'}
          </p>
        ) : (
          <>
            <div className="divide-y divide-gray-100 dark:divide-gray-700">
              {paginatedGuardrails.map(g => (
                <div key={g.id} className={`flex items-start gap-3 py-3 ${!g.isActive ? 'opacity-50' : ''}`}>
                  {/* Toggle */}
                  <button
                    onClick={() => handleToggle(g.id!, g.isActive)}
                    className="mt-0.5 shrink-0 text-gray-400 hover:text-blue-500 transition-colors"
                    title={g.isActive ? 'Disable guardrail' : 'Enable guardrail'}
                  >
                    {g.isActive
                      ? <ToggleRight size={22} className="text-blue-500" />
                      : <ToggleLeft size={22} className="text-gray-400" />
                    }
                  </button>

                  {/* Content */}
                  <div className="flex-1 min-w-0">
                    <div className="flex items-center gap-2 mb-1">
                      <span className="text-sm font-semibold text-gray-900 dark:text-white truncate">{g.title}</span>
                      {g.frameworkTags && g.frameworkTags.map(tag => (
                        <span key={tag} className="px-1.5 py-0.5 bg-blue-100 dark:bg-blue-900/30 text-blue-700 dark:text-blue-400 rounded text-[10px] font-bold uppercase shrink-0">
                          {tag}
                        </span>
                      ))}
                    </div>
                    <p className="text-xs text-gray-500 dark:text-gray-400 mt-0.5 line-clamp-2">{g.ruleText}</p>
                    {g.enforcementScope && g.enforcementScope.length > 0 && (
                      <div className="mt-2 flex items-center gap-1 flex-wrap">
                        <span className="text-[10px] text-gray-400 uppercase tracking-wider font-semibold">Scope:</span>
                        {g.enforcementScope.map(scope => (
                          <span key={scope} className="px-1.5 py-0.5 bg-gray-100 dark:bg-gray-800 text-gray-600 dark:text-gray-300 rounded text-[10px] font-medium">
                            {scope}
                          </span>
                        ))}
                      </div>
                    )}
                  </div>

                  {/* Archive / Restore / Delete */}
                  {showArchived ? (
                  <div className="flex items-center gap-2">
                    <button
                      onClick={() => restoreItem(g.id!)}
                      className="mt-0.5 shrink-0 text-gray-400 hover:text-amber-500 transition-colors"
                      title="Restore guardrail"
                    >
                      <RefreshCw size={15} />
                    </button>
                    <button
                      onClick={() => handleDelete(g.id!)}
                      className="mt-0.5 shrink-0 text-gray-400 hover:text-red-500 transition-colors"
                      title="Delete permanently"
                    >
                      <Trash2 size={15} />
                    </button>
                  </div>
                ) : (
                  <div className="flex items-center gap-2">
                    <button
                      onClick={() => handleEditGuardrail(g)}
                      className="mt-0.5 shrink-0 text-gray-400 hover:text-blue-500 transition-colors"
                      title="Edit guardrail"
                    >
                      <Edit2 size={15} />
                    </button>
                    <button
                      onClick={() => handleArchive(g.id!)}
                      disabled={g.isDefault}
                      className={`mt-0.5 shrink-0 transition-colors ${
                        g.isDefault
                          ? 'text-gray-300 dark:text-gray-600 cursor-not-allowed'
                          : 'text-gray-400 hover:text-red-500'
                      }`}
                      title={g.isDefault ? 'Default policies cannot be archived' : 'Archive guardrail'}
                    >
                      <Trash2 size={15} />
                    </button>
                  </div>
                )}
              </div>
            ))}
          </div>

          {/* Pagination UI */}
          <div className="mt-4 px-4 py-2 border-t border-gray-200 dark:border-gray-700 bg-gray-50 dark:bg-gray-900/50 flex items-center justify-between rounded-b-xl -mx-6 -mb-6">
            <span className="text-[10px] text-gray-500 dark:text-gray-400">
              Page {currentPage} of {totalPages}
            </span>
            <div className="flex gap-2">
              <button 
                onClick={() => setCurrentPage(prev => Math.max(1, prev - 1))}
                disabled={currentPage === 1}
                className="px-2 py-1 text-[10px] font-medium text-gray-600 dark:text-gray-400 bg-white dark:bg-gray-800 border border-gray-300 dark:border-gray-700 rounded disabled:opacity-50 disabled:cursor-not-allowed hover:bg-gray-50 dark:hover:bg-gray-700 transition-colors"
              >
                Previous
              </button>
              <button 
                onClick={() => setCurrentPage(prev => Math.min(totalPages, prev + 1))}
                disabled={currentPage === totalPages}
                className="px-2 py-1 text-[10px] font-medium text-gray-600 dark:text-gray-400 bg-white dark:bg-gray-800 border border-gray-300 dark:border-gray-700 rounded disabled:opacity-50 disabled:cursor-not-allowed hover:bg-gray-50 dark:hover:bg-gray-700 transition-colors"
              >
                Next
              </button>
            </div>
          </div>
        </>
        )}
      </div>

      {/* ── Add Guardrail Modal ─────────────────────────────────────── */}
      {showAddModal && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-[60]" onClick={() => setShowAddModal(false)}>
          <div className="bg-white dark:bg-gray-900 border border-gray-200 dark:border-gray-700 rounded-xl p-6 w-[95%] max-w-lg mx-4 shadow-2xl" onClick={e => e.stopPropagation()}>
            <div className="flex items-center justify-between mb-4">
              <h3 className="text-lg font-bold text-gray-900 dark:text-white">
                {editingPolicyId ? 'Edit Guardrail Policy' : 'New Guardrail Policy'}
              </h3>
              <button onClick={() => setShowAddModal(false)} className="text-gray-400 hover:text-gray-600 dark:hover:text-gray-300" aria-label="Close Modal" title="Close Modal">
                <X size={18} />
              </button>
            </div>

            <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1.5">Policy Title</label>
            <input
              type="text"
              value={newTitle}
              onChange={e => setNewTitle(e.target.value)}
              placeholder="e.g., No External Vendor Naming"
              autoFocus
              className="w-full px-3 py-2 rounded-lg border border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-800 text-gray-900 dark:text-white text-sm focus:ring-2 focus:ring-blue-500 outline-none mb-4"
            />

            <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1.5">Rule Text</label>
            <textarea
              value={newRuleText}
              onChange={e => setNewRuleText(e.target.value)}
              placeholder="The constraint that will be injected into the AI system prompt…"
              rows={3}
              className="w-full px-3 py-2 rounded-lg border border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-800 text-gray-900 dark:text-white text-sm focus:ring-2 focus:ring-blue-500 outline-none mb-4 resize-none"
            />

            {reviewTags !== null && (
              <div className="mb-6 bg-blue-50 dark:bg-blue-900/20 border border-blue-200 dark:border-blue-800 rounded-xl p-4">
                <h4 className="text-sm font-bold text-blue-900 dark:text-blue-300 mb-2">Review Suggested Tags</h4>
                <p className="text-xs text-blue-700 dark:text-blue-400 mb-3">
                  The AI (or fallback heuristic) suggested the following tags based on your rule text. Do you want to apply them?
                </p>
                <div className="flex flex-wrap gap-2 mb-4">
                  {reviewTags.map(tag => (
                    <span key={tag} className="px-2 py-1 bg-blue-100 dark:bg-blue-800 text-blue-800 dark:text-blue-200 rounded text-xs font-semibold">
                      {tag}
                    </span>
                  ))}
                </div>
                <div className="flex gap-2">
                  <button
                    onClick={() => {
                      setNewFrameworkTags(reviewTags);
                      setReviewTags(null);
                    }}
                    className="flex-1 flex items-center justify-center gap-2 px-3 py-2 bg-green-600 hover:bg-green-700 text-white rounded-lg text-sm font-medium transition-colors"
                  >
                    <Check size={16} />
                    Accept
                  </button>
                  <button
                    onClick={() => {
                      setReviewTags(null);
                      setSkipAutoTagging(true);
                    }}
                    className="flex-1 flex items-center justify-center gap-2 px-3 py-2 bg-red-600 hover:bg-red-700 text-white rounded-lg text-sm font-medium transition-colors"
                  >
                    <X size={16} />
                    Reject
                  </button>
                </div>
              </div>
            )}

            <div className="mb-4">
              <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1.5">Framework Tags</label>
              <CreatableDropdown
                value={newFrameworkTags}
                onChange={setNewFrameworkTags}
                options={frameworkOptions}
                categoryType="FrameworkTag"
                placeholder="Select or create tags (e.g., DPDP, SOC2)..."
                isMulti={true}
              />
            </div>

            <div className="mb-6">
              <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1.5">Enforcement Scope</label>
              <CreatableDropdown
                value={newEnforcementScope}
                onChange={setNewEnforcementScope}
                options={scopeOptions}
                categoryType="EnforcementScope"
                placeholder="Where does this rule apply? (Default: GLOBAL)"
                isMulti={true}
              />
            </div>

            <div className="flex justify-end gap-3">
              <button onClick={() => { setShowAddModal(false); setReviewTags(null); setSkipAutoTagging(false); }} className="px-4 py-2 text-gray-500 dark:text-gray-400 hover:text-gray-900 dark:hover:text-white text-sm transition-colors">Cancel</button>
              <button
                id="save-guardrail-btn"
                onClick={handleInitiateSave}
                disabled={!newTitle.trim() || !newRuleText.trim() || isAutoTagging || !isDirty || reviewTags !== null}
                className="px-4 py-2 bg-blue-600 hover:bg-blue-700 disabled:opacity-40 disabled:cursor-not-allowed text-white rounded-lg text-sm font-medium transition-colors flex items-center gap-2"
              >
                {isAutoTagging ? (
                  <>
                    <RefreshCw size={14} className="animate-spin" />
                    AI Auto-Tagging...
                  </>
                ) : (
                  editingPolicyId ? 'Update Guardrail' : 'Save Guardrail'
                )}
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Toast Notification */}
      {toastMessage && (
        <div className="fixed bottom-4 right-4 bg-gray-800 text-white px-4 py-3 rounded-lg shadow-lg z-[100] flex items-center gap-3 animate-in fade-in slide-in-from-bottom-4">
          <AlertTriangle size={16} className="text-amber-400 shrink-0" />
          <span className="text-sm font-medium">{toastMessage}</span>
          <button onClick={() => setToastMessage(null)} className="ml-2 text-gray-400 hover:text-white transition-colors">
            <X size={14} />
          </button>
        </div>
      )}
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { useLiveQuery } from 'dexie-react-hooks';
import { db } from '../../lib/db';
import { Database, Server, Plus, Info, FolderUp, TerminalSquare, Trash2 } from 'lucide-react';
import { SideloadService } from '../../services/SideloadService';
import { getActiveModelUrl } from '../../lib/aiEngine';
import CreatableDropdown from '../ui/CreatableDropdown';
import FolderUploadButton from '../ui/FolderUploadButton';
import PageHeader from '../ui/PageHeader';
import { Logger } from '../../lib/logger';

function EngineDiagnostics({ selectedModelId }: { selectedModelId?: string }) {
  const [logs, setLogs] = useState<string[]>([]);
  const [activeModel, setActiveModel] = useState<string>('Awaiting Target...');
  const [sourceUrl, setSourceUrl] = useState<string>('Idle');

  useEffect(() => {
    const updateMonitor = async () => {
      if (!selectedModelId) {
        setActiveModel('Awaiting Target...');
        setSourceUrl('Idle');
        return;
      }
      
      setActiveModel(selectedModelId);
      const url = await getActiveModelUrl(selectedModelId);
      setSourceUrl(url || 'Local Cache');
    };
    
    updateMonitor();

    const handleProgress = (e: Event) => {
      const customEvent = e as CustomEvent;
      const { text, message, progress: _progress } = customEvent.detail;
      const logText = message || text;
      if (logText) {
        setLogs(prev => {
          const newLogs = [...prev, `[${new Date().toLocaleTimeString()}] ${logText}`];
          return newLogs.slice(-50);
        });
      }
    };

    window.addEventListener('EA_AI_PROGRESS', handleProgress);
    window.addEventListener('DISTILLATION_EVENT', handleProgress);
    return () => {
      window.removeEventListener('EA_AI_PROGRESS', handleProgress);
      window.removeEventListener('DISTILLATION_EVENT', handleProgress);
    };
  }, [selectedModelId]);

  return (
    <div className="bg-gray-900 rounded-xl border border-gray-800 p-5 mt-8 font-mono shadow-inner">
      <div className="flex items-center justify-between mb-4 border-b border-gray-800 pb-3">
        <h3 className="text-sm font-bold text-gray-300 flex items-center gap-2">
          <TerminalSquare className="text-green-500" size={16} />
          Engine Diagnostics Terminal
        </h3>
        <div className="flex items-center gap-2">
           <button 
             onClick={() => {
               const event = new CustomEvent('DISTILLATION_EVENT', { 
                 detail: { message: 'Mock HARVEST payload dispatched...', status: 'INFO', progress: 0 } 
               });
               window.dispatchEvent(event);
               if ((window as any).distillationWorker) {
                 (window as any).distillationWorker.postMessage({ type: 'HARVEST' });
               }
             }}
             className="text-[10px] bg-gray-800 hover:bg-gray-700 text-gray-300 px-2 py-1 rounded border border-gray-700 transition-colors"
           >
             Test Distillation Pipeline
           </button>
           <span className="flex h-2 w-2 relative ml-2">
             <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-green-400 opacity-75"></span>
             <span className="relative inline-flex rounded-full h-2 w-2 bg-green-500"></span>
           </span>
           <span className="text-[10px] text-gray-500 uppercase tracking-wider">Live Monitor</span>
        </div>
      </div>
      
      <div className="grid grid-cols-1 md:grid-cols-2 gap-4 mb-4">
        <div className="bg-black/50 rounded-lg p-3 border border-gray-800/50">
           <p className="text-[10px] text-gray-500 uppercase mb-1">Target Engine ID</p>
           <p className="text-xs text-blue-400 truncate">{activeModel}</p>
        </div>
        <div className="bg-black/50 rounded-lg p-3 border border-gray-800/50">
           <p className="text-[10px] text-gray-500 uppercase mb-1">Upstream Source URL</p>
           <p className="text-[10px] text-blue-400 truncate break-all">{sourceUrl}</p>
        </div>
      </div>

      <div className="bg-black rounded-lg p-3 border border-gray-800 h-40 overflow-y-auto custom-scrollbar text-[10px] leading-relaxed text-gray-400 flex flex-col-reverse">
        <div>
          {logs.length === 0 ? (
            <p className="opacity-50 italic">Waiting for AI Engine initialization events...</p>
          ) : (
            logs.map((log, i) => (
              <div key={i} className="mb-1 hover:bg-gray-800/50 px-1 rounded transition-colors break-words text-green-500/80">
                <span className="text-gray-600 mr-2">{'>'}</span> {log}
              </div>
            ))
          )}
        </div>
      </div>
    </div>
  );
}

export default function ModelSandboxTab() {
  const models = useLiveQuery(() => db.model_registry.toArray());
  const masterCategories = useLiveQuery(() => db.master_categories.toArray()) || [];
  
  const engineTypeOptions = masterCategories
    .filter(c => c.type === 'AI Engine Type')
    .map(c => ({ label: c.name, value: c.name }));
    
  const contextSourceOptions = masterCategories
    .filter(c => c.type === 'Context Source')
    .map(c => ({ label: c.name, value: c.name }));

  const [isAdding, setIsAdding] = useState(false);
  const [selectedMonitorId, setSelectedMonitorId] = useState<string | undefined>();
  const [newModel, setNewModel] = useState<{
    name: string;
    modelUrl: string;
    allowDistillation: boolean;
    apiKey: string;
    contextWindow: number;
    engineType: 'Localhost API' | 'Air-Gapped Network' | 'Cloud VPC (Internet Required)';
    contextSource: 'Global Corpus' | 'Architecture Reviews' | 'Threat Models';
  }>({ 
    name: '', 
    modelUrl: '', 
    allowDistillation: false, 
    apiKey: '', 
    contextWindow: 4096,
    engineType: 'Localhost API',
    contextSource: 'Global Corpus'
  });
  
  // Sideload state
  const [isSideloading, setIsSideloading] = useState(false);
  const [sideloadProgress, setSideloadProgress] = useState({ text: '', percent: 0 });
  const [sideloadModelName, setSideloadModelName] = useState('');
  const [sideloadModelUrl, setSideloadModelUrl] = useState('');

  const [routingThreshold, setRoutingThreshold] = useState(50);
  const [telemetryOptIn, setTelemetryOptIn] = useState(false);

  useEffect(() => {
    const loadSettings = async () => {
      const thresholdSetting = await db.app_settings.get('routingThreshold');
      if (thresholdSetting) setRoutingThreshold(thresholdSetting.value);
      
      const telemetrySetting = await db.app_settings.get('telemetryOptIn');
      if (telemetrySetting) setTelemetryOptIn(telemetrySetting.value);
    };
    loadSettings();
  }, []);

  const handleThresholdChange = async (val: number) => {
    setRoutingThreshold(val);
    await db.app_settings.put({ key: 'routingThreshold', value: val });
  };



  const handleAdd = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!newModel.name || !newModel.modelUrl) return;

    const payload = {
      name: newModel.name,
      type: 'SECONDARY' as const,
      modelUrl: newModel.modelUrl,
      isLocalhost: newModel.modelUrl.includes('localhost') || newModel.modelUrl.startsWith('/'),
      isActive: true,
      allowDistillation: newModel.allowDistillation,
      apiKey: newModel.apiKey,
      contextWindow: newModel.contextWindow,
      engineType: newModel.engineType,
      contextSource: newModel.contextSource
    };

    await db.model_registry.add(payload);
    Logger.("DB Write Success", payload);
    
    setNewModel({ 
      name: '', 
      modelUrl: '', 
      allowDistillation: false, 
      apiKey: '', 
      contextWindow: 4096,
      engineType: 'Localhost API',
      contextSource: 'Global Corpus'
    });
    setIsAdding(false);
  };

  const toggleDistillation = async (id: number, currentVal: boolean) => {
    const newVal = !currentVal;
    await db.model_registry.update(id, { allowDistillation: newVal });
    if (!newVal && (window as any).distillationWorker) {
      (window as any).distillationWorker.postMessage({ type: 'DISPOSE' });
    }
  };

  const handleSideloadClick = (files: FileList) => {
    if (!sideloadModelName || !sideloadModelUrl) {
      alert("Please enter a Model Name and Configuration URL before selecting a folder.");
      return;
    }
    handleFolderSelect(files);
  };

  const handleFolderSelect = async (files: FileList) => {
    setIsSideloading(true);
    setSideloadProgress({ text: 'Reading files...', percent: 0 });

    try {
      // Robustness check for WebLLM config payload
      let hasConfig = false;
      for (let i = 0; i < files.length; i++) {
        const file = files[i];
        if (file.name === 'mlc-chat-config.json' || (file.webkitRelativePath && file.webkitRelativePath.endsWith('mlc-chat-config.json'))) {
          hasConfig = true;
          break;
        }
      }

      if (!hasConfig) {
        throw new Error('Invalid Model Folder: mlc-chat-config.json missing.');
      }

      await SideloadService.processSideloadFolder(files, sideloadModelName, sideloadModelUrl, (text, percent) => {
        setSideloadProgress({ text, percent });
      });

      setCurrentPage(1);
      setSideloadProgress({ text: 'Sideload complete! Model is now available offline.', percent: 100 });
      setSideloadModelName('');
      setSideloadModelUrl('');
      
      setTimeout(() => {
        setIsSideloading(false);
        setSideloadProgress({ text: '', percent: 0 });
      }, 3000);

    } catch (error) {
      Logger.("Sideload failed:", error);
      setSideloadProgress({ text: `Error: ${error instanceof Error ? error.message : String(error)}`, percent: 0 });
      setTimeout(() => setIsSideloading(false), 5000);
    }
  };

  const [editTargetId, setEditTargetId] = useState<number | null>(null);
  const [currentPage, setCurrentPage] = useState(1);
  const pageSize = 5;

  const sideloadedModels = models?.filter(m => m.isLocalhost && m.type === 'SECONDARY') || [];
  const totalPages = Math.ceil(sideloadedModels.length / pageSize) || 1;
  const paginatedSideloaded = sideloadedModels.slice((currentPage - 1) * pageSize, currentPage * pageSize);

  return (
    <div className="w-full max-w-5xl">
      <PageHeader 
        icon={<Database className="text-purple-500" />}
        title="Model Sandbox & Edge Routing"
        description="Configure WebLLM endpoints. Add secondary models for Bring-Your-Own-Model (BYOM) telemetry processing."
      />

      <div className="bg-white dark:bg-gray-800 rounded-xl border border-gray-200 dark:border-gray-700 shadow-sm overflow-hidden mb-8">
         <div className="p-5 border-b border-gray-200 dark:border-gray-700 bg-gray-50 dark:bg-gray-800/50 flex justify-between items-center">
          <h3 className="text-sm font-semibold text-gray-700 dark:text-gray-300">BYOM Engine Registry (Network/VPC/Cloud)</h3>
          <button onClick={() => setIsAdding(!isAdding)} className="flex items-center gap-1.5 text-xs font-semibold bg-gray-200 dark:bg-gray-700 hover:bg-gray-300 dark:hover:bg-gray-600 px-3 py-1.5 rounded-md transition-colors text-gray-800 dark:text-gray-200">
            <Plus size={14} /> Add Secondary Model
          </button>
        </div>

        {isAdding && (
          <form onSubmit={handleAdd} className="p-5 bg-gray-50 dark:bg-gray-900/40 border-b border-gray-200 dark:border-gray-700 grid gap-4">
             <div className="grid grid-cols-2 gap-4">
               <div>
                 <label className="block text-xs font-medium text-gray-700 dark:text-gray-400 mb-1">Model Name / Alias</label>
                 <input type="text" required value={newModel.name} onChange={e => setNewModel({...newModel, name: e.target.value})} className="w-full rounded-md border border-gray-300 dark:border-gray-700 bg-white dark:bg-gray-800 text-sm p-2 outline-none focus:border-blue-500" placeholder="e.g. Llama-3-BYOM" />
               </div>
               <div>
                 <label className="block text-xs font-medium text-gray-700 dark:text-gray-400 mb-1">Endpoint URL</label>
                 <input type="url" required value={newModel.modelUrl} onChange={e => setNewModel({...newModel, modelUrl: e.target.value})} className="w-full rounded-md border border-gray-300 dark:border-gray-700 bg-white dark:bg-gray-800 text-sm p-2 outline-none focus:border-blue-500" placeholder="https://huggingface.co/..." />
               </div>
               <div>
                 <label className="block text-xs font-medium text-gray-700 dark:text-gray-400 mb-1">API Key (Optional)</label>
                 <input type="password" value={newModel.apiKey} onChange={e => setNewModel({...newModel, apiKey: e.target.value})} className="w-full rounded-md border border-gray-300 dark:border-gray-700 bg-white dark:bg-gray-800 text-sm p-2 outline-none focus:border-blue-500" placeholder="sk-..." />
               </div>
               <div>
                 <label className="block text-xs font-medium text-gray-700 dark:text-gray-400 mb-1">Context Window</label>
                 <input type="number" required value={newModel.contextWindow} onChange={e => setNewModel({...newModel, contextWindow: parseInt(e.target.value) || 4096})} className="w-full rounded-md border border-gray-300 dark:border-gray-700 bg-white dark:bg-gray-800 text-sm p-2 outline-none focus:border-blue-500" placeholder="4096" />
               </div>
               <div>
                 <label className="block text-xs font-medium text-gray-700 dark:text-gray-400 mb-1">Engine Type</label>
                 <CreatableDropdown 
                   value={newModel.engineType}
                   onChange={val => setNewModel({...newModel, engineType: val as any})}
                   options={engineTypeOptions.length > 0 ? engineTypeOptions : [
                     { label: 'Localhost API', value: 'Localhost API' },
                     { label: 'Air-Gapped Network', value: 'Air-Gapped Network' },
                     { label: 'Cloud VPC (Internet Required)', value: 'Cloud VPC (Internet Required)' }
                   ]}
                   categoryType="AI Engine Type"
                   placeholder="Select engine type..."
                 />
               </div>
               <div>
                 <label className="block text-xs font-medium text-gray-700 dark:text-gray-400 mb-1">Context Source</label>
                 <CreatableDropdown 
                   value={newModel.contextSource}
                   onChange={val => setNewModel({...newModel, contextSource: val as any})}
                   options={contextSourceOptions.length > 0 ? contextSourceOptions : [
                     { label: 'Global Corpus', value: 'Global Corpus' },
                     { label: 'Architecture Reviews', value: 'Architecture Reviews' },
                     { label: 'Threat Models', value: 'Threat Models' }
                   ]}
                   categoryType="Context Source"
                   placeholder="Select context source..."
                 />
               </div>
               <div className="col-span-2 flex items-center gap-2 mt-2">
                 <input type="checkbox" id="allowDistillation" checked={newModel.allowDistillation} onChange={e => setNewModel({...newModel, allowDistillation: e.target.checked})} className="rounded border-gray-300 text-blue-600 focus:ring-blue-500" />
                 <label htmlFor="allowDistillation" className="text-sm font-medium text-gray-700 dark:text-gray-300">Enable as Distillation Target</label>
               </div>
             </div>
             <div className="flex justify-end items-center gap-3 mt-4">
                <button type="submit" className="bg-blue-600 hover:bg-blue-700 text-white px-4 py-1.5 rounded-md text-sm font-medium transition-colors">Save Engine</button>
                <button type="button" onClick={() => setIsAdding(false)} className="text-sm text-gray-500 hover:text-gray-800 dark:hover:text-white">Cancel</button>
             </div>
          </form>
        )}

        <table className="w-full text-left text-sm">
          <thead className="bg-gray-100 dark:bg-gray-900/50">
            <tr>
              <th className="px-5 py-3 font-medium text-gray-500 dark:text-gray-400">Engine Type</th>
              <th className="px-5 py-3 font-medium text-gray-500 dark:text-gray-400">Model Definition</th>
              <th className="px-5 py-3 font-medium text-gray-500 dark:text-gray-400">Context Source</th>
              <th className="px-5 py-3 font-medium text-gray-500 dark:text-gray-400">Context Window</th>
              <th className="px-5 py-3 font-medium text-gray-500 dark:text-gray-400">Distillation Target</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-gray-200 dark:divide-gray-700">
            {models?.map(m => (
              <tr 
                key={m.id} 
                className={`hover:bg-gray-50 dark:hover:bg-gray-800/50 cursor-pointer ${selectedMonitorId === m.name ? 'bg-blue-50 dark:bg-blue-900/20' : ''}`}
                onClick={() => setSelectedMonitorId(m.name)}
              >
                <td className="px-5 py-4">
                  <span className={`inline-flex px-2 py-0.5 rounded text-[10px] font-bold uppercase tracking-wider ${m.type === 'PRIMARY' ? 'bg-purple-100 text-purple-700 dark:bg-purple-900/30 dark:text-purple-400' : 'bg-blue-100 text-blue-700 dark:bg-blue-900/30 dark:text-blue-400'}`}>
                    {m.engineType || m.type}
                  </span>
                </td>
                <td className="px-5 py-4 font-mono font-medium text-xs text-gray-900 dark:text-gray-100 line-clamp-2" title={m.name}>{m.name}</td>
                <td className="px-5 py-4 text-xs text-gray-500 dark:text-gray-400 flex items-center gap-1.5">
                  {m.isLocalhost ? <Server className="w-3 h-3 text-green-500" /> : <div className="w-2 h-2 rounded-full bg-yellow-500" />} 
                  {m.contextSource || (m.isLocalhost ? 'Localhost (Air-Gapped)' : 'External URI')}
                </td>
                <td className="px-5 py-4 text-xs text-gray-500 dark:text-gray-400">
                  {m.contextWindow || 'N/A'}
                </td>
                <td className="px-5 py-4">
                   {m.type === 'PRIMARY' ? (
                     <span className="text-xs text-gray-400 italic">Self (Target)</span>
                   ) : editTargetId === m.id ? (
                     <select 
                       value={m.allowDistillation ? 'Local Dataset (JSONL)' : 'Disabled/None'}
                       onChange={async (e) => {
                         await toggleDistillation(m.id!, e.target.value === 'Local Dataset (JSONL)');
                         setEditTargetId(null);
                       }}
                       onBlur={() => setEditTargetId(null)}
                       className="text-xs p-1 rounded bg-white dark:bg-gray-800 border border-gray-300 dark:border-gray-600 outline-none text-gray-900 dark:text-gray-100"
                       aria-label="Distillation Options"
                       title="Distillation Options"
                       autoFocus
                     >
                       <option>Disabled/None</option>
                       <option>Local Dataset (JSONL)</option>
                     </select>
                   ) : (
                     <div className="flex items-center gap-2">
                       <span className={`inline-flex px-2 py-0.5 rounded text-[10px] font-bold uppercase ${
                         m.allowDistillation 
                           ? 'bg-blue-100 text-blue-700 dark:bg-blue-900/30 dark:text-blue-400' 
                           : 'bg-gray-100 text-gray-600 dark:bg-gray-800 dark:text-gray-400'
                       }`}>
                         {m.allowDistillation ? 'Local Dataset (JSONL)' : 'Disabled/None'}
                       </span>
                       <button onClick={() => setEditTargetId(m.id!)} className="text-[10px] underline text-blue-500 hover:text-blue-700">
                         Configure
                       </button>
                     </div>
                   )}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-8">
        <div className="bg-white dark:bg-gray-800 rounded-xl border border-gray-200 dark:border-gray-700 shadow-sm overflow-hidden">
          <div className="p-5 border-b border-gray-200 dark:border-gray-700 bg-gray-50 dark:bg-gray-800/50 flex justify-between items-center">
            <h3 className="text-sm font-semibold text-gray-700 dark:text-gray-300">Semantic Edge Routing</h3>
          </div>
          <div className="p-5">
            <label htmlFor="routing-threshold" className="block text-xs font-medium text-gray-700 dark:text-gray-400 mb-2">Complexity Routing Threshold: {routingThreshold}</label>
            <input 
              id="routing-threshold"
              type="range" 
              min="1" 
              max="100" 
              value={routingThreshold} 
              onChange={(e) => handleThresholdChange(parseInt(e.target.value))}
              className="w-full h-2 bg-gray-200 rounded-lg appearance-none cursor-pointer dark:bg-gray-700"
            />
            <p className="text-[10px] text-gray-500 mt-2">
              Queries with a complexity score below this threshold will be routed to the fast Primary Core Model. Queries above this threshold will be routed to the Secondary BYOM model (if available).
            </p>
          </div>
        </div>

        <div className="bg-white dark:bg-gray-800 rounded-xl border border-gray-200 dark:border-gray-700 shadow-sm overflow-hidden">
          <div className="p-5 border-b border-gray-200 dark:border-gray-700 bg-gray-50 dark:bg-gray-800/50 flex justify-between items-center">
            <h3 className="text-sm font-semibold text-gray-700 dark:text-gray-300">Model Foundry & Marketplace (MVP 3.0 Roadmap)</h3>
            <span className="px-2 py-1 bg-gray-200 dark:bg-gray-700 text-gray-600 dark:text-gray-400 rounded text-[10px] font-bold uppercase tracking-wider">
              [ Foundry Locked - Coming in V3 ]
            </span>
          </div>
          <div className="p-5">
            <p className="text-xs text-gray-600 dark:text-gray-400 mb-4">
              Future Capability: Distill your local enterprise corpus into specialized Subject Matter Expert (SME) models. Export custom weights or publish your trained agents directly to the Decentralized EA Marketplace.
            </p>
            <div className="flex items-center justify-between mb-2 opacity-50 pointer-events-none">
              <span className="text-xs font-medium text-gray-700 dark:text-gray-400">Enable Opt-In Telemetry Sync</span>
              <label className="relative inline-flex items-center cursor-pointer">
                <input type="checkbox" className="sr-only peer" checked={telemetryOptIn} readOnly aria-label="Enable telemetry sync" />
                <div className="w-9 h-5 bg-gray-200 peer-focus:outline-none peer-focus:ring-4 peer-focus:ring-blue-300 dark:peer-focus:ring-blue-800 rounded-full peer dark:bg-gray-700 peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-white after:border-gray-300 after:border after:rounded-full after:h-4 after:w-4 after:transition-all dark:border-gray-600 peer-checked:bg-blue-600"></div>
              </label>
            </div>
            {telemetryOptIn && (
              <div className="bg-yellow-50 dark:bg-yellow-900/20 border border-yellow-200 dark:border-yellow-800 rounded p-2 mt-2 opacity-50">
                <p className="text-[10px] text-yellow-800 dark:text-yellow-500">
                  <strong>Warning:</strong> Enabling this feature will send anonymized usage metrics and model performance data to the global EA-NITI marketplace. Ensure this complies with your organization's data privacy policies.
                </p>
              </div>
            )}
          </div>
        </div>
      </div>

      <div className="bg-white dark:bg-gray-800 rounded-xl border border-gray-200 dark:border-gray-700 shadow-sm overflow-hidden mb-8">
        <div className="p-5 border-b border-gray-200 dark:border-gray-700 bg-gray-50 dark:bg-gray-800/50 flex justify-between items-center">
          <h3 className="text-sm font-semibold text-gray-700 dark:text-gray-300 flex items-center gap-2">
            <FolderUp className="text-blue-500" size={18} />
            Offline Sideload Library (Browser Cache)
          </h3>
        </div>
        <div className="p-5 grid gap-4">
          <p className="text-sm text-gray-500 dark:text-gray-400">
            Securely load multiple WebLLM model weights directly from a local folder (e.g., USB drive). This bypasses all network requests and writes directly to the browser's IndexedDB CacheStorage, ensuring 100% air-gapped compliance. You can upload multiple models sequentially.
          </p>
          
          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-xs font-medium text-gray-700 dark:text-gray-400 mb-1">Model Name / Alias</label>
              <input type="text" value={sideloadModelName} onChange={e => setSideloadModelName(e.target.value)} className="w-full rounded-md border border-gray-300 dark:border-gray-700 bg-white dark:bg-gray-900 text-sm p-2 outline-none focus:border-blue-500" placeholder="e.g. Llama-3-Sideloaded" disabled={isSideloading} />
            </div>
            <div>
              <label className="block text-xs font-medium text-gray-700 dark:text-gray-400 mb-1">Model Configuration URL (Base URL)</label>
              <input type="url" value={sideloadModelUrl} onChange={e => setSideloadModelUrl(e.target.value)} className="w-full rounded-md border border-gray-300 dark:border-gray-700 bg-white dark:bg-gray-900 text-sm p-2 outline-none focus:border-blue-500" placeholder="https://huggingface.co/..." disabled={isSideloading} />
            </div>
          </div>

          <div className="mt-2">
            <FolderUploadButton 
              onFolderSelect={handleSideloadClick}
              isLoading={isSideloading}
              id="sandbox-sideload-input"
            />
          </div>

          {isSideloading && (
            <div className="mt-4 bg-gray-50 dark:bg-gray-900 rounded-lg p-4 border border-gray-200 dark:border-gray-700">
              <div className="flex justify-between text-xs font-medium text-gray-700 dark:text-gray-300 mb-1">
                <span>{sideloadProgress.text}</span>
                <span>{sideloadProgress.percent}%</span>
              </div>
              <div className="w-full bg-gray-200 dark:bg-gray-700 rounded-full h-2">
                <div
                  className={`bg-blue-600 h-2 rounded-full transition-all duration-300 progress-width-${Math.min(100, Math.max(0, Math.round(sideloadProgress.percent / 10) * 10))}`}

                />
              </div>
            </div>
          )}

          <div className="mt-6">
            <div className="flex items-center justify-between mb-2">
              <h4 className="text-xs font-semibold text-gray-700 dark:text-gray-300">Sideloaded Engines</h4>
            </div>
            <div className="border border-gray-200 dark:border-gray-700 rounded-md overflow-hidden">
              <table className="w-full text-left text-sm">
                <thead className="bg-gray-100 dark:bg-gray-900/50">
                  <tr>
                    <th className="px-4 py-2 font-medium text-gray-500 dark:text-gray-400">Alias</th>
                    <th className="px-4 py-2 font-medium text-gray-500 dark:text-gray-400">Cache Size</th>
                    <th className="px-4 py-2 font-medium text-gray-500 dark:text-gray-400">Action</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-gray-200 dark:divide-gray-700">
                  {sideloadedModels.length === 0 ? (
                    <tr>
                      <td colSpan={3} className="px-4 py-3 text-xs text-gray-500 text-center italic">No models sideloaded yet.</td>
                    </tr>
                  ) : (
                    paginatedSideloaded.map(m => (
                      <tr key={m.id} className="hover:bg-gray-50 dark:hover:bg-gray-800/50">
                        <td className="px-4 py-2 font-mono text-xs text-gray-900 dark:text-gray-100">{m.name}</td>
                        <td className="px-4 py-2 text-xs text-gray-500 dark:text-gray-400">Cached</td>
                        <td className="px-4 py-2">
                          <button 
                            onClick={async () => {
                              if (m.id) {
                                await SideloadService.deleteSideloadedModel(m.modelUrl);
                                await db.model_registry.delete(m.id);
                              }
                            }}
                            className="text-xs text-red-500 hover:text-red-700 flex items-center gap-1"
                          >
                            <Trash2 size={12} /> Delete
                          </button>
                        </td>
                      </tr>
                    ))
                  )}
                </tbody>
              </table>
              
              {/* Pagination UI */}
              <div className="px-4 py-2 border-t border-gray-200 dark:border-gray-700 bg-gray-50 dark:bg-gray-900/50 flex items-center justify-between">
                <span className="text-[10px] text-gray-500 dark:text-gray-400">
                  Page {currentPage} of {totalPages}
                </span>
                <div className="flex gap-2">
                  <button 
                    onClick={() => setCurrentPage(prev => Math.max(1, prev - 1))}
                    disabled={currentPage === 1}
                    className="px-2 py-1 text-[10px] font-medium text-gray-600 dark:text-gray-400 bg-white dark:bg-gray-800 border border-gray-300 dark:border-gray-700 rounded disabled:opacity-50 disabled:cursor-not-allowed hover:bg-gray-50 dark:hover:bg-gray-700 transition-colors"
                  >
                    Previous
                  </button>
                  <button 
                    onClick={() => setCurrentPage(prev => Math.min(totalPages, prev + 1))}
                    disabled={currentPage === totalPages}
                    className="px-2 py-1 text-[10px] font-medium text-gray-600 dark:text-gray-400 bg-white dark:bg-gray-800 border border-gray-300 dark:border-gray-700 rounded disabled:opacity-50 disabled:cursor-not-allowed hover:bg-gray-50 dark:hover:bg-gray-700 transition-colors"
                  >
                    Next
                  </button>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>

      <div className="bg-blue-50 dark:bg-blue-900/10 border border-blue-200 dark:border-blue-900/40 rounded-xl p-5 flex gap-4 mt-6">
        <Info className="text-blue-500 shrink-0 mt-0.5" size={20} />
        <div>
           <h4 className="text-sm font-bold text-blue-800 dark:text-blue-300 mb-1">How Distillation Routing Works</h4>
           <p className="text-xs text-blue-700 dark:text-blue-400/80 leading-relaxed max-w-2xl">
             When <strong>Distillation Target</strong> is enabled on a Secondary BYOM model, all complex architectural evaluation queries will be routed transparently to the Secondary engine. The insights returned will be automatically vectorized by the Transformers.js embedder and synchronized into the local knowledge base, allowing the fast Primary Core Model to leverage them in the future natively.
           </p>
        </div>
      </div>
      
      <EngineDiagnostics selectedModelId={selectedMonitorId} />
    </div>
  );
}

import React, { useState, useEffect } from 'react';
import { useLiveQuery } from 'dexie-react-hooks';
import { db, NetworkIntegration } from '../../lib/db';
import { Plus, Edit, Trash2, Eye, EyeOff, ShieldAlert, Save, RefreshCw, Loader2, Globe, KeyRound, ExternalLink, CheckCircle2, Network } from 'lucide-react';
import ConfirmModal from '../ui/ConfirmModal';
import { OAUTH_PROVIDERS, getRedirectUri } from '../../lib/oauthConfig';
import PageHeader from '../ui/PageHeader';
import { encryptString, decryptString } from '../../lib/cryptoVault';

export default function NetworkIntegrationTab() {
  const providers = useLiveQuery(() => db.network_integrations.toArray()) || [];
  const appSettings = useLiveQuery(() => db.app_settings.toArray()) || [];

  const enableNetworkIntegrations =
    appSettings.find(s => s.key === 'enableNetworkIntegrations')?.value === true;


  const [formMode, setFormMode] = useState<'add' | 'edit' | null>(null);
  const [selectedProvider, setSelectedProvider] = useState<NetworkIntegration | null>(null);
  const [formData, setFormData] = useState({
    displayName: '',
    endpointUrl: '',
    apiKey: '',
    providerType: 'WebSearchAPI' as 'WebSearchAPI' | 'CloudLLMAPI' | 'CustomEnterprise',
    isDefault: false,
    modelName: '',
  });
  const [showApiKey, setShowApiKey] = useState(false);
  const [error, setError] = useState<string | null>(null);
  const [saveMessage, setSaveMessage] = useState<{ type: 'success' | 'error'; text: string } | null>(null);
  const [itemToDelete, setItemToDelete] = useState<number | null>(null);
  const [isPullingLive, setIsPullingLive] = useState(false);

  // SSO Provider Config State
  const [googleClientId, setGoogleClientId] = useState('');
  const [microsoftClientId, setMicrosoftClientId] = useState('');
  const [ssoSaveMessage, setSsoSaveMessage] = useState<{ type: 'success' | 'error'; text: string } | null>(null);

  useEffect(() => {
    const loadSettings = async () => {
      const setting = await db.app_settings.get('enableNetworkIntegrations');
      if (!setting) {
        await db.app_settings.put({ key: 'enableNetworkIntegrations', value: false });
      }
      // Load SSO client IDs
      const gId = await db.app_settings.get('SSO_GOOGLE_CLIENT_ID');
      const mId = await db.app_settings.get('SSO_MICROSOFT_CLIENT_ID');
      if (gId?.value) setGoogleClientId(gId.value);
      if (mId?.value) setMicrosoftClientId(mId.value);
    };
    loadSettings();
  }, []);

  const resetForm = () => {
    setFormData({
      displayName: '',
      endpointUrl: '',
      apiKey: '',
      providerType: 'WebSearchAPI',
      isDefault: false,
      modelName: '',
    });
    setError(null);
    setShowApiKey(false);
  };

  const handleAddProvider = () => {
    setFormMode('add');
    setSelectedProvider(null);
    resetForm();
  };

  const handleEditProvider = async (provider: NetworkIntegration) => {
    setFormMode('edit');
    setSelectedProvider(provider);

    // Decrypt API key if encrypted version exists
    let decryptedKey = '';
    if (provider.encryptedApiKey) {
      try {
        decryptedKey = await decryptString(provider.encryptedApiKey);
      } catch (e) {
        console.error('[SECURITY] Failed to decrypt API key:', e);
        setError('Failed to decrypt stored API key. It may be corrupted.');
      }
    } else if (provider.apiKey) {
      // Fallback for legacy plaintext API keys
      decryptedKey = provider.apiKey;
    }

    setFormData({
      displayName: provider.displayName,
      endpointUrl: provider.endpointUrl,
      apiKey: decryptedKey,
      providerType: provider.providerType,
      isDefault: provider.isDefault,
      modelName: provider.modelName || '',
    });
    setError(null);
  };

  const validateForm = (): boolean => {
    setError(null);
    if (!formData.displayName.trim()) {
      setError('Display name is required');
      return false;
    }
    if (!formData.endpointUrl.trim()) {
      setError('Endpoint URL is required');
      return false;
    }
    if (formData.providerType !== 'CustomEnterprise' && !formData.apiKey.trim()) {
      setError('API key is required');
      return false;
    }
    if (formData.providerType === 'CustomEnterprise' && !formData.modelName.trim()) {
      setError('Model Name is required for Custom Enterprise endpoints');
      return false;
    }
    try {
      new URL(formData.endpointUrl);
    } catch {
      setError('Invalid URL format');
      return false;
    }
    return true;
  };

  const handleSaveProvider = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!validateForm()) return;

    try {
      // Encrypt the API key before storage
      const encryptedApiKey = formData.apiKey ? await encryptString(formData.apiKey) : undefined;

      const providerData: NetworkIntegration = {
        displayName: formData.displayName,
        endpointUrl: formData.endpointUrl,
        encryptedApiKey: encryptedApiKey,
        providerType: formData.providerType,
        isDefault: formData.isDefault,
        modelName: formData.modelName || undefined,
        createdAt: selectedProvider?.createdAt || new Date(),
      };

      if (formMode === 'add') {
        await db.network_integrations.add(providerData);
        if (providerData.providerType === 'CustomEnterprise' && providerData.modelName) {
          await db.model_registry.add({
            name: providerData.modelName,
            type: 'BYOM_NETWORK',
            modelUrl: providerData.endpointUrl,
            encryptedApiKey: encryptedApiKey,
            isLocalhost: providerData.endpointUrl.includes('localhost') || providerData.endpointUrl.includes('127.0.0.1'),
            isActive: true
          });
        }
        setSaveMessage({ type: 'success', text: 'Provider added successfully!' });
      } else if (formMode === 'edit' && selectedProvider?.id) {
        await db.network_integrations.update(selectedProvider.id, providerData);
        if (providerData.providerType === 'CustomEnterprise' && providerData.modelName) {
           // Try to update existing model registry entry if it exists with encrypted API credentials.
           const existingModel = await db.model_registry.where('modelUrl').equals(selectedProvider.endpointUrl).first();
           if (existingModel && existingModel.id) {
             await db.model_registry.update(existingModel.id, {
               name: providerData.modelName,
               modelUrl: providerData.endpointUrl,
               encryptedApiKey: encryptedApiKey,
               apiKey: undefined,
               isLocalhost: providerData.endpointUrl.includes('localhost') || providerData.endpointUrl.includes('127.0.0.1')
             });
           } else {
             await db.model_registry.add({
               name: providerData.modelName,
               type: 'BYOM_NETWORK',
               modelUrl: providerData.endpointUrl,
               encryptedApiKey: encryptedApiKey,
               isLocalhost: providerData.endpointUrl.includes('localhost') || providerData.endpointUrl.includes('127.0.0.1'),
               isActive: true
             });
           }
        }
        setSaveMessage({ type: 'success', text: 'Provider updated successfully!' });
      }

      resetForm();
      setFormMode(null);
      setTimeout(() => setSaveMessage(null), 3000);
    } catch (err) {
      const errorText = err instanceof Error ? err.message : 'Failed to save provider';
      setSaveMessage({ type: 'error', text: errorText });
    }
  };

  const handleDeleteProvider = async () => {
    if (!itemToDelete) return;

    try {
      await db.network_integrations.delete(itemToDelete);
      setSaveMessage({ type: 'success', text: 'Provider deleted successfully!' });
      setItemToDelete(null);
      setTimeout(() => setSaveMessage(null), 3000);
    } catch {
      setSaveMessage({ type: 'error', text: 'Failed to delete provider' });
    }
  };

  const handleSetDefault = async (providerId: number) => {
    try {
      const all = await db.network_integrations.toArray();
      await Promise.all(
        all.map(p => (p.id === providerId ? db.network_integrations.update(p.id!, { isDefault: true }) : db.network_integrations.update(p.id!, { isDefault: false })))
      );
      setSaveMessage({ type: 'success', text: 'Default provider set!' });
      setTimeout(() => setSaveMessage(null), 3000);
    } catch {
      setSaveMessage({ type: 'error', text: 'Failed to set default provider' });
    }
  };

  const handleToggleNetworkIntegrations = async (enabled: boolean) => {
    try {
      await db.app_settings.put({ key: 'enableNetworkIntegrations', value: enabled });
      setSaveMessage({ type: 'success', text: enabled ? 'Network integrations enabled' : 'Network integrations disabled' });
      setTimeout(() => setSaveMessage(null), 3000);
    } catch {
      setSaveMessage({ type: 'error', text: 'Failed to update setting' });
    }
  };

  const handleSaveSsoConfig = async () => {
    try {
      if (googleClientId.trim()) {
        await db.app_settings.put({ key: 'SSO_GOOGLE_CLIENT_ID', value: googleClientId.trim() });
      } else {
        await db.app_settings.delete('SSO_GOOGLE_CLIENT_ID');
      }
      if (microsoftClientId.trim()) {
        await db.app_settings.put({ key: 'SSO_MICROSOFT_CLIENT_ID', value: microsoftClientId.trim() });
      } else {
        await db.app_settings.delete('SSO_MICROSOFT_CLIENT_ID');
      }
      setSsoSaveMessage({ type: 'success', text: 'SSO configuration saved successfully!' });
      setTimeout(() => setSsoSaveMessage(null), 3000);
    } catch {
      setSsoSaveMessage({ type: 'error', text: 'Failed to save SSO configuration.' });
      setTimeout(() => setSsoSaveMessage(null), 3000);
    }
  };

  const handlePullLiveLearnings = async () => {
    if (!enableNetworkIntegrations) {
        setSaveMessage({ type: 'error', text: 'Network Integrations are globally disabled. Enable them above.' });
        setTimeout(() => setSaveMessage(null), 3000);
        return;
    }
    const hasApi = providers.some(p => p.providerType === 'WebSearchAPI' || p.providerType === 'CloudLLMAPI');
    if (!hasApi) {
        setSaveMessage({ type: 'error', text: 'No external APIs configured. Please add a Web Search API.' });
        setTimeout(() => setSaveMessage(null), 3000);
        return;
    }

    setIsPullingLive(true);
    try {
        // Mock external fetching logic insertion
        await new Promise(r => setTimeout(r, 2000)); 
        await db.architecture_principles.add({
            name: `Cloud-First API Governance (Synced ${new Date().toISOString().split('T')[0]})`,
            statement: "All external capabilities must surface decoupled APIs.",
            rationale: "Pulled from latest Gartner 2026 Architectural Sync.",
            implications: "Legacy monoliths require strangler-fig API wrappers.",
            layerId: 1,
            status: "Needs Review"
        });
        setSaveMessage({ type: 'success', text: 'Live learning payload synced successfully! 1 Pattern Drafted.' });
    } catch (e) {
        setSaveMessage({ type: 'error', text: 'Failed to sync live learnings externally.' });
    } finally {
        setIsPullingLive(false);
        setTimeout(() => setSaveMessage(null), 4000);
    }
  };

  const redirectUri = getRedirectUri();

  return (
    <div className="flex flex-col max-w-4xl">
      <PageHeader 
        icon={<Network className="text-indigo-500" />}
        title="Network & Privacy"
        description="Configure external data providers, SSO identity providers, and manage privacy controls."
      />

      <div className="bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-xl p-6 mb-6">
        <div className="flex items-center justify-between">
          <div>
            <h4 className="text-sm font-medium text-gray-900 dark:text-white">Enable External Network Features</h4>
            <p className="text-xs text-gray-500 dark:text-gray-400 mt-1">Allow the app to connect to external endpoints for market trends and analysis.</p>
          </div>
          <label className="relative inline-flex items-center cursor-pointer">
            <input
              type="checkbox"
              className="sr-only peer"
              checked={enableNetworkIntegrations}
              onChange={(e) => handleToggleNetworkIntegrations(e.target.checked)}
              aria-label="Enable External Network Features"
              title="Enable External Network Features"
            />
            <div className="w-11 h-6 bg-gray-200 peer-focus:outline-none peer-focus:ring-4 peer-focus:ring-blue-300 dark:peer-focus:ring-blue-800 rounded-full peer dark:bg-gray-700 peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-white after:border-gray-300 after:border after:rounded-full after:h-5 after:w-5 after:transition-all dark:border-gray-600 peer-checked:bg-blue-600"></div>
          </label>
        </div>
      </div>

      <div className="bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-xl p-6 mb-6">
        <div className="flex items-start gap-4">
          <div className="p-3 bg-amber-100 dark:bg-amber-900/30 text-amber-600 dark:text-amber-400 rounded-lg shrink-0">
            <ShieldAlert size={24} />
          </div>
          <div>
            <h4 className="text-base font-medium text-gray-900 dark:text-white mb-1">Privacy Guarantee</h4>
            <p className="text-sm text-gray-600 dark:text-gray-400">
              When enabled, this app will connect to external endpoints to fetch data. Your local architecture data, principles, tags, and database context will <strong>NEVER</strong> be sent to external APIs. Only the generic query is transmitted.
            </p>
          </div>
        </div>
      </div>

      {/* ─── Authentication Settings (OAuth / SSO) ─── */}
      <div className="bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-xl p-6 mb-6">
        <div className="flex items-center gap-3 mb-4">
          <div className="p-2.5 bg-blue-100 dark:bg-blue-900/30 text-blue-600 dark:text-blue-400 rounded-lg">
            <KeyRound size={20} />
          </div>
          <div>
            <h4 className="text-base font-medium text-gray-900 dark:text-white">Authentication Settings (OAuth)</h4>
            <p className="text-xs text-gray-500 dark:text-gray-400 mt-0.5">OAuth 2.0 PKCE Client IDs for Hybrid SSO — no secrets required (public SPA clients).</p>
          </div>
        </div>

        <div className="space-y-4">
          {/* Google */}
          <div className="p-4 bg-gray-50 dark:bg-gray-900/50 rounded-lg border border-gray-200 dark:border-gray-700">
            <div className="flex items-center justify-between mb-2">
              <div className="flex items-center gap-2">
                <Globe size={16} className="text-red-500" />
                <span className="text-sm font-semibold text-gray-900 dark:text-white">Google</span>
              </div>
              <a href="https://console.cloud.google.com/apis/credentials" target="_blank" rel="noopener noreferrer" className="flex items-center gap-1 text-[10px] text-blue-600 dark:text-blue-400 hover:underline">
                <ExternalLink size={10} /> Console
              </a>
            </div>
            <div>
              <label className="block text-[10px] font-medium text-gray-500 dark:text-gray-400 mb-0.5">Client ID</label>
              <input
                type="text"
                value={googleClientId}
                onChange={e => setGoogleClientId(e.target.value)}
                placeholder={OAUTH_PROVIDERS.google.defaultClientId}
                className="w-full bg-white dark:bg-gray-800 border border-gray-300 dark:border-gray-600 rounded-lg px-3 py-1.5 text-sm text-gray-900 dark:text-white outline-none focus:border-blue-500 font-mono text-xs"
              />
            </div>
            <div className="flex gap-4 text-[10px] text-gray-500 dark:text-gray-400 mt-1.5">
              <span><strong>Auth:</strong> {OAUTH_PROVIDERS.google.authEndpoint}</span>
            </div>
          </div>

          {/* Microsoft */}
          <div className="p-4 bg-gray-50 dark:bg-gray-900/50 rounded-lg border border-gray-200 dark:border-gray-700">
            <div className="flex items-center justify-between mb-2">
              <div className="flex items-center gap-2">
                <Globe size={16} className="text-blue-600" />
                <span className="text-sm font-semibold text-gray-900 dark:text-white">Microsoft</span>
              </div>
              <a href="https://portal.azure.com/#blade/Microsoft_AAD_RegisteredApps" target="_blank" rel="noopener noreferrer" className="flex items-center gap-1 text-[10px] text-blue-600 dark:text-blue-400 hover:underline">
                <ExternalLink size={10} /> Azure AD
              </a>
            </div>
            <div>
              <label className="block text-[10px] font-medium text-gray-500 dark:text-gray-400 mb-0.5">Client ID</label>
              <input
                type="text"
                value={microsoftClientId}
                onChange={e => setMicrosoftClientId(e.target.value)}
                placeholder={OAUTH_PROVIDERS.microsoft.defaultClientId}
                className="w-full bg-white dark:bg-gray-800 border border-gray-300 dark:border-gray-600 rounded-lg px-3 py-1.5 text-sm text-gray-900 dark:text-white outline-none focus:border-blue-500 font-mono text-xs"
              />
            </div>
            <div className="flex gap-4 text-[10px] text-gray-500 dark:text-gray-400 mt-1.5">
              <span><strong>Auth:</strong> {OAUTH_PROVIDERS.microsoft.authEndpoint}</span>
            </div>
          </div>

          {/* Redirect URI (readonly) */}
          <div className="p-3 bg-emerald-50 dark:bg-emerald-500/10 rounded-lg border border-emerald-200 dark:border-emerald-500/20">
            <div className="flex items-center gap-2">
              <CheckCircle2 size={14} className="text-emerald-600 dark:text-emerald-400 shrink-0" />
              <p className="text-[10px] text-emerald-800 dark:text-emerald-200">
                <strong>Redirect URI:</strong> <code className="bg-emerald-100 dark:bg-emerald-900/30 px-1.5 py-0.5 rounded font-mono">{redirectUri}</code>
                <span className="text-emerald-600 dark:text-emerald-400 ml-2">— Register this in both provider consoles.</span>
              </p>
            </div>
          </div>

          {/* Save + Status */}
          <div className="flex items-center gap-3">
            <button
              onClick={handleSaveSsoConfig}
              className="flex items-center gap-2 px-4 py-2 bg-blue-600 hover:bg-blue-700 text-white rounded-lg text-sm font-medium transition-colors"
            >
              <Save size={14} /> Save SSO Configuration
            </button>
            {ssoSaveMessage && (
              <span className={`text-xs font-medium ${ssoSaveMessage.type === 'success' ? 'text-green-600 dark:text-green-400' : 'text-red-600 dark:text-red-400'}`}>
                {ssoSaveMessage.text}
              </span>
            )}
          </div>
        </div>
      </div>
      <div className="bg-gradient-to-br from-indigo-50 to-purple-50 dark:from-indigo-900/10 dark:to-purple-900/10 border border-indigo-200 dark:border-indigo-800/50 rounded-xl p-6 mb-8 flex justify-between items-center">
         <div>
            <h4 className="text-base font-bold text-gray-900 dark:text-white flex items-center gap-2 mb-1">
               <Globe className="text-indigo-600 dark:text-indigo-400" size={18} />
               Sync Live Enterprise Trends (Web Pull)
            </h4>
            <p className="text-sm text-gray-600 dark:text-gray-400 max-w-2xl">
               Scraping connected Cloud APIs to automatically identify new industry taxonomy shifts and drafting them as "Needs Review" Architecture Principles in your local NITI database.
            </p>
         </div>
         <button 
            onClick={handlePullLiveLearnings}
            disabled={isPullingLive}
            className="flex items-center gap-2 px-5 py-2.5 bg-indigo-600 hover:bg-indigo-700 disabled:opacity-50 text-white rounded-lg font-medium transition-colors shadow-md whitespace-nowrap"
         >
            {isPullingLive ? <Loader2 size={18} className="animate-spin" /> : <RefreshCw size={18} />}
            {isPullingLive ? 'Syncing...' : 'Pull Live Learnings'}
         </button>
      </div>

      {formMode && (
        <div className="bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-xl p-6 mb-6">
          <h4 className="text-base font-medium text-gray-900 dark:text-white mb-4">{formMode === 'add' ? 'Add New Provider' : 'Edit Provider'}</h4>
          <form onSubmit={handleSaveProvider} className="space-y-4">
            {error && <div className="p-3 bg-red-100 dark:bg-red-900/20 border border-red-200 dark:border-red-800 text-red-700 dark:text-red-400 rounded-lg text-sm">{error}</div>}

            <div>
              <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">Display Name</label>
              <input type="text" value={formData.displayName} onChange={(e) => setFormData(prev => ({ ...prev, displayName: e.target.value }))} className="w-full bg-gray-50 dark:bg-gray-900 border border-gray-300 dark:border-gray-700 rounded-lg px-4 py-2 text-gray-900 dark:text-white outline-none focus:border-blue-500" placeholder="e.g., Tavily API" />
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">Provider Type</label>
              <select value={formData.providerType} onChange={(e) => setFormData(prev => ({ ...prev, providerType: e.target.value as any }))} className="w-full bg-gray-50 dark:bg-gray-900 border border-gray-300 dark:border-gray-700 rounded-lg px-4 py-2 text-gray-900 dark:text-white outline-none focus:border-blue-500" aria-label="Provider Type" title="Provider Type">
                <option value="WebSearchAPI">Web Search API</option>
                <option value="CloudLLMAPI">Cloud LLM API</option>
                <option value="CustomEnterprise">Custom Enterprise</option>
              </select>
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">Endpoint URL</label>
              <input type="url" value={formData.endpointUrl} onChange={(e) => setFormData(prev => ({ ...prev, endpointUrl: e.target.value }))} className="w-full bg-gray-50 dark:bg-gray-900 border border-gray-300 dark:border-gray-700 rounded-lg px-4 py-2 text-gray-900 dark:text-white outline-none focus:border-blue-500" placeholder="https://api.example.com/search" />
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">API Key {formData.providerType === 'CustomEnterprise' && '(Optional)'}</label>
              <div className="relative">
                <input type={showApiKey ? 'text' : 'password'} value={formData.apiKey} onChange={(e) => setFormData(prev => ({ ...prev, apiKey: e.target.value }))} className="w-full bg-gray-50 dark:bg-gray-900 border border-gray-300 dark:border-gray-700 rounded-lg px-4 py-2 text-gray-900 dark:text-white outline-none focus:border-blue-500 pr-10" aria-label="API Key" title="API Key" placeholder="Enter API Key" />
                <button type="button" onClick={() => setShowApiKey(v => !v)} className="absolute right-3 top-1/2 -translate-y-1/2 text-gray-400 hover:text-gray-600 dark:hover:text-gray-300 transition-colors">
                  {showApiKey ? <EyeOff size={18} /> : <Eye size={18} />}
                </button>
              </div>
              <p className="text-xs text-gray-500 dark:text-gray-400 mt-1">Stored locally securely in IndexedDB.</p>
            </div>

            {formData.providerType === 'CustomEnterprise' && (
              <div>
                <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-1">Model Name</label>
                <input type="text" value={formData.modelName} onChange={(e) => setFormData(prev => ({ ...prev, modelName: e.target.value }))} className="w-full bg-gray-50 dark:bg-gray-900 border border-gray-300 dark:border-gray-700 rounded-lg px-4 py-2 text-gray-900 dark:text-white outline-none focus:border-blue-500" placeholder="e.g., llama3" />
                <p className="text-xs text-gray-500 dark:text-gray-400 mt-1">The exact model name expected by the OpenAI-compatible endpoint.</p>
              </div>
            )}

            <div className="flex items-center gap-2">
              <input type="checkbox" checked={formData.isDefault} onChange={(e) => setFormData(prev => ({ ...prev, isDefault: e.target.checked }))} id="defaultProvider" className="rounded" />
              <label htmlFor="defaultProvider" className="text-sm text-gray-700 dark:text-gray-300">Set as default provider</label>
            </div>

            <div className="flex justify-end gap-3 pt-4">
              <button type="button" onClick={() => { setFormMode(null); resetForm(); }} className="px-4 py-2 text-gray-600 dark:text-gray-400 hover:text-gray-900 dark:hover:text-white transition-colors">Cancel</button>
              <button type="submit" className="flex items-center gap-2 px-4 py-2 bg-blue-600 hover:bg-blue-700 text-white rounded-lg"> <Save size={16} /> {formMode === 'add' ? 'Add Provider' : 'Update Provider'}</button>
            </div>
          </form>
        </div>
      )}

      {!formMode && (
        <div className="bg-white dark:bg-gray-800 border border-gray-200 dark:border-gray-700 rounded-xl overflow-hidden mb-6">
          <div className="p-6 border-b border-gray-200 dark:border-gray-700 flex justify-between items-center">
            <h4 className="font-medium text-gray-900 dark:text-white">Configured Providers</h4>
            <button onClick={handleAddProvider} className="flex items-center gap-2 px-3 py-1.5 bg-blue-600 hover:bg-blue-700 text-white rounded-lg text-sm"><Plus size={16} /> Add Provider</button>
          </div>

          {providers.length === 0 ? (
            <div className="p-6 text-center text-gray-500 dark:text-gray-400">No providers configured. Add your first provider.</div>
          ) : (
            <div className="overflow-x-auto">
              <table className="w-full text-left text-sm">
                <thead className="bg-gray-50 dark:bg-gray-800/50 border-b border-gray-200 dark:border-gray-700">
                  <tr>
                    <th className="px-6 py-3 font-medium text-gray-700 dark:text-gray-300">Display Name</th>
                    <th className="px-6 py-3 font-medium text-gray-700 dark:text-gray-300">Type</th>
                    <th className="px-6 py-3 font-medium text-gray-700 dark:text-gray-300">Endpoint</th>
                    <th className="px-6 py-3 font-medium text-gray-700 dark:text-gray-300">Default</th>
                    <th className="px-6 py-3 font-medium text-gray-700 dark:text-gray-300">Created</th>
                    <th className="px-6 py-3 text-right font-medium text-gray-700 dark:text-gray-300">Actions</th>
                  </tr>
                </thead>
                <tbody>
                  {providers.map(provider => (
                    <tr key={provider.id} className="border-b border-gray-100 dark:border-gray-800/50 hover:bg-gray-50 dark:hover:bg-gray-800/30">
                      <td className="px-6 py-4 font-medium text-gray-900 dark:text-gray-200">{provider.displayName}</td>
                      <td className="px-6 py-4 text-gray-600 dark:text-gray-400">{provider.providerType}</td>
                      <td className="px-6 py-4 text-gray-600 dark:text-gray-400 text-xs truncate max-w-xs">{provider.endpointUrl}</td>
                      <td className="px-6 py-4">{provider.isDefault ? <span className="inline-block px-2 py-1 bg-blue-100 dark:bg-blue-900/30 text-blue-700 dark:text-blue-400 rounded text-xs">Default</span> : <button onClick={() => provider.id && handleSetDefault(provider.id)} className="text-xs text-gray-500 dark:text-gray-400 hover:text-blue-600 dark:hover:text-blue-400">Set default</button>}</td>
                      <td className="px-6 py-4 text-gray-600 dark:text-gray-400">{new Date(provider.createdAt).toLocaleDateString()}</td>
                      <td className="px-6 py-4 text-right">
                        <button onClick={() => handleEditProvider(provider)} className="p-1.5 text-gray-400 hover:text-blue-600 dark:hover:text-blue-400" aria-label="Edit Provider" title="Edit Provider"><Edit size={16} /></button>
                        <button onClick={() => setItemToDelete(provider.id || null)} className="p-1.5 text-gray-400 hover:text-red-600 dark:hover:text-red-400" aria-label="Delete Provider" title="Delete Provider"><Trash2 size={16} /></button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </div>
      )}

      {saveMessage && (
        <div className={`fixed bottom-6 right-6 px-4 py-3 rounded-lg text-sm font-medium ${
          saveMessage.type === 'success' ? 'bg-green-100 dark:bg-green-900/20 text-green-700 dark:text-green-400 border border-green-200 dark:border-green-800' : 'bg-red-100 dark:bg-red-900/20 text-red-700 dark:text-red-400 border border-red-200 dark:border-red-800'
        }`}>
          {saveMessage.text}
        </div>
      )}

      <ConfirmModal isOpen={!!itemToDelete} title="Delete Provider" message="Are you sure you want to delete this provider? This action cannot be undone." onConfirm={handleDeleteProvider} onCancel={() => setItemToDelete(null)} />
    </div>
  );
}

import React, { useState, useCallback, useEffect } from 'react';
import { db } from '../../lib/db';
import { Download, Upload, Loader2, History, Search, Calendar, BrainCircuit, AlertTriangle, Trash2, FolderOutput, RefreshCw } from 'lucide-react';
import { requestDirectoryPermission } from '../../lib/fileSystemPermissions';
import { useLiveQuery } from 'dexie-react-hooks';
import PageHeader from '../ui/PageHeader';
import { useStateContext } from '../../context/StateContext';
import { logoutUser } from '../../lib/authEngine';
import { useLocalBackupState } from '../../hooks/useLocalBackupState';

export default function SystemTab() {
  const { identity, setIdentity } = useStateContext();
  const [isExporting, setIsExporting] = useState(false);
  const [exportToast, setExportToast] = useState<string | null>(null);
  const [isImporting, setIsImporting] = useState(false);
  const [importError, setImportError] = useState<string | null>(null);

  // ── Local Backup State ─────────────────────────────────────────────
  const [syncToast, setSyncToast] = useState<string | null>(null);
  const [backupError, setBackupError] = useState<string | null>(null);
  const [isRestoringPermission, setIsRestoringPermission] = useState(false);

  const { isConfigured, backupPath, backupDirectoryHandle, isPermissionSuspended } = useLocalBackupState();

  // ── Listen for Consent Modal Events ────────────────────────────────
  useEffect(() => {
    const handleConsentAccepted = async () => {
      try {
        if ('showDirectoryPicker' in window) {
          const handle = await (window as any).showDirectoryPicker({ mode: 'readwrite' });
          
          // Store handle and metadata
          await db.app_settings.put({ key: 'backupDirectoryHandle', value: handle });
          await db.app_settings.put({ key: 'backupConfigured', value: true });
          await db.app_settings.put({ key: 'backupPath', value: handle.name });
          await db.app_settings.put({ key: 'backupStatus', value: 'active' });
          
          setBackupError(null);
        } else {
          setBackupError("Your browser does not support the File System Access API.");
        }
      } catch (err) {
        if (err instanceof Error && err.name === 'AbortError') {
          setBackupError(null);
          return;
        }
        console.error("Failed to select directory:", err);
        setBackupError("Persistent file system access is blocked in this preview environment. Please open the app in a standalone browser tab.");
      }
    };

    const handleConsentRejected = () => {
      setBackupError(null);
    };

    const handleRevokeSuccess = () => {
      setBackupError(null);
      // Clear any other local state that might interfere with UI rendering
      setSyncToast(null);
    };

    window.addEventListener('EA_BACKUP_CONSENT_ACCEPTED', handleConsentAccepted);
    window.addEventListener('EA_BACKUP_CONSENT_REJECTED', handleConsentRejected);
    window.addEventListener('EA_BACKUP_REVOKE_SUCCESS', handleRevokeSuccess);

    return () => {
      window.removeEventListener('EA_BACKUP_CONSENT_ACCEPTED', handleConsentAccepted);
      window.removeEventListener('EA_BACKUP_CONSENT_REJECTED', handleConsentRejected);
      window.removeEventListener('EA_BACKUP_REVOKE_SUCCESS', handleRevokeSuccess);
    };
  }, []);

  const handleConfigureBackup = async () => {
    setBackupError(null);
    try {
      if ('showDirectoryPicker' in window) {
        // Check if consent already exists
        const existingConsent = await db.app_settings.get('autoDumpConsent');
        
        if (existingConsent?.value) {
          // ── RECONFIGURE FLOW: Consent already given, skip modal ──
          try {
            const handle = await (window as any).showDirectoryPicker({ mode: 'readwrite' });
            
            // Store handle and metadata directly
            await db.app_settings.put({ key: 'backupDirectoryHandle', value: handle });
            await db.app_settings.put({ key: 'backupPath', value: handle.name });
            await db.app_settings.put({ key: 'backupStatus', value: 'active' });
            
            await db.audit_logs.add({
              timestamp: new Date(),
              action: 'SYSTEM_BACKUP_CONFIGURED',
              tableName: 'app_settings',
              pseudokey: (identity as any)?.pseudokey || (identity as any)?.username || 'SYSTEM',
              details: JSON.stringify({ path: handle.name, mode: 'reconfigure' })
            });
            
            setBackupError(null);
          } catch (err) {
            if (err instanceof Error && err.name === 'AbortError') {
              setBackupError(null);
              return;
            }
            console.error("Failed to select directory:", err);
            setBackupError("Persistent file system access is blocked in this preview environment. Please open the app in a standalone browser tab.");
          }
        } else {
          // ── INITIAL SETUP FLOW: No consent yet, show consent modal ──
          window.dispatchEvent(new CustomEvent('EA_BACKUP_CONSENT_REQUIRED', {
            detail: {
              mode: 'initial',
              backupPath: backupPath || '',
              existingConsent: false
            }
          }));
        }
      } else {
        setBackupError("Your browser does not support the File System Access API.");
      }
    } catch (err) {
      if (err instanceof Error && err.name === 'AbortError') return;
      console.error("Failed to configure backup:", err);
      setBackupError("Backup configuration failed. Please try again.");
    }
  };

  const handleRemoveConfiguration = async () => {
    setBackupError(null);
    try {
      // Dispatch revoke consent event (BackupConsentModal will intercept)
      window.dispatchEvent(new CustomEvent('EA_BACKUP_CONSENT_REQUIRED', {
        detail: {
          mode: 'revoke',
          backupPath: backupPath || '',
          existingConsent: true
        }
      }));
    } catch (err) {
      console.error("Failed to revoke backup configuration:", err);
      setBackupError("Failed to revoke backup configuration. Please try again.");
    }
  };

  // ── Permission Restoration Handler ────────────────────────────────
  const handleRestoreBackupAccess = async () => {
    if (!backupDirectoryHandle) {
      setBackupError("No backup directory handle available.");
      return;
    }

    setIsRestoringPermission(true);
    setBackupError(null);

    try {
      // requestPermission() MUST be called directly from user interaction
      const granted = await requestDirectoryPermission(backupDirectoryHandle);
      
      if (granted) {
        // Update backup status to active after permission restored
        await db.app_settings.put({ key: 'backupStatus', value: 'active' });
        await db.audit_logs.add({
          timestamp: new Date(),
          action: 'SYSTEM_BACKUP_PERMISSION_RESTORED',
          tableName: 'app_settings',
          pseudokey: (identity as any)?.pseudokey || (identity as any)?.username || 'SYSTEM',
          details: JSON.stringify({ path: backupPath || '(Restored)', status: 'permission_granted' })
        });
        setSyncToast('Backup access restored successfully!');
        setTimeout(() => setSyncToast(null), 3000);
      } else {
        setBackupError('Permission request denied. Please try again or reconfigure your backup directory.');
        await db.audit_logs.add({
          timestamp: new Date(),
          action: 'SYSTEM_BACKUP_PERMISSION_RESTORE_FAILED',
          tableName: 'app_settings',
          pseudokey: (identity as any)?.pseudokey || (identity as any)?.username || 'SYSTEM',
          details: JSON.stringify({ path: backupPath || '(Unknown)', status: 'permission_denied' })
        });
      }
    } catch (err) {
      console.error('Failed to restore backup access:', err);
      setBackupError('Failed to restore backup access. Please try again.');
      await db.audit_logs.add({
        timestamp: new Date(),
        action: 'SYSTEM_BACKUP_PERMISSION_ERROR',
        tableName: 'app_settings',
        pseudokey: (identity as any)?.pseudokey || (identity as any)?.username || 'SYSTEM',
        details: JSON.stringify({ path: backupPath || '(Error)', error: err instanceof Error ? err.message : 'Unknown error' })
      });
    } finally {
      setIsRestoringPermission(false);
    }
  };

  // ── Global Wipe State ──────────────────────────────────────────────
  const [showWipeModal, setShowWipeModal] = useState(false);
  const [confirmInput, setConfirmInput] = useState('');
  const [isWiping, setIsWiping] = useState(false);
  const [wipeError, setWipeError] = useState('');

  const WIPE_CONFIRMATION_PHRASE = 'DELETE';
  const isConfirmValid = confirmInput === WIPE_CONFIRMATION_PHRASE;

  // ── Global Wipe Handler ────────────────────────────────────────────
  const handleGlobalWipe = useCallback(async () => {
    if (!isConfirmValid) return;
    setIsWiping(true);
    setWipeError('');

    try {
      const tables = db.tables;
      await db.transaction('rw', tables, async () => {
        for (const table of tables) {
          await table.clear();
        }
      });

      sessionStorage.clear();
      localStorage.clear();

      try {
        const cacheNames = await caches.keys();
        await Promise.all(cacheNames.map(name => caches.delete(name)));
      } catch (cacheErr) {
        console.warn('[SystemTab] CacheStorage wipe partial:', cacheErr);
      }

      logoutUser();
      setIdentity(null);
    } catch (err) {
      console.error('[SystemTab] Global Data Wipe failed:', err);
      setWipeError(err instanceof Error ? err.message : 'Wipe failed. Check console for details.');
      setIsWiping(false);
    }
  }, [isConfirmValid, setIdentity]);



  const handleCloseWipeModal = () => {
    setShowWipeModal(false);
    setConfirmInput('');
    setWipeError('');
  };

  // Fetch sync history from audit_logs table
  const syncLogs = useLiveQuery(() => 
    db.audit_logs
      .where('tableName')
      .equals('system_portability')
      .reverse()
      .toArray()
  ) || [];

  const [searchQuery, setSearchQuery] = useState('');
  const [startDate, setStartDate] = useState('');
  const [endDate, setEndDate] = useState('');

  const filteredLogs = syncLogs.filter(log => {
      let parsedDetails = { event: 'UNKNOWN', status: 'UNKNOWN' };
      try {
        if (log.details) parsedDetails = JSON.parse(log.details);
      } catch (e) {
        // Ignore parse error
      }

      const q = searchQuery.toLowerCase();
      const timestamp = new Date(log.timestamp).toLocaleString().toLowerCase();
      const action = parsedDetails.event.toLowerCase();
      const status = parsedDetails.status.toLowerCase();
      const alias = log.pseudokey.toLowerCase();

      const matchesSearch = timestamp.includes(q) || 
                            action.includes(q) || 
                            status.includes(q) || 
                            alias.includes(q);
      
      if (!matchesSearch) return false;

      const logDate = new Date(log.timestamp);
      if (startDate && logDate < new Date(startDate)) return false;
      if (endDate) {
        const end = new Date(endDate);
        end.setHours(23, 59, 59, 999);
        if (logDate > end) return false;
      }
      
      return true;
  });

  const handleExportCSV = () => {
    const headers = ['Timestamp,Action,Status,User Alias'];
    const rows = filteredLogs.map(log => {
      let parsedDetails = { event: 'UNKNOWN', status: 'UNKNOWN' };
      try {
        if (log.details) parsedDetails = JSON.parse(log.details);
      } catch (e) {
        // Ignore parse error
      }
      return `"${new Date(log.timestamp).toISOString()}","${parsedDetails.event}","${parsedDetails.status}","${log.pseudokey}"`;
    });
    
    const csvContent = headers.concat(rows).join('\n');
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.setAttribute('download', 'niti_portability_sync_log.csv');
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  };

  const handleExportBrain = async () => {
    setIsExporting(true);
    try {
      const BLACKLIST_PATTERNS = ['vector', 'embedding', 'session', 'history', 'cache', 'audit', 'logs'];
      
      const tablesToExport = db.tables.filter(table => {
        const name = table.name.toLowerCase();
        return !BLACKLIST_PATTERNS.some(pattern => name.includes(pattern));
      });

      setExportToast(`Discovery Complete: Exporting ${tablesToExport.length} Master Data Tables...`);
      
      const dump: Record<string, any[]> = {};
      await Promise.all(
        tablesToExport.map(async (table) => {
          dump[table.name] = await table.toArray();
        })
      );
      
      const blob = new Blob([JSON.stringify(dump, null, 2)], { type: 'application/json' });
      const url = URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `niti_brain_export_${new Date().toISOString().split('T')[0]}.json`;
      a.click();
      URL.revokeObjectURL(url);

      await db.audit_logs.add({
        timestamp: new Date(),
        pseudokey: identity?.username || 'Unknown User',
        action: 'UPDATE',
        tableName: 'system_portability',
        details: JSON.stringify({ event: 'EXPORT_BRAIN', status: 'Success' })
      });
      
      setTimeout(() => setExportToast(null), 3000);
    } catch (e) {
      await db.audit_logs.add({
        timestamp: new Date(),
        pseudokey: identity?.username || 'Unknown User',
        action: 'UPDATE',
        tableName: 'system_portability',
        details: JSON.stringify({ event: 'EXPORT_BRAIN', status: 'Failed' })
      });
      alert("Failed to export database: " + e);
      setExportToast(null);
    } finally {
      setIsExporting(false);
    }
  };

  const handleImportBrain = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    if (!confirm("WARNING: Importing a NITI Brain state will overwrite duplicate keys. Continue?")) {
        event.target.value = '';
        return;
    }

    setIsImporting(true);
    setImportError(null);
    const reader = new FileReader();
    reader.onload = async (e) => {
      try {
        const text = e.target?.result as string;
        
        let dump;
        try {
          dump = JSON.parse(text);
        } catch {
          throw new Error('Invalid NITI Brain Payload: File is not a valid JSON document.');
        }
        
        // Strict Schema Validation
        if (!dump || typeof dump !== 'object') {
          throw new Error('Invalid NITI Brain Payload: Root element is not a JSON object.');
        }

        const requiredTopLevelKeys = [
          'architecture_categories',
          'master_categories',
          'content_metamodel',
          'architecture_layers',
          'architecture_principles',
          'service_domains'
        ];

        // Ensure at least one known architectural array exists in the payload, preventing random JSON uploads
        const hasAnyValidKey = requiredTopLevelKeys.some(key => Array.isArray(dump[key]));
        if (!hasAnyValidKey) {
            throw new Error('Invalid NITI Brain Payload: Missing core architectural entities (e.g., principles, layers).');
        }
        
        await db.transaction('rw', 
          [db.architecture_categories, db.master_categories, db.content_metamodel,
          db.architecture_layers, db.architecture_principles, db.service_domains,
          db.bespoke_tags, db.prompt_templates, db.report_templates,
          db.review_workflows, db.app_settings, db.threat_models], 
        async () => {
          if (dump.architecture_categories) await db.architecture_categories.bulkPut(dump.architecture_categories);
          if (dump.master_categories) await db.master_categories.bulkPut(dump.master_categories);
          if (dump.content_metamodel) await db.content_metamodel.bulkPut(dump.content_metamodel);
          if (dump.architecture_layers) await db.architecture_layers.bulkPut(dump.architecture_layers);
          if (dump.architecture_principles) await db.architecture_principles.bulkPut(dump.architecture_principles);
          if (dump.service_domains) await db.service_domains.bulkPut(dump.service_domains);
          if (dump.bian_domains) await db.service_domains.bulkPut(dump.bian_domains); // Fallback for old exports
          if (dump.bespoke_tags) await db.bespoke_tags.bulkPut(dump.bespoke_tags);
          if (dump.prompt_templates) await db.prompt_templates.bulkPut(dump.prompt_templates);
          if (dump.report_templates) await db.report_templates.bulkPut(dump.report_templates);
          if (dump.review_workflows) await db.review_workflows.bulkPut(dump.review_workflows);
          if (dump.app_settings) await db.app_settings.bulkPut(dump.app_settings);
          if (dump.threat_models) await db.threat_models.bulkPut(dump.threat_models);
        });
        
        await db.audit_logs.add({
          timestamp: new Date(),
          pseudokey: identity?.username || 'Unknown User',
          action: 'UPDATE',
          tableName: 'system_portability',
          details: JSON.stringify({ event: 'IMPORT_MERGE', status: 'Success' })
        });

        alert("NITI Brain state successfully restored! The agent interface will reload to apply changes.");
        window.location.reload();
      } catch (err: any) {
        setImportError(err.message || 'Validation failed');
        await db.audit_logs.add({
          timestamp: new Date(),
          pseudokey: identity?.username || 'Unknown User',
          action: 'UPDATE',
          tableName: 'system_portability',
          details: JSON.stringify({ event: 'IMPORT_MERGE', status: 'Failed' })
        });
      } finally {
        setIsImporting(false);
      }
    };
    reader.readAsText(file);
  };

  return (
    <div className="space-y-8 max-w-4xl">
      <PageHeader 
        icon={<BrainCircuit className="text-indigo-500" />}
        title="State Portability (NITI Brain Transfer)"
        description="Export your agent's entirely localized knowledge base (Categories, Domains, Taxonomies, Templates, Workflow Pipelines, Principles) into a raw JSON struct. Use this to seed new NITI installations without re-training standard metadata manually."
      />

      <div className="bg-gradient-to-br from-indigo-50 to-blue-50 dark:from-indigo-900/20 dark:to-blue-900/20 rounded-xl border border-indigo-200 dark:border-indigo-800/50 p-6">
         <div className="flex gap-4 items-center mb-4">
            <button 
               onClick={handleExportBrain}
               disabled={isExporting}
               className="flex items-center gap-2 px-5 py-2.5 bg-indigo-600 hover:bg-indigo-700 text-white rounded-lg font-medium transition-colors shadow-md disabled:opacity-50"
            >
               {isExporting ? <Loader2 size={18} className="animate-spin" /> : <Download size={18} />}
               Export Knowledge Base
            </button>
            <div className="relative">
               <input 
                  type="file" 
                  accept=".json"
                  className="absolute inset-0 w-full h-full opacity-0 cursor-pointer"
                  onChange={handleImportBrain}
                  disabled={isImporting}
                  id="import-upload"
                  aria-label="Import upload"
                  title="Import upload"
               />
               <button 
                  className={`flex items-center gap-2 px-5 py-2.5 bg-white dark:bg-gray-800 border-2 border-indigo-200 dark:border-indigo-700 hover:border-indigo-500 dark:hover:border-indigo-400 text-indigo-700 dark:text-indigo-300 rounded-lg font-medium transition-colors ${isImporting ? 'opacity-50' : ''}`}
               >
                  {isImporting ? <Loader2 size={18} className="animate-spin" /> : <Upload size={18} />}
                  Import & Merge State
               </button>
            </div>
         </div>

         {/* Localized Error Banner for Validation */}
         {importError && (
            <div className="mt-4 p-3 bg-red-100 dark:bg-red-900/20 border border-red-200 dark:border-red-800/50 rounded-lg">
                <p className="text-sm text-red-700 dark:text-red-400 font-medium">Import Aborted</p>
                <p className="text-xs text-red-600 dark:text-red-300 mt-1">{importError}</p>
            </div>
         )}

         {/* Export Telemetry Toast */}
         {exportToast && (
            <div className="mt-4 p-3 bg-green-100 dark:bg-green-900/20 border border-green-200 dark:border-green-800/50 rounded-lg">
                <p className="text-sm text-green-700 dark:text-green-400 font-medium">{exportToast}</p>
            </div>
         )}
      </div>

      {/* ─── Task 1: Knowledge Sync History Table ─── */}
      <div className="bg-white dark:bg-gray-800/50 rounded-xl border border-gray-200 dark:border-gray-700 shadow-sm overflow-hidden">
        <div className="p-5 border-b border-gray-200 dark:border-gray-700 bg-gray-50 dark:bg-gray-800/80">
          <h3 className="text-sm font-semibold text-gray-800 dark:text-gray-200 flex items-center gap-2 mb-4">
            <History size={16} className="text-gray-500" />
            Knowledge Sync & Portability History
          </h3>
          <div className="flex flex-wrap items-center justify-between gap-4 mb-4">
            <div className="flex flex-wrap items-center gap-3">
               <div className="relative">
                 <Search size={14} className="absolute left-2.5 top-2 text-gray-400" />
                 <input 
                   type="text" 
                   value={searchQuery}
                   onChange={e => setSearchQuery(e.target.value)}
                   placeholder="Search logs..." 
                   className="pl-8 pr-3 py-1.5 text-xs bg-white dark:bg-gray-900 border border-gray-300 dark:border-gray-600 rounded-md focus:border-indigo-500 outline-none w-48 text-gray-800 dark:text-gray-200"
                 />
               </div>
               <div className="flex items-center gap-2 relative">
                 <Calendar size={14} className="absolute left-2.5 top-2 text-gray-400" />
                 <input 
                   type="date"
                   value={startDate}
                   onChange={e => setStartDate(e.target.value)}
                   className="pl-8 pr-2 py-1.5 text-xs bg-white dark:bg-gray-900 border border-gray-300 dark:border-gray-600 rounded-md outline-none text-gray-800 dark:text-gray-200"
                   aria-label="Start date"
                   title="Start date"
                   placeholder="Start date"
                 />
                 <span className="text-gray-400 text-xs">-</span>
                 <input 
                   type="date"
                   value={endDate}
                   onChange={e => setEndDate(e.target.value)}
                   className="px-2 py-1.5 text-xs bg-white dark:bg-gray-900 border border-gray-300 dark:border-gray-600 rounded-md outline-none text-gray-800 dark:text-gray-200"
                   aria-label="End date"
                   title="End date"
                   placeholder="End date"
                 />
               </div>
            </div>
            <button 
               onClick={handleExportCSV}
               className="flex items-center gap-2 px-3 py-1.5 bg-gray-200 hover:bg-gray-300 dark:bg-gray-700 dark:hover:bg-gray-600 text-gray-700 dark:text-gray-300 rounded-md text-xs font-semibold transition-colors shadow-sm ml-auto"
            >
              <Download size={14} />
              Export CSV
            </button>
          </div>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-left text-sm">
            <thead className="bg-gray-100 dark:bg-gray-900/50">
              <tr>
                <th className="px-5 py-3 font-medium text-gray-500 dark:text-gray-400">Timestamp</th>
                <th className="px-5 py-3 font-medium text-gray-500 dark:text-gray-400">Action</th>
                <th className="px-5 py-3 font-medium text-gray-500 dark:text-gray-400">Status</th>
                <th className="px-5 py-3 font-medium text-gray-500 dark:text-gray-400">User Alias</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-200 dark:divide-gray-700">
              {filteredLogs.length > 0 ? (
                filteredLogs.map(log => {
                  let parsedDetails = { event: 'UNKNOWN', status: 'UNKNOWN' };
                  try {
                    if (log.details) parsedDetails = JSON.parse(log.details);
                  } catch (e) {
                    // Ignore parse error
                  }

                  return (
                    <tr key={log.id} className="hover:bg-gray-50 dark:hover:bg-gray-800/30">
                      <td className="px-5 py-3 text-gray-500 dark:text-gray-400">{new Date(log.timestamp).toLocaleString()}</td>
                      <td className="px-5 py-3 font-medium text-gray-900 dark:text-gray-200">{parsedDetails.event}</td>
                      <td className="px-5 py-3">
                        <span className={`inline-flex px-2 py-0.5 rounded text-[10px] font-bold uppercase ${
                          parsedDetails.status === 'Success' 
                            ? 'bg-green-100 text-green-700 dark:bg-green-900/30 dark:text-green-400' 
                            : 'bg-red-100 text-red-700 dark:bg-red-900/30 dark:text-red-400'
                        }`}>
                          {parsedDetails.status}
                        </span>
                      </td>
                      <td className="px-5 py-3 font-mono text-gray-600 dark:text-gray-400">{log.pseudokey}</td>
                    </tr>
                  );
                })
              ) : (
                <tr>
                  <td colSpan={4} className="px-5 py-12 text-center text-gray-500 dark:text-gray-400">
                    <History className="w-8 h-8 text-gray-400 mb-2 mx-auto" />
                    No portability sync history recorded locally.
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
        <div className="px-5 py-3 border-t border-gray-200 dark:border-gray-700 bg-gray-50 dark:bg-gray-800/50 flex items-center justify-between">
          <span className="text-xs text-gray-500 dark:text-gray-400">Page 1 of 1</span>
          <div className="flex gap-2">
            <button disabled className="px-3 py-1 text-xs font-medium text-gray-500 bg-white dark:bg-gray-900 border border-gray-300 dark:border-gray-600 rounded-md opacity-50 cursor-not-allowed">Previous</button>
            <button disabled className="px-3 py-1 text-xs font-medium text-gray-500 bg-white dark:bg-gray-900 border border-gray-300 dark:border-gray-600 rounded-md opacity-50 cursor-not-allowed">Next</button>
          </div>
        </div>
      </div>

      {/* ── Continuous Local Backup ─────────────────────────────────── */}
      <div className="bg-white dark:bg-gray-800/50 rounded-xl border border-gray-200 dark:border-gray-700 p-6 shadow-sm">
        <h3 className="text-sm font-semibold text-gray-800 dark:text-gray-200 mb-2 flex items-center gap-2">
          <FolderOutput size={18} className="text-blue-500" />
          Continuous Local Backup
        </h3>
        <p className="text-sm text-gray-600 dark:text-gray-400 mb-4">
          Map a local OS directory to dump database records directly to your hard drive before purging them from the browser to prevent IndexedDB quota limits.
        </p>
        
        {isConfigured ? (
          isPermissionSuspended ? (
            // Permission Suspended State
            <div className="bg-orange-50 dark:bg-orange-900/20 border border-orange-200 dark:border-orange-800/50 rounded-lg p-4 mb-4">
              <div className="flex items-start gap-3 mb-3">
                <AlertTriangle size={16} className="text-orange-600 dark:text-orange-400 shrink-0 mt-0.5" />
                <div>
                  <h4 className="text-sm font-medium text-orange-800 dark:text-orange-200">Backup Access Suspended</h4>
                  <p className="text-xs text-orange-700 dark:text-orange-300 mt-1">
                    Your permission to access the backup directory was revoked (likely after browser restart). Restore access to resume automatic backups.
                  </p>
                </div>
              </div>
              <p className="text-xs text-orange-700 dark:text-orange-300 mb-3 font-mono">
                Path: {backupPath}
              </p>
              <div className="flex gap-3">
                <button
                  onClick={handleRestoreBackupAccess}
                  disabled={isRestoringPermission}
                  className="px-3 py-1.5 bg-orange-600 hover:bg-orange-700 disabled:opacity-50 text-white rounded-lg text-xs font-medium transition-colors flex items-center gap-2"
                >
                  <RefreshCw size={14} className={isRestoringPermission ? 'animate-spin' : ''} />
                  {isRestoringPermission ? 'Restoring...' : 'Restore Backup Access'}
                </button>
                <button
                  onClick={handleRemoveConfiguration}
                  className="px-3 py-1.5 bg-red-600 hover:bg-red-700 text-white rounded-lg text-xs font-medium transition-colors"
                >
                  Remove Configuration
                </button>
              </div>
            </div>
          ) : (
            // Active Configuration State
            <div className="bg-green-50 dark:bg-green-900/20 border border-green-200 dark:border-green-800/50 rounded-lg p-4 mb-4">
              <h4 className="text-sm font-medium text-green-800 dark:text-green-200 mb-2">Current Configuration</h4>
              <p className="text-sm text-green-700 dark:text-green-300 mb-3">
                Active Path: {backupPath}
              </p>
              <div className="flex gap-3">
                <button
                  onClick={handleConfigureBackup}
                  className="px-3 py-1.5 bg-blue-600 hover:bg-blue-700 text-white rounded-lg text-xs font-medium transition-colors"
                >
                  Edit / Reconfigure
                </button>
                <button
                  onClick={handleRemoveConfiguration}
                  className="px-3 py-1.5 bg-red-600 hover:bg-red-700 text-white rounded-lg text-xs font-medium transition-colors"
                >
                  Remove Configuration
                </button>
              </div>
            </div>
          )
        ) : (
          <div className="flex flex-col sm:flex-row items-start sm:items-center gap-4">
            <button
              onClick={handleConfigureBackup}
              className="px-4 py-2 bg-gray-100 hover:bg-gray-200 dark:bg-gray-700 dark:hover:bg-gray-600 text-gray-800 dark:text-gray-200 rounded-lg text-sm font-medium transition-colors flex items-center gap-2 border border-gray-300 dark:border-gray-600"
            >
              <FolderOutput size={16} />
              Configure Backup Folder
            </button>
          </div>
        )}

        {backupError && (
          <div className="mt-3 text-red-500 dark:text-red-400 text-sm font-medium flex items-center gap-2">
            <AlertTriangle size={14} />
            {backupError}
          </div>
        )}

        {syncToast && (
          <div className="mt-4 p-3 bg-green-100 dark:bg-green-900/20 border border-green-200 dark:border-green-800/50 rounded-lg">
            <p className="text-sm text-green-700 dark:text-green-400 font-medium">{syncToast}</p>
          </div>
        )}
      </div>

      {/* ── Danger Zone ─────────────────────────────────────────────── */}
      <div className="bg-red-50 dark:bg-red-900/10 border border-red-200 dark:border-red-800 rounded-xl p-6">
        <div className="flex items-start gap-3">
          <AlertTriangle size={20} className="text-red-500 shrink-0 mt-0.5" />
          <div>
            <h3 className="text-sm font-bold text-red-800 dark:text-red-400 mb-1">Danger Zone — Global Data Wipe</h3>
            <p className="text-sm text-red-700 dark:text-red-500/80 mb-4">
              Irreversibly destroy <strong>all</strong> local data: IndexedDB tables, cached AI model weights (OPFS/CacheStorage), session tokens, and local preferences.
            </p>
            <button
              id="global-data-wipe-trigger"
              onClick={() => setShowWipeModal(true)}
              className="px-4 py-2 bg-red-600 hover:bg-red-700 text-white rounded-lg text-sm font-medium transition-colors flex items-center gap-2"
            >
              <Trash2 size={14} />
              Initiate Global Data Wipe
            </button>
          </div>
        </div>
      </div>

      {/* ── Wipe Confirmation Modal ────────────────────────────────── */}
      {showWipeModal && (
        <div className="fixed inset-0 bg-black/60 flex items-center justify-center z-[60]" onClick={handleCloseWipeModal}>
          <div className="bg-white dark:bg-gray-900 border border-red-300 dark:border-red-800 rounded-xl p-6 w-[95%] max-w-md mx-4 shadow-2xl" onClick={e => e.stopPropagation()}>
            <div className="flex items-center gap-3 mb-4">
              <div className="w-10 h-10 rounded-full bg-red-100 dark:bg-red-900/30 flex items-center justify-center shrink-0">
                <AlertTriangle size={20} className="text-red-600 dark:text-red-400" />
              </div>
              <div>
                <h3 className="text-lg font-bold text-gray-900 dark:text-white">Confirm Global Data Wipe</h3>
                <p className="text-xs text-red-600 dark:text-red-400 font-medium">This action is permanent and irreversible.</p>
              </div>
            </div>

            <p className="text-sm text-gray-600 dark:text-gray-400 mb-4">This will destroy all data stored by EA-NITI in this browser:</p>
            <ul className="text-xs text-gray-500 dark:text-gray-500 mb-5 space-y-1 list-disc pl-4">
              <li>All IndexedDB tables (reviews, principles, domains, threat models, guardrails…)</li>
              <li>Cached AI model weights (OPFS / CacheStorage)</li>
              <li>Session tokens, preferences, and audit logs</li>
              <li>Enterprise knowledge embeddings</li>
            </ul>

            <label className="block text-sm font-medium text-gray-700 dark:text-gray-300 mb-2">
              Type <code className="px-1.5 py-0.5 bg-red-100 dark:bg-red-900/30 text-red-700 dark:text-red-400 rounded text-xs font-bold">DELETE</code> to confirm:
            </label>
            <input
              id="global-wipe-confirm-input"
              type="text"
              value={confirmInput}
              onChange={e => setConfirmInput(e.target.value)}
              placeholder="Type DELETE here"
              autoFocus
              autoComplete="off"
              className="w-full px-3 py-2 rounded-lg border border-gray-300 dark:border-gray-600 bg-white dark:bg-gray-800 text-gray-900 dark:text-white text-sm focus:ring-2 focus:ring-red-500 focus:border-red-500 outline-none mb-2"
            />

            {wipeError && <p className="text-xs text-red-600 dark:text-red-400 mb-3">{wipeError}</p>}

            <div className="flex justify-end gap-3 mt-4">
              <button onClick={handleCloseWipeModal} disabled={isWiping} className="px-4 py-2 text-gray-500 dark:text-gray-400 hover:text-gray-900 dark:hover:text-white transition-colors text-sm">Cancel</button>
              <button
                id="global-wipe-execute-btn"
                onClick={handleGlobalWipe}
                disabled={!isConfirmValid || isWiping}
                className="px-4 py-2 bg-red-600 hover:bg-red-700 disabled:opacity-40 disabled:cursor-not-allowed text-white rounded-lg text-sm font-medium transition-colors flex items-center gap-2"
              >
                {isWiping ? (
                  <>
                    <span className="inline-block w-3.5 h-3.5 border-2 border-white border-t-transparent rounded-full animate-spin" />
                    Wiping…
                  </>
                ) : (
                  <>
                    <Trash2 size={14} />
                    Wipe All Data
                  </>
                )}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

import React, { useRef, useState } from 'react'; // React needed for React.ChangeEvent
import { useLiveQuery } from 'dexie-react-hooks';
import { db } from '../../lib/db';
import { useArchive } from '../../hooks/useArchive';
import { initiateTrainingJob } from '../../lib/knowledgeIngestionEngine';
import { Database, Plus, RefreshCcw, CheckCircle2, XCircle, Clock, Loader2, Link2, Search, Calendar, Download, Trash2, FileText, Type, Archive, BookOpen } from 'lucide-react';
import PageHeader from '../ui/PageHeader';

export default function TrainingEventsTable() {
  const [isUploading, setIsUploading] = useState(false);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const jobs = useLiveQuery(() => db.training_jobs.orderBy('startedAt').reverse().toArray()) || [];
  const knowledgeChunks = useLiveQuery(() => db.enterprise_knowledge.toArray()) || [];
  const knowledgeCount = knowledgeChunks.length;

  const { archiveItem: purgeDocument } = useArchive({
    tableName: 'training_jobs',
    statusField: 'status',
    archivedValue: 'PURGED',
    activeValue: 'Completed',
    isRagEntity: true
  });

  const [isFreeTextModalOpen, setIsFreeTextModalOpen] = useState(false);
  const [freeTextName, setFreeTextName] = useState('');
  const [freeTextContent, setFreeTextContent] = useState('');

  const [showArchived, setShowArchived] = useState(false);

  const [searchQuery, setSearchQuery] = useState('');
  const [startDate, setStartDate] = useState('');
  const [endDate, setEndDate] = useState('');

  const filteredJobs = jobs.filter(job => {
      if (showArchived) {
         if (job.status !== 'PURGED') return false;
      } else {
         if (job.status === 'PURGED') return false;
      }

      const q = searchQuery.toLowerCase();
      const matchesSearch = job.filename.toLowerCase().includes(q) || 
                            job.status.toLowerCase().includes(q) ||
                            (job.logs[job.logs.length - 1] || '').toLowerCase().includes(q);

      if (!matchesSearch) return false;

      const jobDate = new Date(job.startedAt);
      if (startDate && jobDate < new Date(startDate)) return false;
      if (endDate) {
        const end = new Date(endDate);
        end.setHours(23, 59, 59, 999);
        if (jobDate > end) return false;
      }
      return true;
  });

  const handleExportCSV = () => {
    const headers = ['Timestamp,Data Source,Status,Latest Log'];
    const rows = filteredJobs.map(job => {
      const logString = (job.logs[job.logs.length - 1] || '').replace(/"/g, '""');
      return `"${new Date(job.startedAt).toISOString()}","${job.filename}","${job.status}","${logString}"`;
    });
    const csvContent = headers.concat(rows).join('\n');
    const blob = new Blob([csvContent], { type: 'text/csv;charset=utf-8;' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.setAttribute('download', 'niti_knowledge_ingestion_log.csv');
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  };

  const registryMap = new Map<string, { filename: string, type: string, chunks: number }>();
  knowledgeChunks.forEach(doc => {
      const type = doc.sourceType || 'MD'; 
      if (!registryMap.has(doc.sourceFile)) {
         registryMap.set(doc.sourceFile, { filename: doc.sourceFile, type: type, chunks: 0 });
      }
      registryMap.get(doc.sourceFile)!.chunks++;
  });

  const displayRegistryItems = showArchived 
     ? Array.from(new Set(jobs.filter(j => j.status === 'PURGED').map(j => j.filename))).map(filename => {
         const type = filename.split('.').pop()?.toUpperCase() || 'UNKNOWN';
         return { filename, type: type, chunks: 0 };
       })
     : Array.from(registryMap.values());

  const handlePurgeDocument = async (filename: string) => {
    if (!confirm(`Are you sure you want to purge all indexed chunks for "${filename}"? This will remove it from the vector database.`)) return;
    try {
        await purgeDocument(filename);
    } catch (e) {
        alert("Failed to purge document: " + e);
    }
  };

  const handleFreeTextSubmit = async () => {
    if (!freeTextName || !freeTextContent) return;
    const blob = new Blob([freeTextContent], { type: 'text/plain' });
    const file = new File([blob], `${freeTextName}.txt`, { type: 'text/plain' });

    setIsFreeTextModalOpen(false);
    setIsUploading(true);
    try {
      await initiateTrainingJob(file, () => {});
    } catch (e) {
      console.error(e);
    } finally {
      setIsUploading(false);
      setFreeTextName('');
      setFreeTextContent('');
    }
  };

  const handleFileUpload = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    // QA Audit - Strict File Extension Validation
    const ext = file.name.split('.').pop()?.toLowerCase() || '';
    if (!['pdf', 'md', 'txt', 'csv', 'docx'].includes(ext)) {
      alert("Unsupported binary format. Please convert to .docx or .csv.");
      if (fileInputRef.current) fileInputRef.current.value = '';
      return;
    }

    setIsUploading(true);
    try {
      await initiateTrainingJob(file, (_progress) => {
        // the knowledgeIngestionEngine takes care of writing to the DB
      });
    } catch (e) {
      console.error(e);
    } finally {
      setIsUploading(false);
      if (fileInputRef.current) fileInputRef.current.value = '';
    }
  };

  const getStatusIcon = (status: string) => {
    switch (status) {
      case 'Completed': return <CheckCircle2 size={16} className="text-green-500" />;
      case 'Failed': return <XCircle size={16} className="text-red-500" />;
      case 'Processing': return <Loader2 size={16} className="text-blue-500 animate-spin" />;
      case 'Pending': return <Clock size={16} className="text-gray-400" />;
      default: return null;
    }
  };

  const getStatusStyle = (status: string) => {
    switch (status) {
      case 'Completed': return 'bg-green-100 text-green-700 dark:bg-green-900/40 dark:text-green-400';
      case 'Failed': return 'bg-red-100 text-red-700 dark:bg-red-900/40 dark:text-red-400';
      case 'Processing': return 'bg-blue-100 text-blue-700 dark:bg-blue-900/40 dark:text-blue-400';
      case 'Pending': return 'bg-gray-100 text-gray-700 dark:bg-gray-800 dark:text-gray-400';
      default: return 'bg-gray-100 text-gray-700';
    }
  };

  return (
    <div className="space-y-8">
      <PageHeader 
        icon={<BookOpen className="text-indigo-500" />}
        title="Enterprise Knowledge Ingestion"
        description="Train EA-NITI on your proprietary architecture standards via Local Offline RAG."
        action={
          <div className="flex items-center gap-1 font-mono text-xs bg-indigo-100 dark:bg-indigo-900/50 text-indigo-700 dark:text-indigo-400 px-2 py-0.5 rounded-full">
            <Link2 size={12} /> {knowledgeCount} semantic chunks indexed
          </div>
        }
      />

      <div className="bg-white dark:bg-gray-900 rounded-xl border border-gray-200 dark:border-gray-800 overflow-hidden shadow-sm">
      <div className="p-6 border-b border-gray-200 dark:border-gray-800 flex justify-between items-center bg-gray-50 dark:bg-gray-800/50">
        <div>
          <h3 className="text-lg font-bold text-gray-900 dark:text-white flex items-center gap-2">
            <Database className="text-indigo-500" />
            Ingestion Controls
          </h3>
          <p className="text-sm text-gray-600 dark:text-gray-400 mt-1">
            Upload documents or paste text to seed the local vector store.
          </p>
        </div>
        <div className="text-right">
          <div className="flex items-center gap-2 mb-1 justify-end">
            <input 
              type="file" 
              ref={fileInputRef} 
              onChange={handleFileUpload} 
              accept=".pdf,.md,.txt,.csv,.docx" 
              className="hidden" 
              disabled={isUploading}
              aria-label="Upload Training File"
              title="Upload File"
            />
            <button 
              onClick={() => setIsFreeTextModalOpen(true)}
              disabled={isUploading}
              className="flex items-center gap-2 px-4 py-2 bg-gray-200 hover:bg-gray-300 dark:bg-gray-800 dark:hover:bg-gray-700 text-gray-800 dark:text-gray-200 disabled:opacity-50 rounded-lg font-medium transition-colors border border-gray-300 dark:border-gray-700"
            >
              <Type size={16} />
              Paste Free Text
            </button>
            <button 
              onClick={() => fileInputRef.current?.click()}
              disabled={isUploading}
              className="flex items-center gap-2 px-5 py-2 bg-indigo-600 hover:bg-indigo-700 disabled:opacity-50 text-white rounded-lg font-medium transition-colors shadow-md shadow-indigo-500/20"
            >
              {isUploading ? <Loader2 size={18} className="animate-spin" /> : <Plus size={18} />}
              Train EA-NITI
            </button>
          </div>
          <p className="text-[10px] text-gray-500 mr-1 mt-2 tracking-wide font-medium bg-gray-100 dark:bg-gray-800/80 inline-block px-2 py-0.5 rounded border border-gray-200 dark:border-gray-700">Supported: .PDF, .MD, .TXT, .CSV, .DOCX</p>
        </div>
      </div>

