export const db = new EADatabase();

/**
 * Prunes old chat threads to maintain storage efficiency.
 * Automatically deletes the oldest thread and its associated messages if count > 50.
 */
export async function pruneOldChats(): Promise<void> {
  try {
    const threadCount = await db.chat_threads.count();
    if (threadCount > 50) {
      const oldest = await db.chat_threads
        .orderBy('updatedAt')
        .first();

      if (oldest?.id) {
        // Delete all messages associated with oldest thread
        await db.chat_messages.where('threadId').equals(oldest.id).delete();
        // Delete the thread itself
        await db.chat_threads.delete(oldest.id);
      }
    }
  } catch (e) {
    // Silently log to avoid disrupting UI
    if (typeof window !== 'undefined') {
      // Logger not imported here to avoid circular deps
      console.warn('[pruneOldChats] Error during chat history pruning:', e);
    }
  }
}

// Setup Audit Hooks globally across all tables (excluding audit_logs itself)
db.on('ready', () => {
  db.tables.forEach(table => {
    if (table.name === 'audit_logs' || table.name === 'users' || table.name === 'privacy_guardrails') return; // Don't audit the audit or identity table loops

    table.hook('creating', function (_primKey, _obj, _transaction) {
      const pseudokey = sessionStorage.getItem('ea_niti_session') || 'SYSTEM';
      // Create separate async transaction to avoid blocking main CRUD
      Dexie.ignoreTransaction(() => {
        db.audit_logs.add({
          timestamp: new Date(),
          pseudokey,
          action: 'CREATE',
          tableName: table.name,
          details: `Created record in ${table.name}`
        });
      });
    });

    table.hook('updating', function (_modifications, primKey, _obj, _transaction) {
      const pseudokey = sessionStorage.getItem('ea_niti_session') || 'SYSTEM';
      Dexie.ignoreTransaction(() => {
        db.audit_logs.add({
          timestamp: new Date(),
          pseudokey,
          action: 'UPDATE',
          tableName: table.name,
          recordId: String(primKey),
          details: `Updated record in ${table.name}`
        });
      });
    });

    table.hook('deleting', function (primKey, _obj, _transaction) {
      const pseudokey = sessionStorage.getItem('ea_niti_session') || 'SYSTEM';
      Dexie.ignoreTransaction(() => {
        db.audit_logs.add({
          timestamp: new Date(),
          pseudokey,
          action: 'DELETE',
          tableName: table.name,
          recordId: String(primKey),
          details: `Deleted record from ${table.name}`
        });
      });
    });
  });
});

export async function logForensicAudit(
  action: 'CREATE' | 'UPDATE' | 'DELETE',
  tableName: string,
  recordId: string | number,
  previousState: Record<string, any> | null,
  newState: Record<string, any> | null
) {
  const pseudokey = sessionStorage.getItem('ea_niti_session') || 'SYSTEM';

  const sanitize = (obj: Record<string, any> | null) => {
    if (!obj) return null;
    const clone = { ...obj };
    const sensitiveKeys = ['password', 'token', 'secret', 'key', 'credential', 'encrypted'];
    for (const key of Object.keys(clone)) {
      if (sensitiveKeys.some(sk => key.toLowerCase().includes(sk))) {
        clone[key] = '[REDACTED]';
      }
    }
    return clone;
  };

  await db.audit_logs.add({
    timestamp: new Date(),
    pseudokey,
    action,
    tableName,
    recordId: String(recordId),
    details: JSON.stringify({
      recordId: String(recordId),
      previousState: sanitize(previousState),
      newState: sanitize(newState)
    }, null, 2)
  });
}

import { PGlite } from '@electric-sql/pglite';
import seedData from '../data/ea_seed_data.json';
import { Logger } from '../lib/logger';

let db: PGlite | null = null;

self.onmessage = async (e: MessageEvent) => {
  const { id, type, payload } = e.data;

  try {
    if (type === 'INIT') {
      if (!db) {
        // Initialize PGLite with IndexedDB persistence
        db = new PGlite('idb://ea-niti-pglite');
        await db.waitReady;

        // Setup initial schema if needed
        await db.exec(`
          CREATE TABLE IF NOT EXISTS sme_routing (
            id SERIAL PRIMARY KEY,
            domain VARCHAR(255) NOT NULL,
            rules JSONB NOT NULL
          );

          CREATE TABLE IF NOT EXISTS togaf_phases (
            id VARCHAR(10) PRIMARY KEY,
            name VARCHAR(255) NOT NULL,
            description TEXT
          );

          CREATE TABLE IF NOT EXISTS service_domains (
            id VARCHAR(10) PRIMARY KEY,
            name VARCHAR(255) NOT NULL,
            businessArea VARCHAR(255),
            status VARCHAR(50)
          );
        `);

        // Check if seeded
        const res = await db.query('SELECT count(*) as count FROM togaf_phases');
        if (Number((res.rows[0] as any).count) === 0) {
          Logger.('[PGLite] Seeding TOGAF and Service data...');
          // Seed TOGAF
          for (const phase of seedData.togaf_phases) {
            await db.query('INSERT INTO togaf_phases (id, name, description) VALUES ($1, $2, $3)', [phase.id, phase.name, phase.description]);
          }
          // Seed Service Domains
          for (const domain of seedData.service_domains) {
            await db.query('INSERT INTO service_domains (id, name, businessArea, status) VALUES ($1, $2, $3, $4)', [domain.id, domain.name, domain.businessArea, domain.status]);
          }
        }
      }
      self.postMessage({ id, status: 'success' });
    } 
    else if (type === 'QUERY') {
      if (!db) throw new Error('PGLite not initialized');
      const result = await db.query(payload.query, payload.params);
      self.postMessage({ id, status: 'success', data: result.rows });
    }
    else if (type === 'EXEC') {
      if (!db) throw new Error('PGLite not initialized');
      await db.exec(payload.query);
      self.postMessage({ id, status: 'success' });
    }
  } catch (error: any) {
    self.postMessage({ id, status: 'error', error: error.message });
  }
};

/**
 * Scorecard Engine — BDAT Weighted Vendor Comparison
 *
 * Pure function module. No React dependencies.
 * Consumes DDQScorecard objects from ddqRules.ts and applies
 * configurable Business/Data/Application/Technology axis weights
 * to produce a ranked vendor comparison.
 */

import { DDQScorecard } from './ddqRules';

// ─── Types ───────────────────────────────────────────────────

export interface BDATWeights {
  B: number; // Business
  D: number; // Data
  A: number; // Application
  T: number; // Technology
}

export interface BDATAxisScore {
  raw: number;      // Sum of principle scores on this axis
  max: number;      // Sum of max possible scores on this axis
  percentage: number;
  weighted: number;  // raw * (weight / 100)
}

export interface WeightedVendorResult {
  name: string;
  axes: { B: BDATAxisScore; D: BDATAxisScore; A: BDATAxisScore; T: BDATAxisScore };
  totalWeightedScore: number;
  totalRawScore: number;
  totalMaxScore: number;
  overallPercentage: number;
}

// ─── BDAT Principle Mapping ──────────────────────────────────
// Maps each DDQ design principle to a BDAT axis.
// B = Business value & alignment
// D = Data governance, compliance, portability
// A = Application architecture patterns
// T = Technology infrastructure & operations

export const BDAT_PRINCIPLE_MAP: Record<string, keyof BDATWeights> = {
  // Business Axis
  'Capability Dedupe':        'B',
  'Outsourcing':              'B',
  'Testing':                  'B',

  // Data Axis
  'Security':                 'D',
  'Compliance':               'D',
  'Data Models':              'D',
  'Portability':              'D',

  // Application Axis
  'Scalability':              'A',
  'Extensibility':            'A',
  'Interoperability':         'A',
  'API':                      'A',

  // Technology Axis
  'Reliability':              'T',
  'Performance Optimization': 'T',
  'Observability':            'T',
  'Build and Deployments':    'T',
  'Tech Obsolescence':        'T',
  'Migration':                'T',
  'VAPT / AppSec':            'T',
};

// ─── Weight Presets ──────────────────────────────────────────

export const BDAT_WEIGHT_PRESETS: Record<string, BDATWeights> = {
  NSI:          { B: 15, D: 35, A: 15, T: 35 },
  Enhancement:  { B: 30, D: 20, A: 30, T: 20 },
  Flat:         { B: 25, D: 25, A: 25, T: 25 },
};

/**
 * Returns the appropriate BDAT weight preset based on the review type string.
 * Falls back to Flat if no match is found.
 */
export function getDefaultWeightsForReviewType(reviewType: string): BDATWeights {
  const normalized = reviewType.toLowerCase();
  if (normalized.includes('nsi') || normalized.includes('new system')) {
    return { ...BDAT_WEIGHT_PRESETS.NSI };
  }
  if (normalized.includes('enhancement') || normalized.includes('er ')) {
    return { ...BDAT_WEIGHT_PRESETS.Enhancement };
  }
  return { ...BDAT_WEIGHT_PRESETS.Flat };
}

// ─── Core Computation ────────────────────────────────────────

/**
 * Computes a BDAT-weighted scorecard for multiple vendors.
 * Each vendor's DDQScorecard principleScores are mapped to BDAT axes,
 * weighted, and returned as a ranked array (highest weighted score first).
 */
export function computeWeightedScorecard(
  vendors: { name: string; scorecard: DDQScorecard }[],
  weights: BDATWeights
): WeightedVendorResult[] {
  // Normalize weights to ensure they sum to 100
  const totalWeight = weights.B + weights.D + weights.A + weights.T;
  const norm: BDATWeights = {
    B: (weights.B / totalWeight) * 100,
    D: (weights.D / totalWeight) * 100,
    A: (weights.A / totalWeight) * 100,
    T: (weights.T / totalWeight) * 100,
  };

  return vendors.map(vendor => {
    const axisAccum: Record<keyof BDATWeights, { raw: number; max: number }> = {
      B: { raw: 0, max: 0 },
      D: { raw: 0, max: 0 },
      A: { raw: 0, max: 0 },
      T: { raw: 0, max: 0 },
    };

    // Accumulate principle scores into BDAT axes
    for (const [principle, data] of Object.entries(vendor.scorecard.principleScores)) {
      const axis = BDAT_PRINCIPLE_MAP[principle];
      if (axis) {
        axisAccum[axis].raw += data.score;
        axisAccum[axis].max += data.maxScore;
      }
    }

    // Build axis scores with weighting
    const axes = {} as WeightedVendorResult['axes'];
    let totalWeightedScore = 0;
    let totalRawScore = 0;
    let totalMaxScore = 0;

    for (const key of ['B', 'D', 'A', 'T'] as (keyof BDATWeights)[]) {
      const { raw, max } = axisAccum[key];
      const percentage = max > 0 ? (raw / max) * 100 : 0;
      const weighted = percentage * (norm[key] / 100);

      axes[key] = {
        raw,
        max,
        percentage: Math.round(percentage),
        weighted: Math.round(weighted * 100) / 100,
      };

      totalWeightedScore += weighted;
      totalRawScore += raw;
      totalMaxScore += max;
    }

    return {
      name: vendor.name,
      axes,
      totalWeightedScore: Math.round(totalWeightedScore * 100) / 100,
      totalRawScore,
      totalMaxScore,
      overallPercentage: totalMaxScore > 0 ? Math.round((totalRawScore / totalMaxScore) * 100) : 0,
    };
  }).sort((a, b) => b.totalWeightedScore - a.totalWeightedScore);
}

/**
 * Returns the principle-level breakdown for a specific BDAT axis.
 * Useful for rendering expandable detail rows in the scorecard table.
 */
export function getPrinciplesByAxis(axis: keyof BDATWeights): string[] {
  return Object.entries(BDAT_PRINCIPLE_MAP)
    .filter(([_, a]) => a === axis)
    .map(([principle]) => principle);
}

