                        Lost access? Hard Reset Application
                      </button>
                    )}
                  </div>
                )}
                
                <button type="submit" disabled={isProcessing} className="w-full bg-blue-600 hover:bg-blue-700 dark:bg-gradient-to-r dark:from-blue-600 dark:to-blue-500 text-white font-bold rounded-lg px-6 py-3 text-sm transition-all flex items-center justify-center gap-2 disabled:opacity-50">
                  {isProcessing ? <Loader2 className="w-5 h-5 animate-spin" /> : <Lock className="w-5 h-5" />} Recover Passphrase
                </button>
              </form>
            </div>
          )}

          {view === 'RECOVERY_SUCCESS' && (
            <div className="space-y-4">
              <div className="text-center">
                <div className="inline-flex items-center justify-center w-12 h-12 rounded-full bg-emerald-100 dark:bg-emerald-500/20 text-emerald-600 dark:text-emerald-400 mb-2">
                  <CheckCircle2 className="w-6 h-6" />
                </div>
                <h3 className="text-base sm:text-lg font-bold text-gray-900 dark:text-white tracking-wide">Recovery Successful</h3>
                <p className="text-xs sm:text-sm text-gray-500 dark:text-blue-200/60 mt-1">Your credentials have been recovered.</p>
              </div>

              <div className="space-y-3 bg-gray-50 dark:bg-white/5 p-4 rounded-xl border border-gray-200 dark:border-white/10">
                <div>
                  <p className="text-xs text-gray-500 dark:text-gray-400 font-semibold mb-1">Agent ID</p>
                  <div className="flex items-center justify-between">
                    <p className="font-mono text-sm text-gray-900 dark:text-white">
                      {showRecoveredAgentId ? pseudokey : `${pseudokey.substring(0, 3)}***${pseudokey.substring(pseudokey.length - 3)}`}
                    </p>
                    <button 
                      onClick={() => setShowRecoveredAgentId(!showRecoveredAgentId)}
                      className="text-xs bg-blue-100 dark:bg-blue-500/20 text-blue-700 dark:text-blue-400 px-2 py-1 rounded font-bold hover:bg-blue-200 dark:hover:bg-blue-500/30 transition-colors"
                    >
                      {showRecoveredAgentId ? 'Hide' : 'View'}
                    </button>
                  </div>
                </div>
                <div>
                  <p className="text-xs text-gray-500 dark:text-gray-400 font-semibold mb-1">PIN</p>
                  <div className="flex items-center justify-between">
                    <p className="font-mono text-sm text-gray-900 dark:text-white">
                      {showRecoveredPin ? pin : `***${pin.substring(pin.length - 1)}`}
                    </p>
                    <button 
                      onClick={() => setShowRecoveredPin(!showRecoveredPin)}
                      className="text-xs bg-blue-100 dark:bg-blue-500/20 text-blue-700 dark:text-blue-400 px-2 py-1 rounded font-bold hover:bg-blue-200 dark:hover:bg-blue-500/30 transition-colors"
                    >
                      {showRecoveredPin ? 'Hide' : 'View'}
                    </button>
                  </div>
                </div>
                <div>
                  <p className="text-xs text-gray-500 dark:text-gray-400 font-semibold mb-1">Passphrase</p>
                  <div className="flex items-center justify-between">
                    <p className="font-mono text-sm text-gray-900 dark:text-white">
                      {showRecoveredPassword ? recoveredPassword : '••••••••••••'}
                    </p>
                    <button 
                      onClick={() => setShowRecoveredPassword(!showRecoveredPassword)}
                      className="text-xs bg-blue-100 dark:bg-blue-500/20 text-blue-700 dark:text-blue-400 px-2 py-1 rounded font-bold hover:bg-blue-200 dark:hover:bg-blue-500/30 transition-colors"
                    >
                      {showRecoveredPassword ? 'Hide' : 'View'}
                    </button>
                  </div>
                </div>
              </div>

              <button onClick={() => { setView('LOGIN'); setRecoveredPassword(null); setShowRecoveredPassword(false); setShowRecoveredAgentId(false); setShowRecoveredPin(false); setPassword(''); }} className="w-full bg-blue-600 hover:bg-blue-700 dark:bg-gradient-to-r dark:from-blue-600 dark:to-blue-500 text-white font-bold rounded-lg px-6 py-3 text-sm transition-all flex items-center justify-center gap-2">
                Return to Login
              </button>
            </div>
          )}
        </div>
        
        {/* Footer shrink-blocked to maintain presence at bounds layer */}
        <div className="mt-0.5 text-center text-[10px] sm:text-xs text-gray-400 dark:text-gray-600 flex flex-col gap-0.5 w-full shrink-0">
          <p className="flex items-center justify-center gap-1"><AlertTriangle className="w-2 h-2" /> Immutable Data Minimization.</p>
          <p>Local Storage DB is natively encrypted with these keys.</p>
        </div>
      </div>

      {showResetConfirm && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/60 backdrop-blur-sm p-4">
          <div className="bg-white dark:bg-gray-900 border border-red-200 dark:border-red-900/50 rounded-2xl p-6 max-w-sm w-full shadow-2xl">
            <div className="flex items-center gap-3 text-red-600 dark:text-red-500 mb-4">
              <AlertTriangle className="w-6 h-6" />
              <h3 className="text-lg font-bold">Hard Reset Application</h3>
            </div>
            <p className="text-sm text-gray-600 dark:text-gray-300 mb-6">
              This will permanently delete all local data, including your identity, vault, and configurations. This action cannot be undone. Are you sure you want to proceed?
            </p>
            <div className="flex gap-3">
              <button 
                onClick={() => setShowResetConfirm(false)}
                className="flex-1 px-4 py-2 bg-gray-100 hover:bg-gray-200 dark:bg-gray-800 dark:hover:bg-gray-700 text-gray-700 dark:text-gray-300 font-bold rounded-lg transition-colors"
              >
                Cancel
              </button>
              <button 
                onClick={async () => {
                  const { hardResetApp } = await import('../lib/authEngine');
                  await hardResetApp();
                }}
                className="flex-1 px-4 py-2 bg-red-600 hover:bg-red-700 text-white font-bold rounded-lg transition-colors"
              >
                Yes, Reset
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
    </>
  );
}

import { useState, useEffect, useMemo } from 'react';
import SystemHealth from '../components/widgets/SystemHealth';
import DistillationTerminal from '../components/widgets/DistillationTerminal';
import { useLiveQuery } from 'dexie-react-hooks';
import { db } from '../lib/db';
import { FileText, Edit2, Save, LayoutGrid, CheckCircle } from 'lucide-react';
import { StatCard, NativeBarChart, NativeProgressRing } from '../components/widgets/WidgetLibrary';

// Default layout config if no dashboard exist
const DEFAULT_WIDGETS = ['drafts', 'completed', 'reviews_by_type', 'completion_rate'];

interface DashboardProps {
  setCurrentView: (view: string) => void;
  setCurrentSessionId: (id: number) => void;
}

export default function Dashboard({ setCurrentView: _setCurrentView, setCurrentSessionId: _setCurrentSessionId }: DashboardProps) {
  const [isEditMode, setIsEditMode] = useState(false);
  const [boardName, setBoardName] = useState('Default View');
  const [activeWidgets, setActiveWidgets] = useState<string[]>(DEFAULT_WIDGETS);

  // Fetch Dashboards
  const savedBoards = useLiveQuery(() => db.dashboard_states.toArray());

  // Real-time Metrics Queries
  const allSessions = useLiveQuery(() => db.review_sessions.toArray()) || [];
  const threatModels = useLiveQuery(() => db.threat_models.toArray()) || [];

  const draftCount = useMemo(() => {
    return allSessions.filter(s => s.status === 'Draft').length;
  }, [allSessions]);

  const completedCount = useMemo(() => {
    return allSessions.filter(s => s.status === 'Completed').length;
  }, [allSessions]);

  const barChartData = useMemo(() => {
    const typeMap: Record<string, number> = {};
    allSessions.forEach(s => {
      if (s.type) typeMap[s.type] = (typeMap[s.type] || 0) + 1;
    });
    return Object.entries(typeMap).map(([label, value]) => ({ label, value }));
  }, [allSessions]);

  // Load first board if exists
  useEffect(() => {
     if (savedBoards && savedBoards.length > 0 && !isEditMode) {
       const board = savedBoards[0];
       setBoardName(board.name);
       setActiveWidgets(board.layoutConfig);
     }
  }, [savedBoards, isEditMode]);

  const handleSaveBoard = async () => {
    try {
      await db.dashboard_states.add({
         name: boardName,
         isDefault: false,
         layoutConfig: activeWidgets,
         createdAt: new Date(),
         updatedAt: new Date(),
      });
      setIsEditMode(false);
    } catch (e) {
      console.error(e);
    }
  };

  const toggleWidget = (id: string) => {
    setActiveWidgets(prev => prev.includes(id) ? prev.filter(w => w !== id) : [...prev, id]);
  };

  return (
    <div className="w-full pb-10">
      <div className="flex justify-between items-center mb-6">
        <div className="flex items-center gap-3">
          {isEditMode ? (
             <input type="text" aria-label="Board Name" value={boardName} onChange={e => setBoardName(e.target.value)}
                    className="text-2xl font-bold bg-white dark:bg-gray-800 border border-blue-500 rounded px-2 py-1 outline-none text-gray-900 dark:text-white" />
          ) : (
             <h2 className="text-2xl font-bold text-gray-900 dark:text-white flex items-center gap-2">
               <LayoutGrid size={24} className="text-blue-600 dark:text-blue-500" />
               {boardName}
             </h2>
          )}
        </div>

        <div className="flex items-center gap-2">
          {isEditMode ? (
             <button onClick={handleSaveBoard} className="flex items-center gap-2 px-4 py-2 bg-green-600 hover:bg-green-700 text-white rounded-lg text-sm font-medium transition-colors">
               <Save size={16} /> Save As New
             </button>
          ) : (
             <button onClick={() => setIsEditMode(true)} className="flex items-center gap-2 px-4 py-2 bg-gray-200 dark:bg-gray-800 hover:bg-gray-300 dark:hover:bg-gray-700 text-gray-900 dark:text-white rounded-lg text-sm font-medium transition-colors">
               <Edit2 size={16} /> Edit Mode
             </button>
          )}
        </div>
      </div>

      {isEditMode && (
         <div className="bg-yellow-50 dark:bg-yellow-900/20 border border-yellow-200 dark:border-yellow-800 rounded-xl p-4 mb-6">
            <h3 className="text-sm font-bold text-yellow-800 dark:text-yellow-400 mb-3">Widget Selection</h3>
            <div className="flex flex-wrap gap-2">
               {[
                 { id: 'drafts', label: 'Draft Sessions Card' },
                 { id: 'completed', label: 'Completed Reviews Card' },
                 { id: 'threats', label: 'Threat Models Card' },
                 { id: 'reviews_by_type', label: 'Reviews by Type (Bar)' },
                 { id: 'completion_rate', label: 'Completion Rate (Ring)' }
               ].map(w => (
                 <button key={w.id} onClick={() => toggleWidget(w.id)}
                         className={`px-3 py-1.5 rounded-full text-xs font-medium border transition-colors ${activeWidgets.includes(w.id) ? 'bg-blue-600 text-white border-blue-600' : 'bg-white dark:bg-gray-800 text-gray-600 dark:text-gray-400 border-gray-300 dark:border-gray-600 hover:border-gray-400'}`}>
                   {activeWidgets.includes(w.id) ? <CheckCircle size={10} className="inline mr-1" /> : null}
                   {w.label}
                 </button>
               ))}
            </div>
         </div>
      )}

      {/* Responsive Grid System for Widgets */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-6">

        {/* Row 1 / Stat Cards */}
        {activeWidgets.includes('drafts') && (
           <div className="lg:col-span-1 border border-transparent">
             <StatCard title="Draft Reviews" value={draftCount} icon={FileText} />
           </div>
        )}
        {activeWidgets.includes('completed') && (
           <div className="lg:col-span-1 border border-transparent">
             <StatCard title="Completed Output" value={completedCount} icon={CheckCircle} colorClass="text-emerald-500 bg-emerald-100 dark:bg-emerald-900/30" />
           </div>
        )}
        {activeWidgets.includes('threats') && (
           <div className="lg:col-span-1 border border-transparent">
             <StatCard title="Threat Models" value={threatModels.length} colorClass="text-red-500 bg-red-100 dark:bg-red-900/30" />
           </div>
        )}

      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 mb-6">

        {/* Row 2 / Visualizations */}
        {activeWidgets.includes('completion_rate') && (
           <div className="lg:col-span-1 min-h-[250px] border border-transparent">
             <NativeProgressRing title="Completion Rate" value={completedCount} max={allSessions.length} label="Finalized" />
           </div>
        )}

        {activeWidgets.includes('reviews_by_type') && (
           <div className="lg:col-span-2 min-h-[250px] border border-transparent">
             <NativeBarChart title="Assessments By Review Type" data={barChartData} />
           </div>
        )}

      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        <div className="lg:col-span-1">
          <SystemHealth />
        </div>
        <div className="lg:col-span-2">
          <DistillationTerminal />
        </div>
      </div>
    </div>
  );
}

import { useState, useEffect, useMemo, useCallback } from 'react';
import { db } from '../lib/db';
import { encryptString, decryptString } from '../lib/cryptoVault';
import { useLiveQuery } from 'dexie-react-hooks';
import {
  DataFlowComponent, ComponentType, StrideThreat, ThreatModel,
  analyzeComponentsForThreats, buildMermaidDFD, generateThreatModelPrompt,
  generateComponentId, getThreatStats, STRIDE_CATEGORIES, StrideCategoryKey
} from '../lib/threatEngine';
import { generateReview } from '../lib/aiEngine';
import SafeMermaid from '../components/ui/SafeMermaid';
import { Plus, Trash2, Shield, BrainCircuit, Save, Download, Loader2, Link2, AlertTriangle, X, ArrowLeft, Wand2 } from 'lucide-react';
import { Logger } from '../lib/logger';

const COMPONENT_TYPES: ComponentType[] = ['External Entity', 'Process', 'Data Store', 'Data Flow', 'Trust Boundary'];
const TYPE_ICONS: Record<ComponentType, string> = {
  'External Entity': '👤',
  'Process':         '⚙️',
  'Data Store':      '🗄️',
  'Data Flow':       '🔀',
  'Trust Boundary':  '🛡️',
};

export default function ThreatEditor({ onClose: _onClose, modelId }: { onClose?: () => void, modelId?: number }) {
  const [projectName, setProjectName] = useState('');
  const [components, setComponents] = useState<DataFlowComponent[]>([]);
  const [linkedSessionId, setLinkedSessionId] = useState<number | undefined>();
  const [isEnriching, setIsEnriching] = useState(false);
  const [enrichedReport, setEnrichedReport] = useState('');
  const [isSaving, setIsSaving] = useState(false);
  const [saveMessage, setSaveMessage] = useState('');

  // Hybrid Context State
  const [dataClassification, setDataClassification] = useState('Confidential');
  const [networkPosture, setNetworkPosture] = useState('Internal VPC');
  const [hostingModel, setHostingModel] = useState('On-Premises');

  useEffect(() => {
    if (modelId) {
      db.threat_models.get(modelId).then(async (model) => {
        if (model) {
          setProjectName(model.projectName);
          setLinkedSessionId(model.sessionId);
          if (model.encryptedData) {
            try {
              const decrypted = await decryptString(model.encryptedData);
              const data = JSON.parse(decrypted);
              setComponents(data.components || []);
              if (data.dataClassification) setDataClassification(data.dataClassification);
              if (data.networkPosture) setNetworkPosture(data.networkPosture);
              if (data.hostingModel) setHostingModel(data.hostingModel);
            } catch (e) {
              Logger.('Failed to decrypt threat model', e);
            }
          } else {
            setComponents(model.components || []);
          }
        }
      });
    }
  }, [modelId]);

  // Form state for adding components
  const [showAddForm, setShowAddForm] = useState(false);
  const [newComp, setNewComp] = useState<{ name: string; type: ComponentType; description: string; connectsTo: string[] }>({
    name: '', type: 'Process', description: '', connectsTo: []
  });

  const reviewSessions = useLiveQuery(() => db.review_sessions.toArray()) || [];

  const threats = useMemo<StrideThreat[]>(() => {
    return components.length > 0 ? analyzeComponentsForThreats(components) : [];
  }, [components]);

  const mermaidDFD = useMemo(() => {
    return components.length > 0 ? buildMermaidDFD(components) : '';
  }, [components]);

  const handleToggleConnection = useCallback((id: string) => {
    setNewComp(prev => ({
      ...prev,
      connectsTo: prev.connectsTo.includes(id)
        ? prev.connectsTo.filter(connId => connId !== id)
        : [...prev.connectsTo, id]
    }));
  }, []);

  const handleAddComponent = useCallback(() => {
    if (!newComp.name.trim()) return;
    const component: DataFlowComponent = {
      id: generateComponentId(newComp.type),
      name: newComp.name.trim(),
      type: newComp.type,
      description: newComp.description.trim(),
      connectsTo: newComp.connectsTo,
    };
    setComponents(prev => [...prev, component]);
    setNewComp({ name: '', type: 'Process', description: '', connectsTo: [] });
    setShowAddForm(false);
  }, [newComp]);

  const handleRemoveComponent = useCallback((id: string) => {
    setComponents(prev => {
      const filtered = prev.filter(c => c.id !== id);
      return filtered.map(c => ({
        ...c,
        connectsTo: c.connectsTo.filter(cid => cid !== id)
      }));
    });
  }, []);

  const handleSave = useCallback(async () => {
    if (!projectName.trim()) {
      setSaveMessage('Project name is required.');
      setTimeout(() => setSaveMessage(''), 3000);
      return;
    }
    setIsSaving(true);
    try {
      const payload = JSON.stringify({ 
        components, 
        threats, 
        mermaidDFD,
        dataClassification,
        networkPosture,
        hostingModel
      });
      const encryptedData = await encryptString(payload);

      if (modelId) {
        await db.threat_models.update(modelId, {
          projectName: projectName.trim(),
          sessionId: linkedSessionId,
          encryptedData,
          componentCount: components.length,
          threatCount: threats.length,
          updatedAt: new Date(),
        });
      } else {
        await db.threat_models.add({
          projectName: projectName.trim(),
          sessionId: linkedSessionId,
          encryptedData,
          componentCount: components.length,
          threatCount: threats.length,
          createdAt: new Date(),
          updatedAt: new Date(),
        });
      }
      setSaveMessage('Threat model saved to local database.');
      setTimeout(() => setSaveMessage(''), 3000);
    } catch (e) {
      setSaveMessage('Failed to save threat model.');
    } finally {
      setIsSaving(false);
    }
  }, [projectName, components, threats, mermaidDFD, dataClassification, networkPosture, hostingModel, linkedSessionId, modelId]);

  const handleExportMarkdown = useCallback(() => {
    let md = `# STRIDE Threat Model: ${projectName || 'Untitled'}\n\n`;
    md += `**Generated:** ${new Date().toISOString()}\n\n`;
    md += `## Data Flow Diagram\n\n\`\`\`mermaid\n${mermaidDFD}\n\`\`\`\n\n`;
    md += `## Components (${components.length})\n\n`;
    md += `| ID | Name | Type | Description |\n|-----|------|------|-------------|\n`;
    components.forEach(c => { md += `| ${c.id} | ${c.name} | ${c.type} | ${c.description} |\n`; });
    md += `\n## STRIDE Threat Analysis (${threats.length} threats)\n\n`;
    (['S','T','R','I','D','E'] as StrideCategoryKey[]).forEach(cat => {
      const catThreats = threats.filter(t => t.category === cat);
      if (catThreats.length === 0) return;
      md += `### ${STRIDE_CATEGORIES[cat].name} (${catThreats.length})\n\n`;
      md += `| Component | Severity | Description | Mitigation |\n|-----------|----------|-------------|------------|\n`;
      catThreats.forEach(t => { md += `| ${t.componentName} | ${t.severity} | ${t.description} | ${t.mitigation} |\n`; });
      md += '\n';
    });
    if (enrichedReport) {
      md += `## AI-Enriched Analysis\n\n${enrichedReport}\n`;
    }
    const blob = new Blob([md], { type: 'text/markdown' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `STRIDE_${(projectName || 'threat_model').replace(/[^a-z0-9]/gi, '_')}.md`;
    a.click();
    URL.revokeObjectURL(url);
  }, [projectName, components, threats, mermaidDFD, enrichedReport]);

  const handleEnrichWithAI = async () => {
    if (threats.length === 0) return;
    setIsEnriching(true);
    setEnrichedReport('');
    try {
      const principles = await db.architecture_principles.where('status').equals('Active').toArray();
      const model: ThreatModel = {
        projectName: projectName || 'Untitled',
        components,
        threats,
        mermaidDFD,
        createdAt: new Date(),
        updatedAt: new Date(),
      };
      const prompt = generateThreatModelPrompt(model, principles);
      await generateReview(prompt, (text) => setEnrichedReport(text), 'Primary EA Agent');
    } catch (error: any) {
      if (!error.message?.includes('CONSENT_REQUIRED')) {
        Logger.('AI Enrichment error:', error);
      }
    } finally {
      setIsEnriching(false);
    }
  };

  const handleSynthesize = () => {
    const payload = {
      dataClassification,
      networkPosture,
      hostingModel,
      components
    };
    Logger.('Synthesizing Threat Matrix with payload:', payload);
    // In a future MVP, this will trigger the WebLLM engine
  };

  const threatStats = useMemo(() => getThreatStats(threats), [threats]);

  return (
    <div className="w-full pb-20">
      <div className="mb-6 flex items-center gap-4">
        {_onClose && (
          <button 
            onClick={_onClose}
            className="p-2 text-gray-500 hover:text-blue-600 hover:bg-blue-50 dark:hover:bg-blue-900/20 rounded-lg transition-colors"
            title="Back to Ledger"
          >
            <ArrowLeft size={20} />
          </button>
        )}
        <div>
          <h2 className="text-2xl font-bold text-gray-900 dark:text-white mb-1">STRIDE Threat Modeling</h2>
          <p className="text-gray-600 dark:text-gray-400">Build Data Flow Diagrams and auto-generate STRIDE-based threat analysis locally.</p>
        </div>
      </div>

      {/* Header Controls */}
      <div className="bg-white dark:bg-gray-800 rounded-xl border border-gray-200 dark:border-gray-700 p-5 mb-6 shadow-sm dark:shadow-none space-y-6">
        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
          <div>
            <label className="block text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase mb-1">Project Name</label>
            <input
              type="text" value={projectName}
              onChange={e => setProjectName(e.target.value)}
              placeholder="e.g., Payment Gateway Redesign"
              className="w-full bg-gray-50 dark:bg-gray-900 border border-gray-300 dark:border-gray-700 rounded-lg px-3 py-2 text-sm text-gray-900 dark:text-white outline-none focus:ring-1 focus:ring-blue-500"
            />
          </div>
          <div>
            <label htmlFor="linked-session-select" className="block text-xs font-semibold text-gray-500 dark:text-gray-400 uppercase mb-1">Attach to Review Session (Optional)</label>
            <select
              id="linked-session-select"
              value={linkedSessionId || ''}
              onChange={e => setLinkedSessionId(e.target.value ? parseInt(e.target.value) : undefined)}
              className="w-full bg-gray-50 dark:bg-gray-900 border border-gray-300 dark:border-gray-700 rounded-lg px-3 py-2 text-sm text-gray-900 dark:text-white outline-none focus:ring-1 focus:ring-blue-500"
            >
              <option value="">Standalone (no session)</option>
              {reviewSessions.map(s => (
                <option key={s.id} value={s.id}>{s.projectName} ({s.type})</option>
              ))}
            </select>
          </div>
          <div className="flex items-end gap-2">
            <button onClick={handleSave} disabled={isSaving} className="flex items-center gap-2 px-4 py-2 bg-blue-600 hover:bg-blue-700 disabled:opacity-50 text-white rounded-lg text-sm font-medium transition-colors">
              {isSaving ? <Loader2 size={14} className="animate-spin" /> : <Save size={14} />} Save
            </button>
            <button onClick={handleExportMarkdown} disabled={threats.length === 0} className="flex items-center gap-2 px-4 py-2 bg-gray-200 dark:bg-gray-700 hover:bg-gray-300 dark:hover:bg-gray-600 disabled:opacity-50 text-gray-900 dark:text-white rounded-lg text-sm font-medium transition-colors">
              <Download size={14} /> Export .md
            </button>
            <button 
              onClick={handleSynthesize} 
              disabled={components.length === 0} 
              className="flex items-center gap-2 px-4 py-2 bg-purple-600 hover:bg-purple-700 disabled:opacity-50 text-white rounded-lg text-sm font-medium transition-colors shadow-sm"
            >
              <Wand2 size={14} /> Synthesize STRIDE Threats
            </button>
          </div>
        </div>

        {/* Hybrid Context Dropdowns */}
        <div className="pt-4 border-t border-gray-200 dark:border-gray-700">
          <h3 className="text-xs font-bold text-gray-900 dark:text-white mb-3 uppercase tracking-wider">System Context</h3>
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            <div className="flex flex-col gap-2">
              <label htmlFor="data-classification" className="text-[10px] font-semibold text-gray-500 dark:text-gray-400 uppercase">Data Classification</label>
              <select
                id="data-classification"
                value={dataClassification}
                onChange={(e) => setDataClassification(e.target.value)}
                className="font-mono text-xs bg-gray-50 dark:bg-gray-900 border border-gray-300 dark:border-gray-700 text-gray-900 dark:text-white rounded-lg px-3 py-2 outline-none focus:border-blue-500 dark:focus:border-blue-500"
              >
                <option value="Public">Public</option>
                <option value="Internal">Internal</option>
                <option value="Confidential">Confidential</option>
                <option value="Restricted">Restricted</option>
              </select>
            </div>
            <div className="flex flex-col gap-2">
              <label htmlFor="network-posture" className="text-[10px] font-semibold text-gray-500 dark:text-gray-400 uppercase">Network Posture</label>
              <select
                id="network-posture"
                value={networkPosture}
                onChange={(e) => setNetworkPosture(e.target.value)}
                className="font-mono text-xs bg-gray-50 dark:bg-gray-900 border border-gray-300 dark:border-gray-700 text-gray-900 dark:text-white rounded-lg px-3 py-2 outline-none focus:border-blue-500 dark:focus:border-blue-500"
              >
                <option value="Air-Gapped">Air-Gapped</option>
                <option value="Internal VPC">Internal VPC</option>
                <option value="Internet-Facing">Internet-Facing</option>
              </select>
            </div>
            <div className="flex flex-col gap-2">
              <label htmlFor="hosting-model" className="text-[10px] font-semibold text-gray-500 dark:text-gray-400 uppercase">Hosting Model</label>
              <select
                id="hosting-model"
                value={hostingModel}
                onChange={(e) => setHostingModel(e.target.value)}
                className="font-mono text-xs bg-gray-50 dark:bg-gray-900 border border-gray-300 dark:border-gray-700 text-gray-900 dark:text-white rounded-lg px-3 py-2 outline-none focus:border-blue-500 dark:focus:border-blue-500"
              >
                <option value="On-Premises">On-Premises</option>
                <option value="Cloud Provider">Cloud Provider</option>
                <option value="Edge Device">Edge Device</option>
              </select>
            </div>
          </div>
        </div>
      </div>

      {saveMessage && (
        <div className="mb-4 px-4 py-2 rounded-lg text-sm font-medium bg-green-100 dark:bg-green-900/20 text-green-700 dark:text-green-400 border border-green-200 dark:border-green-800">
          {saveMessage}
        </div>
      )}

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
        {/* Left Panel: Component Builder */}
        <div className="lg:col-span-1 space-y-4">
          <div className="bg-white dark:bg-gray-800 rounded-xl border border-gray-200 dark:border-gray-700 p-5 shadow-sm dark:shadow-none">
            <div className="flex justify-between items-center mb-4">
              <h3 className="font-semibold text-gray-900 dark:text-white text-sm">DFD Components ({components.length})</h3>
              <button onClick={() => setShowAddForm(!showAddForm)} className="flex items-center gap-1 px-3 py-1.5 bg-blue-600 hover:bg-blue-700 text-white rounded-lg text-xs font-medium transition-colors">
                {showAddForm ? <X size={12} /> : <Plus size={12} />} {showAddForm ? 'Cancel' : 'Add'}
              </button>
            </div>

            {showAddForm && (
              <div className="mb-4 p-3 bg-gray-50 dark:bg-gray-900 rounded-lg border border-gray-200 dark:border-gray-700 space-y-3">
                <input type="text" value={newComp.name} onChange={e => setNewComp({ ...newComp, name: e.target.value })}
                  placeholder="Component name" className="w-full bg-white dark:bg-gray-800 border border-gray-300 dark:border-gray-700 rounded px-3 py-1.5 text-sm text-gray-900 dark:text-white outline-none" />
                <select aria-label="New component type" value={newComp.type} onChange={e => setNewComp({ ...newComp, type: e.target.value as ComponentType })}
                  className="w-full bg-white dark:bg-gray-800 border border-gray-300 dark:border-gray-700 rounded px-3 py-1.5 text-sm text-gray-900 dark:text-white outline-none">
                  {COMPONENT_TYPES.map(t => <option key={t} value={t}>{TYPE_ICONS[t]} {t}</option>)}
                </select>
                <textarea value={newComp.description} onChange={e => setNewComp({ ...newComp, description: e.target.value })}
                  placeholder="Description..." className="w-full bg-white dark:bg-gray-800 border border-gray-300 dark:border-gray-700 rounded px-3 py-1.5 text-sm text-gray-900 dark:text-white outline-none resize-none h-14" />
                {components.length > 0 && (
                  <div>
                    <label className="block text-xs text-gray-500 mb-1">Connects to:</label>
                    <div className="flex flex-wrap gap-1">
                      {components.map(c => (
                        <button key={c.id} onClick={() => handleToggleConnection(c.id)}
                          className={`px-2 py-0.5 rounded text-[10px] font-medium transition-colors ${newComp.connectsTo.includes(c.id) ? 'bg-blue-600 text-white' : 'bg-gray-200 dark:bg-gray-700 text-gray-700 dark:text-gray-300'}`}
                        >
                          {c.name}
                        </button>
                      ))}
                    </div>
                  </div>
                )}
                <button onClick={handleAddComponent} disabled={!newComp.name.trim()} className="w-full py-1.5 bg-blue-600 hover:bg-blue-700 disabled:opacity-50 text-white rounded text-xs font-medium transition-colors">
                  Add Component
                </button>
              </div>
            )}

            {/* Component List */}
            <div className="space-y-2 max-h-[400px] overflow-y-auto pr-1">
              {components.length === 0 ? (
                <p className="text-xs text-gray-500 dark:text-gray-400 text-center py-6">Add components to start building the DFD.</p>
              ) : (
                components.map(c => (
                  <div key={c.id} className="flex items-start gap-2 p-2.5 bg-gray-50 dark:bg-gray-900 rounded-lg border border-gray-200 dark:border-gray-700 group">
                    <span className="text-sm mt-0.5">{TYPE_ICONS[c.type]}</span>
                    <div className="flex-1 min-w-0">
                      <div className="text-sm font-medium text-gray-900 dark:text-white truncate">{c.name}</div>
                      <div className="text-[10px] text-gray-500 uppercase">{c.type}</div>
                      {c.connectsTo.length > 0 && (
                        <div className="flex items-center gap-1 mt-1 text-[10px] text-gray-400">
                          <Link2 size={8} />
                          {c.connectsTo.map(tid => components.find(tc => tc.id === tid)?.name || tid).join(', ')}
                        </div>
                      )}
                    </div>
                    <button onClick={() => handleRemoveComponent(c.id)} aria-label="Remove component" className="p-1 text-gray-400 hover:text-red-500 opacity-0 group-hover:opacity-100 transition-opacity">
                      <Trash2 size={12} />
                    </button>
                  </div>
                ))
              )}
            </div>
          </div>

          {/* STRIDE Stats */}
          {threats.length > 0 && (
            <div className="bg-white dark:bg-gray-800 rounded-xl border border-gray-200 dark:border-gray-700 p-5 shadow-sm dark:shadow-none">
              <h3 className="font-semibold text-gray-900 dark:text-white text-sm mb-3 flex items-center gap-2">
                <AlertTriangle size={14} className="text-amber-500" /> Threat Summary
              </h3>
              <div className="grid grid-cols-3 gap-2">
                {(['S','T','R','I','D','E'] as StrideCategoryKey[]).map(cat => (
                  <div key={cat} className={`px-2.5 py-2 rounded-lg text-center ${STRIDE_CATEGORIES[cat].color}`}>
                    <div className="text-lg font-bold">{threatStats[cat].count}</div>
                    <div className="text-[9px] uppercase font-semibold leading-tight">{STRIDE_CATEGORIES[cat].name}</div>
                    {threatStats[cat].critical > 0 && (
                      <div className="text-[8px] mt-0.5 font-bold text-red-600">
                        {threatStats[cat].critical} Critical
                      </div>
                    )}
                  </div>
                ))}
              </div>
              <button
                onClick={handleEnrichWithAI}
                disabled={isEnriching || threats.length === 0}
                className="w-full mt-4 flex items-center justify-center gap-2 py-2 bg-purple-600 hover:bg-purple-700 disabled:opacity-50 text-white rounded-lg text-sm font-medium transition-colors"
              >
                {isEnriching ? <Loader2 size={14} className="animate-spin" /> : <BrainCircuit size={14} />}
                {isEnriching ? 'Analyzing...' : 'Enrich with AI'}
              </button>
            </div>
          )}
        </div>

        {/* Center + Right Panel: DFD + Threats */}
        <div className="lg:col-span-2 space-y-6">
          {/* Auto-DFD */}
          {mermaidDFD && (
            <div className="bg-white dark:bg-gray-800 rounded-xl border border-gray-200 dark:border-gray-700 p-6 shadow-sm dark:shadow-none">
              <h3 className="text-sm font-medium text-gray-500 dark:text-gray-400 uppercase tracking-wider mb-3">Live Data Flow Diagram</h3>
              <SafeMermaid chart={mermaidDFD} />
            </div>
          )}

          {/* STRIDE Threats Table */}
          {threats.length > 0 && (
            <div className="bg-white dark:bg-gray-800 rounded-xl border border-gray-200 dark:border-gray-700 shadow-sm dark:shadow-none">
              <div className="p-5 border-b border-gray-200 dark:border-gray-700">
                <h3 className="text-sm font-medium text-gray-500 dark:text-gray-400 uppercase tracking-wider flex items-center gap-2">
                  <Shield size={14} /> STRIDE Threat Register ({threats.length})
                </h3>
              </div>
              <div className="overflow-auto max-h-[500px]">
                <table className="w-full text-xs text-left">
                  <thead className="sticky top-0 z-10 bg-gray-50 dark:bg-gray-900">
                    <tr>
                      <th className="px-4 py-2.5 font-semibold text-gray-600 dark:text-gray-400">ID</th>
                      <th className="px-4 py-2.5 font-semibold text-gray-600 dark:text-gray-400">Category</th>
                      <th className="px-4 py-2.5 font-semibold text-gray-600 dark:text-gray-400">Component</th>
                      <th className="px-4 py-2.5 font-semibold text-gray-600 dark:text-gray-400">Severity</th>
                      <th className="px-4 py-2.5 font-semibold text-gray-600 dark:text-gray-400 min-w-[250px]">Description</th>
                      <th className="px-4 py-2.5 font-semibold text-gray-600 dark:text-gray-400 min-w-[250px]">Mitigation</th>
                    </tr>
                  </thead>
                  <tbody>
                    {threats.map(t => (
                      <tr key={t.id} className="border-t border-gray-100 dark:border-gray-800 hover:bg-gray-50 dark:hover:bg-gray-800/50">
                        <td className="px-4 py-2.5 font-mono text-gray-500">{t.id}</td>
                        <td className="px-4 py-2.5">
                          <span className={`inline-block px-2 py-0.5 rounded text-[10px] font-bold ${STRIDE_CATEGORIES[t.category].color}`}>
                            {t.categoryName}
                          </span>
                        </td>
                        <td className="px-4 py-2.5 font-medium text-gray-900 dark:text-white">{t.componentName}</td>
                        <td className="px-4 py-2.5">
                          <span className={`inline-block px-2 py-0.5 rounded text-[10px] font-bold ${
                            t.severity === 'Critical' ? 'bg-red-100 dark:bg-red-900/30 text-red-700 dark:text-red-400' :
                            t.severity === 'High' ? 'bg-orange-100 dark:bg-orange-900/30 text-orange-700 dark:text-orange-400' :
                            t.severity === 'Medium' ? 'bg-amber-100 dark:bg-amber-900/30 text-amber-700 dark:text-amber-400' :
                            'bg-gray-100 dark:bg-gray-800 text-gray-700 dark:text-gray-400'
                          }`}>
                            {t.severity}
                          </span>
                        </td>
                        <td className="px-4 py-2.5 text-gray-700 dark:text-gray-300">{t.description}</td>
                        <td className="px-4 py-2.5 text-gray-600 dark:text-gray-400">{t.mitigation}</td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          )}

          {/* AI Enriched Report */}
          {enrichedReport && (
            <div className="bg-white dark:bg-gray-800 rounded-xl border border-purple-200 dark:border-purple-700/50 p-6 shadow-sm dark:shadow-none">
              <h3 className="text-sm font-medium text-purple-500 dark:text-purple-400 uppercase tracking-wider mb-3 flex items-center gap-2">
                <BrainCircuit size={14} /> AI-Enriched Threat Analysis
              </h3>
              <div className="prose dark:prose-invert max-w-none text-sm">
                <pre className="whitespace-pre-wrap text-gray-800 dark:text-gray-200 font-sans text-xs leading-relaxed bg-gray-50 dark:bg-gray-900 p-4 rounded-lg">
                  {enrichedReport}
                </pre>
              </div>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}
